const nullclaw_agent_memory_projection = "agent_memory";

pub const Context = struct {
    allocator: std.mem.Allocator,
    store: *Store,
    required_token: ?[]const u8 = null,
    token_principals_json: ?[]const u8 = null,
    actor_id: []const u8 = "local",
    feed_instance_id: []const u8 = "nullpantry",
    actor_scopes_json: []const u8 = "[\"admin\"]",
    actor_capabilities_json: []const u8 = "[\"read\",\"write\",\"propose\",\"verify\",\"delete\",\"export\",\"feed_apply\"]",
    embedding_base_url: ?[]const u8 = null,
    embedding_api_key: ?[]const u8 = null,
    embedding_model: ?[]const u8 = null,
    embedding_provider: providers.EmbeddingProviderKind = .openai_compatible,
    embedding_fallbacks: []const providers.EmbeddingEndpointConfig = &.{},
    embedding_dimensions: usize = 64,
    embedding_allow_insecure_http: bool = false,
    llm_base_url: ?[]const u8 = null,
    llm_api_key: ?[]const u8 = null,
    llm_model: ?[]const u8 = null,
    llm_allow_insecure_http: bool = false,
    provider_timeout_secs: u32 = 30,
    provider_runtime: ?*providers.ProviderRuntime = null,
    trust_actor_headers: bool = false,
};

pub const HttpResponse = json.HttpResponse;

pub fn handleRequest(ctx: *Context, method: []const u8, target: []const u8, body: []const u8, raw_request: []const u8) HttpResponse {
    const parsed = json.parsePath(target);
    const path = parsed.path;
    const seg0 = decodeSegment(ctx.allocator, json.segment(path, 0)) catch return serverError(ctx);
    defer if (seg0) |value| ctx.allocator.free(value);
    const seg1 = decodeSegment(ctx.allocator, json.segment(path, 1)) catch return serverError(ctx);
    defer if (seg1) |value| ctx.allocator.free(value);
    const seg2 = decodeSegment(ctx.allocator, json.segment(path, 2)) catch return serverError(ctx);
    defer if (seg2) |value| ctx.allocator.free(value);
    const seg3 = decodeSegment(ctx.allocator, json.segment(path, 3)) catch return serverError(ctx);
    defer if (seg3) |value| ctx.allocator.free(value);
    const seg4 = decodeSegment(ctx.allocator, json.segment(path, 4)) catch return serverError(ctx);
    defer if (seg4) |value| ctx.allocator.free(value);

    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_patch = std.mem.eql(u8, method, "PATCH");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    const is_health = is_get and ((eql(seg0, "health") and seg1 == null) or (eql(seg0, "v1") and eql(seg1, "health") and seg2 == null));
    if (!is_health and !authorized(ctx, raw_request)) {
        return json.errorResponse(ctx.allocator, 401, "unauthorized", "Missing or invalid Authorization header");
    }
    if (is_health) return health(ctx);

    const original_actor_id = ctx.actor_id;
    const original_scopes = ctx.actor_scopes_json;
    const original_capabilities = ctx.actor_capabilities_json;
    applyRequestPrincipal(ctx, raw_request) catch return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid actor scope or capability headers");
    defer {
        ctx.actor_id = original_actor_id;
        ctx.actor_scopes_json = original_scopes;
        ctx.actor_capabilities_json = original_capabilities;
    }

    if (!eql(seg0, "v1")) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");

    if (eql(seg1, "engines") and is_get) {
        return engineRegistry(ctx);
    } else if ((eql(seg1, "openapi.json") or eql(seg1, "openapi")) and is_get) {
        return openApiDocument(ctx);
    } else if (eql(seg1, "capabilities") and is_get) {
        return capabilities(ctx);
    } else if (eql(seg1, "providers") and is_get) {
        return providerRegistry(ctx);
    } else if (eql(seg1, "connectors")) {
        if (is_get and seg2 == null) return connectors(ctx);
        if (is_get and seg2 != null and eql(seg3, "cursor")) return connectorCursorGet(ctx, seg2.?, parsed.query);
        if (is_post and seg2 != null and eql(seg3, "cursor")) return connectorCursorUpsert(ctx, seg2.?, body);
        if (is_post and eql(seg2, "qmd") and eql(seg3, "export-sessions")) return qmdSessionExport(ctx, body);
        if (is_post and eql(seg2, "qmd") and eql(seg3, "prune-sessions")) return qmdSessionPrune(ctx, body);
        if (is_post and seg2 != null and eql(seg3, "ingest")) return connectorIngest(ctx, seg2.?, body);
    } else if (eql(seg1, "markdown")) {
        if (is_post and eql(seg2, "import")) return markdownImport(ctx, body);
        if (is_post and eql(seg2, "import-directory")) return markdownImportDirectory(ctx, body);
        if (is_post and eql(seg2, "export")) return markdownExport(ctx, body);
        if (is_post and eql(seg2, "export-directory")) return markdownExportDirectory(ctx, body);
    } else if (eql(seg1, "bootstrap") and eql(seg2, "prompts")) {
        return handleBootstrapPrompts(ctx, method, parsed.query, seg3, seg4, body);
    } else if (eql(seg1, "artifact-types") and is_get) {
        return artifactTypes(ctx);
    } else if (eql(seg1, "spaces")) {
        if (is_post and seg2 == null) return createSpace(ctx, body);
        if (is_get and seg2 == null) return listSpaces(ctx, parsed.query);
        if (is_get and seg2 != null and seg3 == null) return getSpace(ctx, seg2.?);
    } else if (eql(seg1, "policy-scopes")) {
        if (is_post and seg2 == null) return upsertPolicyScope(ctx, body);
        if (is_get and seg2 == null) return listPolicyScopes(ctx, parsed.query);
        if (is_get and seg2 != null and seg3 == null) return getPolicyScope(ctx, seg2.?);
    } else if (eql(seg1, "sdk") and eql(seg2, "manifest") and is_get) {
        return sdkManifest(ctx);
    } else if (eql(seg1, "ingest") and is_post) {
        return ingest(ctx, body);
    } else if (eql(seg1, "extract-memory") and is_post) {
        return extractMemory(ctx, body);
    } else if (eql(seg1, "jobs")) {
        if (is_post and seg2 == null) return createJob(ctx, body);
        if (is_get and seg2 == null) return listJobs(ctx, parsed.query);
        if (is_post and seg2 != null and eql(seg3, "run")) return runJob(ctx, seg2.?);
    } else if (eql(seg1, "conflicts")) {
        if (is_get and seg2 == null) return listConflicts(ctx, parsed.query);
        if (is_post and eql(seg2, "scan")) return scanConflicts(ctx, body);
    } else if (eql(seg1, "agent-memory")) {
        if (is_post and eql(seg2, "search")) return agentMemorySearch(ctx, body);
        if (is_get and eql(seg2, "count")) return agentMemoryCount(ctx, parsed.query);
        if (is_post and seg2 == null) return agentMemoryStoreBody(ctx, body);
        if ((is_put or is_post) and seg2 != null and seg3 == null) return agentMemoryStoreKey(ctx, seg2.?, body);
        if (is_get and seg2 == null) return agentMemoryList(ctx, parsed.query);
        if (is_get and seg2 != null and seg3 == null) return agentMemoryGet(ctx, seg2.?, parsed.query);
        if (is_delete and seg2 != null and seg3 == null) return agentMemoryDelete(ctx, seg2.?, parsed.query);
    } else if (eql(seg1, "agent-sessions")) {
        return handleAgentSessions(ctx, method, parsed.query, seg2, seg3, body);
    } else if (eql(seg1, "agent")) {
        return handleNullClawAgentAdapter(ctx, method, parsed.query, seg2, seg3, seg4, body);
    } else if (eql(seg1, "sources")) {
        if (is_post and seg2 == null) return createSource(ctx, body);
        if (is_get and seg2 != null and seg3 == null) return getSource(ctx, seg2.?);
    } else if (eql(seg1, "artifacts")) {
        if (is_post and seg2 == null) return createArtifact(ctx, body);
        if (is_get and seg2 != null and seg3 == null) return getArtifact(ctx, seg2.?);
    } else if (eql(seg1, "memory-atoms")) {
        if (is_post and seg2 == null) return createMemoryAtom(ctx, body);
        if ((is_patch or is_put or is_post) and seg2 != null and seg3 == null) return patchMemoryAtom(ctx, seg2.?, body);
    } else if (eql(seg1, "entities")) {
        if (eql(seg2, "resolve") and is_post) return resolveEntity(ctx, body);
        if (is_get and seg2 != null and seg3 == null) return getEntity(ctx, seg2.?);
        if ((is_patch or is_put or is_post) and seg2 != null and seg3 == null) return patchEntity(ctx, seg2.?, body);
        if (is_delete and seg2 != null and seg3 == null) return deleteEntity(ctx, seg2.?);
    } else if (eql(seg1, "relations")) {
        if (is_post and seg2 == null) return createRelation(ctx, body);
        if (is_get and seg2 != null and seg3 == null) return getRelation(ctx, seg2.?);
        if ((is_patch or is_put) and seg2 != null and seg3 == null) return patchRelation(ctx, seg2.?, body);
        if (is_delete and seg2 != null and seg3 == null) return deleteRelation(ctx, seg2.?);
    } else if (eql(seg1, "graph")) {
        if (eql(seg2, "schema") and is_get) return graphSchema(ctx);
        if (eql(seg2, "query") and is_post) return graphQuery(ctx, body);
        if (eql(seg2, "neighbors") and is_post) return graphNeighbors(ctx, body);
        if (eql(seg2, "path") and is_post) return graphPath(ctx, body);
    } else if (eql(seg1, "search") and is_post) {
        return search(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "status") and is_get) {
        return vectorStatus(ctx);
    } else if (eql(seg1, "vector") and eql(seg2, "embed") and is_post) {
        return vectorEmbed(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "upsert") and is_post) {
        return vectorUpsert(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "search") and is_post) {
        return vectorSearch(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "delete") and is_post) {
        return vectorDelete(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "rebuild") and is_post) {
        return vectorRebuild(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "reconcile") and is_post) {
        return vectorReconcile(ctx, body);
    } else if (eql(seg1, "vector") and eql(seg2, "outbox") and is_get) {
        return vectorOutboxStatus(ctx);
    } else if (eql(seg1, "vector") and eql(seg2, "outbox") and eql(seg3, "run") and is_post) {
        return vectorOutboxRun(ctx, body);
    } else if (eql(seg1, "retrieval") and eql(seg2, "plan") and is_post) {
        return retrievalPlan(ctx, body);
    } else if (eql(seg1, "retrieval") and eql(seg2, "search") and is_post) {
        return retrievalSearch(ctx, body);
    } else if (eql(seg1, "workers") and eql(seg2, "run") and is_post) {
        return workersRun(ctx, body);
    } else if (eql(seg1, "memory")) {
        return handleMemorySurface(ctx, method, parsed.query, seg2, seg3, seg4, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "lucid") and eql(seg3, "status") and is_get) {
        return lifecycleLucidStatus(ctx);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "lucid") and eql(seg3, "rebuild") and is_post) {
        return lifecycleLucidRebuild(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "analytics") and eql(seg3, "status") and is_get) {
        return lifecycleAnalyticsStatus(ctx);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "analytics") and eql(seg3, "query") and is_post) {
        return lifecycleAnalyticsQuery(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "analytics") and eql(seg3, "export") and is_post) {
        return lifecycleAnalyticsExport(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "diagnostics") and is_get) {
        return lifecycleDiagnostics(ctx);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "stats") and is_get) {
        return memoryStats(ctx);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "migrate") and is_post) {
        return lifecycleMigrate(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "export-jsonl") and is_post) {
        return lifecycleExportJsonl(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "snapshot") and eql(seg3, "export-jsonl") and is_post) {
        return lifecycleExportJsonl(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "snapshot") and eql(seg3, "export") and is_post) {
        return lifecycleSnapshotExport(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "snapshot") and eql(seg3, "import") and is_post) {
        return lifecycleSnapshotImport(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "snapshot") and eql(seg3, "hydrate") and is_post) {
        return lifecycleSnapshotImport(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "hydrate") and is_post) {
        return lifecycleSnapshotImport(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "snapshot") and is_post) {
        return lifecycleSnapshot(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "cache") and eql(seg3, "put") and is_post) {
        return responseCachePut(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "cache") and eql(seg3, "get") and is_post) {
        return responseCacheGet(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "semantic-cache") and eql(seg3, "put") and is_post) {
        return semanticCachePut(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "semantic-cache") and eql(seg3, "search") and is_post) {
        return semanticCacheSearch(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "hygiene-report") and is_post) {
        return lifecycleHygieneReport(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "hygiene") and is_post) {
        return lifecycleHygiene(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "summarize") and is_post) {
        return lifecycleSummarize(ctx, body);
    } else if (eql(seg1, "lifecycle") and eql(seg2, "rollout") and is_post) {
        return lifecycleRollout(ctx, body);
    } else if (eql(seg1, "ask") and is_post) {
        return ask(ctx, body);
    } else if (eql(seg1, "context-packs") and is_post) {
        return contextPack(ctx, body);
    } else if (eql(seg1, "remember") and is_post) {
        return remember(ctx, body);
    } else if (eql(seg1, "forget") and is_post) {
        return statusAction(ctx, body, "deprecated", false, "forgotten");
    } else if (eql(seg1, "verify") and is_post) {
        return statusAction(ctx, body, "verified", true, "verified");
    } else if (eql(seg1, "mark-stale") and is_post) {
        return statusAction(ctx, body, "stale", false, "stale");
    }

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn handleAgentSessions(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if (seg2 == null and is_get) {
        if (!allAgentSessionsReadAllowed(ctx)) return forbidden(ctx);
        const limit = parseLimit(json.queryParam(query, "limit"), 50);
        const offset = parseLimit(json.queryParam(query, "offset"), 0);
        const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
        const result = ctx.store.listSessionsRouted(ctx.allocator, limit, offset, actorFilter(ctx), storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return writeHistoryList(ctx, result, limit, offset);
    }

    if (eql(seg2, "auto-saved") and seg3 == null and is_delete) {
        const session_id = json.queryParamDecoded(ctx.allocator, query, "session_id") catch return serverError(ctx);
        if (session_id) |sid| {
            if (!agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);
        } else if (!allAgentSessionsWriteAllowed(ctx)) {
            return forbidden(ctx);
        }
        const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
        ctx.store.clearAutoSavedRouted(session_id, actorFilter(ctx), storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return ok(ctx, "{\"ok\":true}");
    }

    if (seg2 != null and seg3 == null and is_get) {
        if (!agentSessionReadAllowed(ctx, seg2.?)) return forbidden(ctx);
        const limit = parseLimit(json.queryParam(query, "limit"), 100);
        const offset = parseLimit(json.queryParam(query, "offset"), 0);
        const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
        const result = ctx.store.historyRouted(ctx.allocator, seg2.?, limit, offset, actorFilter(ctx), storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        return writeHistoryShow(ctx, seg2.?, result, limit, offset);
    }

    if (seg2 != null and seg3 == null and is_delete) {
        return agentSessionTerminate(ctx, seg2.?, query, body);
    }

    if (seg2 != null and eql(seg3, "terminate") and is_post) {
        return agentSessionTerminate(ctx, seg2.?, query, body);
    }

    if (seg2 != null and eql(seg3, "messages")) {
        if ((is_post or is_delete) and !agentSessionWriteAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_get and !agentSessionReadAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_post) return saveMessage(ctx, seg2.?, body, query);
        if (is_get) return loadMessages(ctx, seg2.?, query);
        if (is_delete) {
            const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
            ctx.store.clearMessagesRouted(seg2.?, actorFilter(ctx), storage_target) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            return ok(ctx, "{\"ok\":true}");
        }
    }

    if (seg2 != null and eql(seg3, "usage")) {
        if ((is_put or is_delete) and !agentSessionWriteAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_get and !agentSessionReadAllowed(ctx, seg2.?)) return forbidden(ctx);
        if (is_put) return saveUsage(ctx, seg2.?, body, query);
        if (is_get) return loadUsage(ctx, seg2.?, query);
        if (is_delete) {
            const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
            _ = ctx.store.deleteUsageRouted(seg2.?, actorFilter(ctx), storage_target) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            return ok(ctx, "{\"ok\":true}");
        }
    }

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn agentSessionTerminate(ctx: *Context, session_id: []const u8, query: []const u8, body: []const u8) HttpResponse {
    if (!agentSessionWriteAllowed(ctx, session_id)) return forbidden(ctx);
    const storage_target = if (std.mem.trim(u8, body, " \t\r\n").len == 0)
        storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx)
    else blk: {
        var parsed = parseBody(ctx, body) catch return badJson(ctx);
        defer parsed.deinit();
        break :blk storage_routes.fromObjectOrQuery(ctx.allocator, parsed.value.object, query) catch return serverError(ctx);
    };
    const actor_filter = actorFilter(ctx);

    const history = ctx.store.historyRouted(ctx.allocator, session_id, 500, 0, actor_filter, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const usage = ctx.store.loadUsageRouted(session_id, actor_filter, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const memory_entries = ctx.store.agentMemoryListVisibleRouted(ctx.allocator, null, session_id, ctx.actor_id, ctx.actor_scopes_json, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };

    if (history.total == 0 and usage == null and memory_entries.len == 0) {
        return json.errorResponse(ctx.allocator, 404, "session_not_found", "No session with that key");
    }

    var memory_deleted: usize = 0;
    for (memory_entries) |entry| {
        if (!agentMemoryEntryDeletable(ctx, entry)) return forbidden(ctx);
        if (ctx.store.agentMemoryDeleteRouted(entry.key, entry.session_id, entry.actor_id, ctx.actor_id, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }) {
            memory_deleted += 1;
        }
    }

    ctx.store.clearMessagesRouted(session_id, actor_filter, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    ctx.store.clearAutoSavedRouted(session_id, actor_filter, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const usage_deleted_now = ctx.store.deleteUsageRouted(session_id, actor_filter, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const usage_deleted = usage != null or usage_deleted_now;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"session_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, session_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"session_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, session_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"terminated\":true") catch return serverError(ctx);
    out.print(ctx.allocator, ",\"messages_deleted\":{d},\"memory_entries_deleted\":{d},\"usage_deleted\":{s},\"storage_route\":", .{
        history.total,
        memory_deleted,
        if (usage_deleted) "true" else "false",
    }) catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, storage_target) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn handleNullClawAgentAdapter(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, seg4: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if (is_get and eql(seg2, "health") and seg3 == null) {
        return ok(ctx, "{\"ok\":true,\"service\":\"nullpantry\",\"adapter\":\"nullclaw-api-memory\"}");
    }

    if (eql(seg2, "memories")) {
        if (is_post and eql(seg3, "search") and seg4 == null) return nullClawAgentMemorySearch(ctx, body);
        if ((is_put or is_post) and seg3 != null and seg4 == null) return nullClawAgentMemoryStore(ctx, seg3.?, body);
        if (is_get and seg3 == null) return nullClawAgentMemoryList(ctx, query);
        if (is_get and eql(seg3, "count") and seg4 == null) return agentMemoryCount(ctx, query);
        if (is_get and seg3 != null and seg4 == null) return nullClawAgentMemoryGet(ctx, seg3.?, query);
        if (is_delete and seg3 != null and seg4 == null) return nullClawAgentMemoryDelete(ctx, seg3.?, query);
    }

    if (eql(seg2, "memory")) {
        if ((eql(seg3, "feed") or eql(seg3, "events")) and is_get and seg4 == null) return nullClawMemoryFeed(ctx, query);
        if (eql(seg3, "status") and is_get and seg4 == null) return nullClawMemoryFeedStatus(ctx, query);
        if (eql(seg3, "stats") and is_get and seg4 == null) return memoryStats(ctx);
        if (eql(seg3, "reindex") and is_post and seg4 == null) return memoryReindex(ctx, body);
        if (eql(seg3, "drain-outbox") and is_post and seg4 == null) return memoryDrainOutbox(ctx, body);
        if (eql(seg3, "compact") and is_post and seg4 == null) return nullClawMemoryFeedCompact(ctx, body, query);
        if (eql(seg3, "checkpoint") and is_get and seg4 == null) return nullClawMemoryFeedCheckpoint(ctx, query);
        if (eql(seg3, "checkpoint") and is_post and seg4 == null) return nullClawMemoryFeedCheckpointRestore(ctx, body, query);
        if (eql(seg3, "apply") and is_post and seg4 == null) return nullClawMemoryFeedApply(ctx, body, query);
    }

    if (eql(seg2, "sessions")) {
        if (eql(seg3, "auto-saved") and seg4 == null) return handleAgentSessions(ctx, method, query, seg3, null, body);
        if (is_delete and seg3 != null and seg4 == null) return handleAgentSessions(ctx, method, query, seg3, null, body);
        if (is_delete and seg3 != null and eql(seg4, "messages")) return nullClawAgentClearMessages(ctx, seg3.?, query);
        if (seg3 != null and seg4 != null) return handleAgentSessions(ctx, method, query, seg3, seg4, body);
        if (seg3 == null and is_get) return handleAgentSessions(ctx, method, query, null, null, body);
    }

    if (eql(seg2, "history")) {
        if (is_get and seg3 == null) return handleAgentSessions(ctx, method, query, null, null, body);
        if (is_get and seg3 != null and seg4 == null) return handleAgentSessions(ctx, method, query, seg3, null, body);
    }

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn handleMemorySurface(ctx: *Context, method: []const u8, query: []const u8, seg2: ?[]u8, seg3: ?[]u8, seg4: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if ((eql(seg2, "feed") or eql(seg2, "events")) and is_get and seg3 == null) return memoryFeed(ctx, query);
    if ((eql(seg2, "feed") or eql(seg2, "events")) and is_post and seg3 == null) return appendMemoryFeed(ctx, body, query);
    if (eql(seg2, "status") and is_get and seg3 == null) return memoryFeedStatus(ctx, query);
    if (eql(seg2, "stats") and is_get and seg3 == null) return memoryStats(ctx);
    if (eql(seg2, "reindex") and is_post and seg3 == null) return memoryReindex(ctx, body);
    if (eql(seg2, "drain-outbox") and is_post and seg3 == null) return memoryDrainOutbox(ctx, body);
    if (eql(seg2, "compact") and is_post and seg3 == null) return memoryFeedCompact(ctx, body, query);
    if (eql(seg2, "checkpoint") and is_get and seg3 == null) return memoryFeedCheckpoint(ctx, query);
    if (eql(seg2, "checkpoint") and is_post and seg3 == null) return memoryFeedCheckpointRestore(ctx, body, query);
    if (eql(seg2, "apply") and is_post and seg3 == null) return applyMemoryEvent(ctx, body, query);

    if (eql(seg2, "count") and is_get and seg3 == null) return agentMemoryCount(ctx, query);
    if (eql(seg2, "list") and is_get and seg3 == null) return nullClawAgentMemoryList(ctx, query);
    if (eql(seg2, "search") and is_post and seg3 == null) return nullClawAgentMemorySearch(ctx, body);
    if (eql(seg2, "get") and is_get and seg3 != null and seg4 == null) return nullClawAgentMemoryGet(ctx, seg3.?, query);
    if (eql(seg2, "store") and (is_post or is_put)) {
        if (seg3 != null and seg4 == null) return memoryCommandStoreKey(ctx, seg3.?, body);
        if (seg3 != null) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
        return memoryCommandStoreBody(ctx, body);
    }
    if (eql(seg2, "update") and (is_post or is_put)) {
        if (seg3 != null and seg4 == null) return memoryCommandUpdateKey(ctx, seg3.?, body);
        if (seg3 != null) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
        return memoryCommandUpdateBody(ctx, body);
    }
    if ((eql(seg2, "delete") or eql(seg2, "forget")) and (is_delete or is_post)) {
        if (seg3 != null and seg4 == null) return memoryCommandDeleteKey(ctx, seg3.?, query);
        if (seg3 != null) return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
        if (is_post) return memoryCommandDeleteBody(ctx, body);
    }
    if (eql(seg2, "export-jsonl") and is_post and seg3 == null) return memoryCommandExportJsonl(ctx, body);
    if (eql(seg2, "hygiene-report") and is_post and seg3 == null) return lifecycleHygieneReport(ctx, body);

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn nullClawAgentClearMessages(ctx: *Context, session_id: []const u8, query: []const u8) HttpResponse {
    if (!agentSessionWriteAllowed(ctx, session_id)) return forbidden(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    ctx.store.clearMessagesRouted(session_id, actorFilter(ctx), storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    _ = ctx.store.deleteUsageRouted(session_id, actorFilter(ctx), storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn handleBootstrapPrompts(ctx: *Context, method: []const u8, query: []const u8, seg3: ?[]u8, seg4: ?[]u8, body: []const u8) HttpResponse {
    const is_get = std.mem.eql(u8, method, "GET");
    const is_put = std.mem.eql(u8, method, "PUT");
    const is_post = std.mem.eql(u8, method, "POST");
    const is_delete = std.mem.eql(u8, method, "DELETE");

    if (seg3 == null and is_get) return bootstrapPromptsList(ctx, query);
    if (eql(seg3, "fingerprint") and seg4 == null and is_get) return bootstrapPromptsFingerprint(ctx, query);
    if (eql(seg3, "import-directory") and seg4 == null and is_post) return bootstrapPromptsImportDirectory(ctx, body);
    if (seg3 != null and eql(seg4, "exists") and is_get) return bootstrapPromptExists(ctx, seg3.?, query);
    if (seg3 != null and seg4 == null and is_get) return bootstrapPromptGet(ctx, seg3.?, query);
    if (seg3 != null and seg4 == null and (is_put or is_post)) return bootstrapPromptStore(ctx, seg3.?, body);
    if (seg3 != null and seg4 == null and is_delete) return bootstrapPromptDelete(ctx, seg3.?, query);

    return json.errorResponse(ctx.allocator, 404, "not_found", "Not found");
}

fn bootstrapPromptsList(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"prefix\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, bootstrap_prompts.key_prefix) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"prompts\":[") catch return serverError(ctx);
    for (bootstrap_prompts.docs, 0..) |doc, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        const entry = loadAgentMemoryForRequest(ctx, doc.memory_key, null, requested_scope, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        out.appendSlice(ctx.allocator, "{\"filename\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.filename) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.memory_key) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"exists\":") catch return serverError(ctx);
        out.appendSlice(ctx.allocator, if (entry != null) "true" else "false") catch return serverError(ctx);
        if (entry) |value| {
            out.appendSlice(ctx.allocator, ",\"content_bytes\":") catch return serverError(ctx);
            out.print(ctx.allocator, "{d}", .{value.content.len}) catch return serverError(ctx);
            if (value.store.len > 0) {
                out.appendSlice(ctx.allocator, ",\"store\":") catch return serverError(ctx);
                json.appendString(&out, ctx.allocator, value.store) catch return serverError(ctx);
            }
        }
        out.append(ctx.allocator, '}') catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn bootstrapPromptsFingerprint(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    var entries = ctx.allocator.alloc(?[]const u8, bootstrap_prompts.docs.len) catch return serverError(ctx);
    @memset(entries, null);
    for (bootstrap_prompts.docs, 0..) |doc, i| {
        const entry = loadAgentMemoryForRequest(ctx, doc.memory_key, null, requested_scope, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (entry) |value| {
            entries[i] = value.content;
        }
    }
    const fp = bootstrap_prompts.fingerprint(entries);
    const body = std.fmt.allocPrint(ctx.allocator, "{{\"fingerprint\":{d},\"fingerprint_hex\":\"{x}\",\"present\":{d},\"total\":{d}}}", .{ fp.value, fp.value, fp.present, fp.total }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn bootstrapPromptGet(ctx: *Context, filename: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    const max_bytes = if (json.queryParam(query, "max_bytes")) |value| parseLimit(value, 0) else 0;
    const entry = loadAgentMemoryForRequest(ctx, key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt not found");
    return bootstrapPromptResponse(ctx, filename, key, entry.?, max_bytes);
}

fn bootstrapPromptExists(ctx: *Context, filename: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    const entry = loadAgentMemoryForRequest(ctx, key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"filename\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, filename) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"exists\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (entry != null) "true" else "false") catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn bootstrapPromptStore(ctx: *Context, filename: []const u8, body: []const u8) HttpResponse {
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const stored = agentMemoryStoreParsed(ctx, key, parsed.value.object);
    if (!std.mem.eql(u8, stored.status, "200 OK")) return stored;
    const requested_scope = json.nullableStringField(parsed.value.object, "scope");
    const storage_target = storage_routes.fromObject(ctx.allocator, parsed.value.object) catch return serverError(ctx);
    const entry = loadAgentMemoryForRequest(ctx, key, null, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (entry == null) return ok(ctx, "{\"ok\":true}");
    return bootstrapPromptResponse(ctx, filename, key, entry.?, 0);
}

fn bootstrapPromptDelete(ctx: *Context, filename: []const u8, query: []const u8) HttpResponse {
    const key = bootstrap_prompts.memoryKey(filename) orelse return json.errorResponse(ctx.allocator, 404, "not_found", "Bootstrap prompt is not registered");
    return agentMemoryDelete(ctx, key, query);
}

fn bootstrapPromptsImportDirectory(ctx: *Context, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const root_path = json.stringField(obj, "path") orelse json.stringField(obj, "directory") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    if (root_path.len == 0) return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing path");
    const max_file_bytes = positiveBounded(json.intField(obj, "max_file_bytes"), 10 * 1024 * 1024, 100 * 1024 * 1024);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"imported\":[") catch return serverError(ctx);
    var imported: usize = 0;
    for (bootstrap_prompts.docs) |doc| {
        const file_path = std.fs.path.join(ctx.allocator, &.{ root_path, doc.filename }) catch return serverError(ctx);
        const content = std.Io.Dir.cwd().readFileAlloc(compat.io(), file_path, ctx.allocator, .limited(max_file_bytes)) catch |err| switch (err) {
            error.FileNotFound => continue,
            error.StreamTooLong => return json.errorResponse(ctx.allocator, 413, "payload_too_large", "Bootstrap prompt file exceeds max_file_bytes"),
            else => return serverError(ctx),
        };
        const store_body = bootstrapPromptStoreBody(ctx, obj, content) catch return serverError(ctx);
        const stored = agentMemoryStoreKey(ctx, doc.memory_key, store_body);
        if (!std.mem.eql(u8, stored.status, "200 OK")) return stored;
        if (imported > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        out.appendSlice(ctx.allocator, "{\"filename\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.filename) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, doc.memory_key) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"content_bytes\":") catch return serverError(ctx);
        out.print(ctx.allocator, "{d}", .{content.len}) catch return serverError(ctx);
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        imported += 1;
    }
    out.print(ctx.allocator, "],\"imported_count\":{d}}}", .{imported}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn bootstrapPromptStoreBody(ctx: *Context, obj: std.json.ObjectMap, content: []const u8) ![]const u8 {
    return bootstrap_prompts.buildStoreBody(ctx.allocator, content, .{
        .scope = json.nullableStringField(obj, "scope"),
        .permissions_json = try rawField(ctx.allocator, obj, "permissions", "[]"),
        .storage = json.stringField(obj, "storage"),
        .store = json.stringField(obj, "store"),
        .target_store = json.stringField(obj, "target_store"),
        .stores_json = if (obj.get("stores") != null) try rawField(ctx.allocator, obj, "stores", "[]") else null,
    });
}

fn bootstrapPromptResponse(ctx: *Context, filename: []const u8, key: []const u8, entry: domain.AgentMemory, max_bytes: usize) HttpResponse {
    const excerpt = bootstrap_prompts.excerpt(ctx.allocator, entry.content, max_bytes) catch return serverError(ctx);
    const content = excerpt.content;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"prompt\":{\"filename\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, filename) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory_key\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, key) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"content\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, content) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"content_bytes\":") catch return serverError(ctx);
    out.print(ctx.allocator, "{d}", .{entry.content.len}) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"truncated\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (excerpt.truncated) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"memory\":") catch return serverError(ctx);
    if (max_bytes > 0) {
        appendBootstrapPromptMemoryJson(ctx, &out, entry, content) catch return serverError(ctx);
    } else {
        entry.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendBootstrapPromptMemoryJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), entry: domain.AgentMemory, content: []const u8) !void {
    try out.appendSlice(ctx.allocator, "{\"id\":");
    try json.appendString(out, ctx.allocator, entry.id);
    try out.appendSlice(ctx.allocator, ",\"key\":");
    try json.appendString(out, ctx.allocator, entry.key);
    try out.appendSlice(ctx.allocator, ",\"content\":");
    try json.appendString(out, ctx.allocator, content);
    try out.appendSlice(ctx.allocator, ",\"category\":");
    try json.appendString(out, ctx.allocator, entry.category);
    try out.appendSlice(ctx.allocator, ",\"timestamp\":");
    try json.appendString(out, ctx.allocator, entry.timestamp);
    try out.appendSlice(ctx.allocator, ",\"session_id\":");
    try json.appendNullableString(out, ctx.allocator, entry.session_id);
    try out.appendSlice(ctx.allocator, ",\"actor_id\":");
    try json.appendString(out, ctx.allocator, entry.actor_id);
    try out.appendSlice(ctx.allocator, ",\"owner_id\":");
    try json.appendString(out, ctx.allocator, entry.actor_id);
    try out.appendSlice(ctx.allocator, ",\"created_by_actor_id\":");
    try json.appendString(out, ctx.allocator, if (entry.writer_actor_id.len > 0) entry.writer_actor_id else entry.actor_id);
    try out.appendSlice(ctx.allocator, ",\"scope\":");
    try json.appendString(out, ctx.allocator, entry.scope);
    try out.appendSlice(ctx.allocator, ",\"permissions\":");
    try json.appendRawJsonOr(out, ctx.allocator, entry.permissions_json, "[]");
    if (entry.store.len > 0) {
        try out.appendSlice(ctx.allocator, ",\"store\":");
        try json.appendString(out, ctx.allocator, entry.store);
        try out.appendSlice(ctx.allocator, ",\"storage\":");
        try json.appendString(out, ctx.allocator, entry.store);
    }
    try out.appendSlice(ctx.allocator, ",\"score\":");
    if (entry.score) |score| try out.print(ctx.allocator, "{d}", .{score}) else try out.appendSlice(ctx.allocator, "null");
    try out.append(ctx.allocator, '}');
}

fn nullClawAgentMemoryStore(ctx: *Context, key: []const u8, body: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const storage_target = storage_routes.fromObject(ctx.allocator, obj) catch return serverError(ctx);
    if (kgMemoryRequest(key, storage_target)) {
        const entry = kgMemoryStoreEntry(ctx, key, obj, "core") catch |err| return kgMemoryErrorResponse(ctx, err);
        return nullClawAgentMemoryEntryResponse(ctx, entry);
    }

    const stored = agentMemoryStoreParsed(ctx, key, obj);
    if (!std.mem.eql(u8, stored.status, "200 OK")) return stored;

    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    const requested_scope = json.nullableStringField(obj, "scope");
    const entry = loadAgentMemoryForRequest(ctx, key, session_id, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (entry == null) return ok(ctx, "{\"ok\":true}");
    return nullClawAgentMemoryEntryResponse(ctx, entry.?);
}

fn nullClawAgentMemoryGet(ctx: *Context, key: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const session_id = queryParamDecodedAlias(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!agentSessionReadAllowed(ctx, sid)) return forbidden(ctx);
    }
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    if (kgMemoryRequest(key, storage_target)) {
        const entry = kgMemoryGetEntry(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
        if (entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
        return nullClawAgentMemoryEntryResponse(ctx, entry.?);
    }
    const entry = loadAgentMemoryForRequest(ctx, key, session_id, requested_scope, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const effective_entry = if (entry == null and session_id == null and requested_scope == null and queryBool(query, "include_sessions", false))
        ctx.store.agentMemoryGetAnyVisibleRouted(ctx.allocator, key, ctx.actor_id, ctx.actor_scopes_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }
    else
        entry;
    if (effective_entry == null) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    return nullClawAgentMemoryEntryResponse(ctx, effective_entry.?);
}

fn nullClawAgentMemoryList(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const category = json.queryParamDecoded(ctx.allocator, query, "category") catch return serverError(ctx);
    const session_id = queryParamDecodedAlias(ctx, query, "session_id", "session") catch return serverError(ctx);
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!agentSessionReadAllowed(ctx, sid)) return forbidden(ctx);
    }
    const include_global = queryBool(query, "include_global", false);
    const include_internal = queryBool(query, "include_internal", false);
    const include_content = queryBool(query, "include_content", true);
    const limit = parseLimit(json.queryParam(query, "limit"), std.math.maxInt(usize));
    const offset = parseLimit(json.queryParam(query, "offset"), 0);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    if (storageRouteTargetsKg(storage_target)) {
        const entries = kgMemoryListEntries(ctx, category, requested_scope) catch |err| return kgMemoryErrorResponse(ctx, err);
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries, include_internal, include_content, limit, offset);
    }
    const exact_owner = if (requested_scope) |scope| access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx) else null;
    defer if (exact_owner) |owner| ctx.allocator.free(owner);
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    const primary = if (exact_owner) |owner|
        ctx.store.agentMemoryListRouted(ctx.allocator, category, session_id, owner, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }
    else if (session_id == null)
        ctx.store.agentMemoryListAnyVisibleRouted(ctx.allocator, category, ctx.actor_id, ctx.actor_scopes_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }
    else
        ctx.store.agentMemoryListVisibleRouted(ctx.allocator, category, session_id, ctx.actor_id, ctx.actor_scopes_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
    if (include_global and session_id != null) {
        const global = if (exact_owner) |owner| ctx.store.agentMemoryListRouted(ctx.allocator, category, null, owner, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        } else ctx.store.agentMemoryListVisibleRouted(ctx.allocator, category, null, ctx.actor_id, ctx.actor_scopes_json, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
    }
    dedupeAgentMemoryEntries(ctx.allocator, &entries);
    return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries.items, include_internal, include_content, limit, offset);
}

fn nullClawAgentMemorySearch(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    const session_field_present = fieldAliasPresent(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!agentSessionReadAllowed(ctx, sid)) return forbidden(ctx);
    }
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse "";
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const limit = positiveLimit(json.intField(obj, "limit"), 10);
    const include_global = json.boolField(obj, "include_global") orelse false;
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const include_content = json.boolField(obj, "include_content") orelse true;
    const graph_entries = graphCommandAgentMemoryEntriesFromObject(ctx, obj, query, limit) catch |err| switch (err) {
        error.InvalidGraphCommand, error.InvalidGraphDirection, error.InvalidGraphFilter => return badJson(ctx),
        else => return serverError(ctx),
    };
    if (graph_entries) |entries| {
        return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries, include_internal, include_content, limit, 0);
    }
    const storage_target = storage_routes.fromObject(ctx.allocator, obj) catch return serverError(ctx);
    var entries: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    const primary = if (session_id == null and !session_field_present)
        ctx.store.agentMemorySearchAnyVisibleRouted(ctx.allocator, query, limit, scopes_json, ctx.actor_id, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        }
    else
        ctx.store.agentMemorySearchRouted(ctx.allocator, query, limit, session_id, scopes_json, ctx.actor_id, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
    appendAgentMemoryEntries(ctx.allocator, &entries, primary) catch return serverError(ctx);
    if (include_global and session_id != null) {
        const global = ctx.store.agentMemorySearchRouted(ctx.allocator, query, limit, null, scopes_json, ctx.actor_id, storage_target) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        appendMissingAgentMemoryEntries(ctx.allocator, &entries, global) catch return serverError(ctx);
    }
    dedupeAgentMemoryEntries(ctx.allocator, &entries);
    return nullClawAgentMemoryEntriesResponseWithContent(ctx, entries.items, include_internal, include_content, limit, 0);
}

fn nullClawAgentMemoryDelete(ctx: *Context, key: []const u8, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "delete")) return forbidden(ctx);
    if (!queryDeleteAll(query)) return agentMemoryDelete(ctx, key, query);

    const session_id = queryParamDecodedAlias(ctx, query, "session_id", "session") catch return serverError(ctx);
    if (session_id) |sid| {
        if (!agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);
    }
    const requested_scope = json.queryParamDecoded(ctx.allocator, query, "scope") catch return serverError(ctx);
    if (requested_scope) |scope| {
        if (!domain.scopeDeletable(scope, ctx.actor_scopes_json)) return forbidden(ctx);
    }
    const owner_actor_id = if (requested_scope) |scope|
        access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) catch return serverError(ctx)
    else
        ctx.actor_id;
    defer if (requested_scope != null) ctx.allocator.free(owner_actor_id);
    const storage_target = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    if (kgMemoryRequest(key, storage_target)) {
        const deleted = kgMemoryDeleteKey(ctx, key) catch |err| return kgMemoryErrorResponse(ctx, err);
        if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
        return ok(ctx, "{\"ok\":true}");
    }
    const deleted = ctx.store.agentMemoryDeleteAllRouted(key, owner_actor_id, ctx.actor_id, storage_target) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    if (!deleted) return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory not found");
    return ok(ctx, "{\"ok\":true}");
}

