fn nullClawMemoryFeedCheckpointRestore(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    const projection_cursor = feedProjectionCursorName(ctx, nullclaw_agent_memory_projection) catch return serverError(ctx);
    defer ctx.allocator.free(projection_cursor);
    const transformed = nullClawCheckpointToNativeFeedCheckpoint(ctx, body) catch |err| switch (err) {
        error.NotNullClawCheckpoint => return memoryFeedCheckpointRestoreInternal(ctx, body, query, .{ .name = projection_cursor, .object_type = "agent_memory" }),
        else => return badJson(ctx),
    };
    defer ctx.allocator.free(transformed);
    return memoryFeedCheckpointRestoreInternal(ctx, transformed, query, .{ .name = projection_cursor, .object_type = "agent_memory" });
}

fn feedProjectionCursorName(ctx: *Context, projection: []const u8) ![]const u8 {
    return std.fmt.allocPrint(ctx.allocator, "{s}:actor:{s}", .{ projection, ctx.actor_id });
}

fn nullClawMemoryFeedApply(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (checkpointEventsValue(obj) != null) return nullClawMemoryFeedCheckpointRestore(ctx, body, query);
    if (json.stringField(obj, "key") != null and json.stringField(obj, "object_type") == null) {
        const transformed = nullClawEventToNativeFeedEvent(ctx, obj) catch return badJson(ctx);
        return applyMemoryEvent(ctx, transformed, query);
    }
    return applyMemoryEvent(ctx, body, query);
}

fn memoryFeed(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    defer storage_route.deinit(ctx.allocator);
    if (feedRuntimeForRoute(ctx, storage_route) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeed(ctx, runtime, query);
    }
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const projection_floor = routeProjectionCursorFloor(ctx, storage_route) catch return serverError(ctx);
    if (projection_floor) |floor| {
        if (since_id < floor) return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted storage-route cursor floor; request a checkpoint");
    }
    const events = listCentralFeedEventsForRoute(ctx, since_id, limit, feed_scopes, projection_floor != null, storage_route) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor; request a checkpoint"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    return feedEventsResponse(ctx, events);
}

fn memoryFeedStatus(ctx: *Context, query: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    defer storage_route.deinit(ctx.allocator);
    if (feedRuntimeForRoute(ctx, storage_route) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedStatus(ctx, runtime);
    }
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const status = if (routeProjectionCursorFloor(ctx, storage_route) catch return serverError(ctx)) |floor|
        centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, floor) catch return serverError(ctx)
    else
        centralFeedStatusForRoute(ctx, feed_scopes, storage_route) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    status.writeJsonWithInstance(ctx.allocator, &out, ctx.feed_instance_id) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memoryFeedCompact(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "feed_apply") and (hasCapability(ctx, "export") or hasCapability(ctx, "delete")))) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, parsed.value.object, query) catch return serverError(ctx);
    defer storage_route.deinit(ctx.allocator);
    const requested_before_id = feedCompactCursorFromObject(parsed.value.object);
    if (feedRuntimeForRoute(ctx, storage_route) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedCompact(ctx, runtime, requested_before_id);
    }
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    if (feedRouteProjectionName(ctx, storage_route) catch return serverError(ctx)) |projection_name| {
        defer ctx.allocator.free(projection_name);
        const projection_floor = ctx.store.feedProjectionCursorFloor(ctx.allocator, projection_name) catch return serverError(ctx);
        const status = centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, projection_floor) catch return serverError(ctx);
        const before_id = requested_before_id orelse status.max_event_id;
        const result = ctx.store.compactFeedCursorProjection(projection_name, before_id, ctx.actor_id) catch return serverError(ctx);
        var out: std.ArrayListUnmanaged(u8) = .empty;
        out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"oldest_available_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d},\"projection\":\"storage_route\",\"route\":", .{ result.cursor_floor, result.cursor_floor, result.cursor_floor + 1, result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
        storage_routes.appendRouteJson(ctx.allocator, &out, storage_route) catch return serverError(ctx);
        out.append(ctx.allocator, '}') catch return serverError(ctx);
        return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
    }
    const status = ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);
    const before_id = requested_before_id orelse status.max_event_id;
    const result = ctx.store.compactFeed(before_id, ctx.actor_id) catch return serverError(ctx);
    const response = std.fmt.allocPrint(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d}}}", .{ result.cursor_floor, result.cursor_floor, result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn feedCompactCursorFromObject(obj: std.json.ObjectMap) ?i64 {
    return json.intField(obj, "before_id") orelse
        json.intField(obj, "before_event_id") orelse
        json.intField(obj, "before_sequence") orelse
        json.intField(obj, "through_id") orelse
        json.intField(obj, "through_sequence");
}

fn memoryFeedCheckpoint(ctx: *Context, query: []const u8) HttpResponse {
    if (!(hasCapability(ctx, "read") and hasCapability(ctx, "export"))) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    defer storage_route.deinit(ctx.allocator);
    if (feedRuntimeForRoute(ctx, storage_route) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedCheckpoint(ctx, runtime, query);
    }
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const status = if (routeProjectionCursorFloor(ctx, storage_route) catch return serverError(ctx)) |floor|
        centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, floor) catch return serverError(ctx)
    else
        ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 500);
    const events = listCentralFeedEventsForRoute(ctx, since_id, limit, feed_scopes, true, storage_route) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor"),
        else => return serverError(ctx),
    };
    defer store_mod.freeFeedEvents(ctx.allocator, events);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"instance_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.feed_instance_id) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"events\":[", .{ status.cursor_floor, status.cursor_floor, status.max_event_id, status.max_event_id }) catch return serverError(ctx);
    _ = appendFeedEventsForActor(ctx, &out, events) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "]}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn feedCursorFromQuery(query: []const u8) i64 {
    if (json.queryParam(query, "since_id")) |raw| return std.fmt.parseInt(i64, raw, 10) catch 0;
    if (json.queryParam(query, "after")) |raw| return std.fmt.parseInt(i64, raw, 10) catch 0;
    if (json.queryParam(query, "after_id")) |raw| return std.fmt.parseInt(i64, raw, 10) catch 0;
    if (json.queryParam(query, "after_sequence")) |raw| return std.fmt.parseInt(i64, raw, 10) catch 0;
    return 0;
}

fn feedRuntimeForRoute(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !?*agent_memory_runtime.Runtime {
    return switch (route.target) {
        .primary, .native => null,
        .runtime => if (ctx.store.agent_memory.isExternal() and ctx.store.agent_memory.supportsFeed()) &ctx.store.agent_memory else null,
        .named => blk: {
            const name = route.name orelse return error.AgentMemoryStorageUnavailable;
            const runtime = ctx.store.agent_memory_stores.get(name) orelse return error.AgentMemoryStorageUnavailable;
            break :blk if (runtime.supportsFeed()) runtime else null;
        },
        .subset, .all => null,
    };
}

fn centralFeedRouteNeedsFilter(route: store_mod.AgentMemoryStorageRoute) bool {
    return switch (route.target) {
        .primary, .all => false,
        .native, .runtime, .named, .subset => true,
    };
}

fn routeProjectionCursorFloor(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !?i64 {
    const projection_name = (try feedRouteProjectionName(ctx, route)) orelse return null;
    defer ctx.allocator.free(projection_name);
    return try ctx.store.feedProjectionCursorFloor(ctx.allocator, projection_name);
}

fn feedRouteProjectionName(ctx: *Context, route: store_mod.AgentMemoryStorageRoute) !?[]const u8 {
    if (!centralFeedRouteNeedsFilter(route)) return null;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.appendSlice(ctx.allocator, "memory_feed_route:actor:");
    try out.appendSlice(ctx.allocator, ctx.actor_id);
    try out.append(ctx.allocator, ':');
    switch (route.target) {
        .primary, .all => unreachable,
        .native => try out.appendSlice(ctx.allocator, "native"),
        .runtime => try out.appendSlice(ctx.allocator, "runtime"),
        .named => {
            try out.appendSlice(ctx.allocator, "named:");
            try out.appendSlice(ctx.allocator, route.name orelse "runtime");
        },
        .subset => {
            try out.appendSlice(ctx.allocator, "subset:");
            const stores = try ctx.allocator.dupe([]const u8, route.stores);
            defer ctx.allocator.free(stores);
            std.mem.sort([]const u8, stores, {}, struct {
                fn lessThan(_: void, a: []const u8, b: []const u8) bool {
                    return std.mem.lessThan(u8, a, b);
                }
            }.lessThan);
            var written: usize = 0;
            var previous: ?[]const u8 = null;
            for (stores) |store_name| {
                if (previous) |prev| {
                    if (std.mem.eql(u8, prev, store_name)) continue;
                }
                previous = store_name;
                if (written > 0) try out.append(ctx.allocator, ',');
                try out.appendSlice(ctx.allocator, store_name);
                written += 1;
            }
        },
    }
    const projection_name = try out.toOwnedSlice(ctx.allocator);
    return projection_name;
}

fn listCentralFeedEventsForRoute(ctx: *Context, since_id: i64, limit: usize, scopes_json: []const u8, ignore_cursor_floor: bool, route: store_mod.AgentMemoryStorageRoute) ![]store_mod.FeedEvent {
    if (!centralFeedRouteNeedsFilter(route)) {
        return ctx.store.listFeedEvents(ctx.allocator, .{ .since_id = since_id, .limit = limit, .scopes_json = scopes_json, .ignore_cursor_floor = ignore_cursor_floor, .actor_id = ctx.actor_id });
    }

    const target_limit = @max(@as(usize, 1), @min(limit, 500));
    var cursor = since_id;
    var out: std.ArrayListUnmanaged(store_mod.FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(ctx.allocator);
        out.deinit(ctx.allocator);
    }
    var batch_arena = std.heap.ArenaAllocator.init(ctx.allocator);
    defer batch_arena.deinit();
    while (out.items.len < target_limit) {
        _ = batch_arena.reset(.retain_capacity);
        const batch_allocator = batch_arena.allocator();
        const batch = try ctx.store.listFeedEvents(batch_allocator, .{
            .since_id = cursor,
            .limit = 500,
            .scopes_json = scopes_json,
            .ignore_cursor_floor = ignore_cursor_floor,
            .actor_id = ctx.actor_id,
        });
        if (batch.len == 0) break;
        for (batch) |event| {
            cursor = @max(cursor, event.id);
            if (!feedEventMatchesStorageRoute(batch_allocator, event, route)) continue;
            var cloned = try event.clone(ctx.allocator);
            errdefer cloned.deinit(ctx.allocator);
            try out.append(ctx.allocator, cloned);
            if (out.items.len >= target_limit) break;
        }
        if (batch.len < 500) break;
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn centralFeedStatusForRoute(ctx: *Context, scopes_json: []const u8, route: store_mod.AgentMemoryStorageRoute) !store_mod.FeedStatus {
    const base = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    if (!centralFeedRouteNeedsFilter(route)) return base;

    return centralFeedStatusForRouteFromFloor(ctx, scopes_json, route, base.cursor_floor);
}

fn centralFeedStatusForRouteFromFloor(ctx: *Context, scopes_json: []const u8, route: store_mod.AgentMemoryStorageRoute, cursor_floor: i64) !store_mod.FeedStatus {
    const base = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    var filtered = store_mod.FeedStatus{
        .cursor_floor = cursor_floor,
        .max_event_id = base.max_event_id,
        .visible_events = 0,
        .pending_events = 0,
        .applying_events = 0,
        .applied_events = 0,
    };
    var cursor = cursor_floor;
    var batch_arena = std.heap.ArenaAllocator.init(ctx.allocator);
    defer batch_arena.deinit();
    while (true) {
        _ = batch_arena.reset(.retain_capacity);
        const batch_allocator = batch_arena.allocator();
        const batch = try ctx.store.listFeedEvents(batch_allocator, .{
            .since_id = cursor,
            .limit = 500,
            .scopes_json = scopes_json,
            .ignore_cursor_floor = true,
            .actor_id = ctx.actor_id,
        });
        if (batch.len == 0) break;
        for (batch) |event| {
            cursor = @max(cursor, event.id);
            if (!feedEventMatchesStorageRoute(batch_allocator, event, route)) continue;
            filtered.visible_events += 1;
            if (std.mem.eql(u8, event.status, "pending")) {
                filtered.pending_events += 1;
            } else if (std.mem.eql(u8, event.status, "applying")) {
                filtered.applying_events += 1;
            } else if (std.mem.eql(u8, event.status, "applied")) {
                filtered.applied_events += 1;
            }
        }
        if (batch.len < 500) break;
    }
    return filtered;
}

fn listCentralFeedEventsByObjectType(ctx: *Context, since_id: i64, limit: usize, scopes_json: []const u8, ignore_cursor_floor: bool, object_type: []const u8) ![]store_mod.FeedEvent {
    const target_limit = @max(@as(usize, 1), @min(limit, 500));
    var cursor = since_id;
    var out: std.ArrayListUnmanaged(store_mod.FeedEvent) = .empty;
    errdefer {
        for (out.items) |*event| event.deinit(ctx.allocator);
        out.deinit(ctx.allocator);
    }
    var batch_arena = std.heap.ArenaAllocator.init(ctx.allocator);
    defer batch_arena.deinit();
    while (out.items.len < target_limit) {
        _ = batch_arena.reset(.retain_capacity);
        const batch_allocator = batch_arena.allocator();
        const batch = try ctx.store.listFeedEvents(batch_allocator, .{
            .since_id = cursor,
            .limit = 500,
            .scopes_json = scopes_json,
            .ignore_cursor_floor = ignore_cursor_floor,
            .actor_id = ctx.actor_id,
        });
        if (batch.len == 0) break;
        for (batch) |event| {
            cursor = @max(cursor, event.id);
            if (!std.mem.eql(u8, event.object_type, object_type)) continue;
            var cloned = try event.clone(ctx.allocator);
            errdefer cloned.deinit(ctx.allocator);
            try out.append(ctx.allocator, cloned);
            if (out.items.len >= target_limit) break;
        }
        if (batch.len < 500) break;
    }
    return out.toOwnedSlice(ctx.allocator);
}

fn centralFeedStatusByObjectType(ctx: *Context, scopes_json: []const u8, object_type: []const u8) !store_mod.FeedStatus {
    const base = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    return centralFeedStatusByObjectTypeFromFloor(ctx, scopes_json, object_type, base.cursor_floor);
}

fn centralFeedStatusByObjectTypeFromFloor(ctx: *Context, scopes_json: []const u8, object_type: []const u8, cursor_floor: i64) !store_mod.FeedStatus {
    const base = try ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = scopes_json, .actor_id = ctx.actor_id });
    var filtered = store_mod.FeedStatus{
        .cursor_floor = cursor_floor,
        .max_event_id = base.max_event_id,
        .visible_events = 0,
        .pending_events = 0,
        .applying_events = 0,
        .applied_events = 0,
    };
    var cursor = cursor_floor;
    var batch_arena = std.heap.ArenaAllocator.init(ctx.allocator);
    defer batch_arena.deinit();
    while (true) {
        _ = batch_arena.reset(.retain_capacity);
        const batch_allocator = batch_arena.allocator();
        const batch = try ctx.store.listFeedEvents(batch_allocator, .{
            .since_id = cursor,
            .limit = 500,
            .scopes_json = scopes_json,
            .ignore_cursor_floor = true,
            .actor_id = ctx.actor_id,
        });
        if (batch.len == 0) break;
        for (batch) |event| {
            cursor = @max(cursor, event.id);
            if (!std.mem.eql(u8, event.object_type, object_type)) continue;
            filtered.visible_events += 1;
            if (std.mem.eql(u8, event.status, "pending")) {
                filtered.pending_events += 1;
            } else if (std.mem.eql(u8, event.status, "applying")) {
                filtered.applying_events += 1;
            } else if (std.mem.eql(u8, event.status, "applied")) {
                filtered.applied_events += 1;
            }
        }
        if (batch.len < 500) break;
    }
    return filtered;
}

fn feedEventMatchesStorageRoute(allocator: std.mem.Allocator, event: store_mod.FeedEvent, route: store_mod.AgentMemoryStorageRoute) bool {
    return switch (route.target) {
        .primary, .all => true,
        .native => feedEventMatchesStoreName(allocator, event, "native", true),
        .runtime => feedEventMatchesStoreName(allocator, event, "runtime", false),
        .named => blk: {
            const name = route.name orelse break :blk false;
            break :blk feedEventMatchesStoreName(allocator, event, name, false);
        },
        .subset => blk: {
            for (route.stores) |store_name| {
                if (feedEventMatchesStoreName(allocator, event, store_name, std.ascii.eqlIgnoreCase(store_name, "native"))) break :blk true;
            }
            break :blk false;
        },
    };
}

fn feedEventMatchesStoreName(allocator: std.mem.Allocator, event: store_mod.FeedEvent, store_name: []const u8, include_unrouted_native: bool) bool {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, event.payload_json, .{}) catch return include_unrouted_native;
    defer parsed.deinit();
    if (parsed.value != .object) return include_unrouted_native;
    const obj = parsed.value.object;
    var routed = false;
    if (json.stringField(obj, "store")) |value| {
        routed = true;
        if (std.ascii.eqlIgnoreCase(value, store_name)) return true;
    }
    if (json.stringField(obj, "storage")) |value| {
        routed = true;
        if (std.ascii.eqlIgnoreCase(value, "all") or std.ascii.eqlIgnoreCase(value, store_name)) return true;
    }
    if (obj.get("stores")) |stores| {
        routed = true;
        if (stores == .array) {
            for (stores.array.items) |item| {
                if (item == .string and std.ascii.eqlIgnoreCase(item.string, store_name)) return true;
            }
        }
    }
    return include_unrouted_native and !routed;
}

fn runtimeMemoryFeed(ctx: *Context, runtime: *agent_memory_runtime.Runtime, query: []const u8) HttpResponse {
    const since_id = feedCursorFromQuery(query);
    const limit = parseLimit(json.queryParam(query, "limit"), 100);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const events = runtime.listFeedEvents(ctx.allocator, since_id, limit, ctx.actor_id, feed_scopes) catch |err| switch (err) {
        error.CursorExpired => return json.errorResponse(ctx.allocator, 410, "cursor_expired", "Feed cursor is older than the compacted cursor floor; request a checkpoint"),
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    defer {
        for (events) |*event| event.deinit(ctx.allocator);
        ctx.allocator.free(events);
    }
    return runtimeFeedEventsResponse(ctx, events);
}

fn runtimeMemoryFeedStatus(ctx: *Context, runtime: *agent_memory_runtime.Runtime) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    var status = runtime.feedStatus(ctx.allocator, ctx.actor_id, feed_scopes) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    defer status.deinit(ctx.allocator);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    appendRuntimeFeedStatusJson(ctx.allocator, &out, status) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn runtimeMemoryFeedCompact(ctx: *Context, runtime: *agent_memory_runtime.Runtime, before_id: ?i64) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const result = runtime.compactFeed(ctx.allocator, ctx.actor_id, feed_scopes, before_id) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const response = std.fmt.allocPrint(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"max_event_id\":{d},\"last_sequence\":{d},\"compacted_events\":{d}}}", .{ result.cursor_floor, result.compacted_through_sequence, result.max_event_id, result.max_event_id, result.compacted_events }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn runtimeMemoryFeedCheckpoint(ctx: *Context, runtime: *agent_memory_runtime.Runtime, query: []const u8) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const since_id = feedCursorFromQuery(query);
    const limit = if (json.queryParam(query, "limit")) |raw| parseLimit(raw, 500) else null;
    const body = runtime.exportFeedCheckpoint(ctx.allocator, since_id, limit, ctx.actor_id, feed_scopes) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return .{ .status = "200 OK", .body = body };
}

fn runtimeMemoryFeedCheckpointRestore(ctx: *Context, runtime: *agent_memory_runtime.Runtime, body: []const u8) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    runtime.restoreFeedCheckpoint(ctx.allocator, body, ctx.actor_id, feed_scopes) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

fn runtimeMemoryFeedApply(ctx: *Context, runtime: *agent_memory_runtime.Runtime, body: []const u8) HttpResponse {
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    runtime.applyFeedEventJson(ctx.allocator, body, ctx.actor_id, feed_scopes) catch |err| switch (err) {
        error.NotSupported, error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    return ok(ctx, "{\"ok\":true}");
}

const FeedProjectionCompaction = struct {
    name: []const u8,
    object_type: ?[]const u8 = null,
};

fn memoryFeedCheckpointRestore(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    return memoryFeedCheckpointRestoreInternal(ctx, body, query, null);
}

fn memoryFeedCheckpointRestoreInternal(ctx: *Context, body: []const u8, query: []const u8, projection_compaction: ?FeedProjectionCompaction) HttpResponse {
    if (!canApplyFeed(ctx)) return forbidden(ctx);
    const storage_route = storage_routes.fromQuery(ctx.allocator, query) catch return serverError(ctx);
    defer storage_route.deinit(ctx.allocator);
    if (projection_compaction == null) {
        if (feedRuntimeForRoute(ctx, storage_route) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
            return runtimeMemoryFeedCheckpointRestore(ctx, runtime, body);
        }
    }
    var owned_projection_name: ?[]const u8 = null;
    defer if (owned_projection_name) |value| ctx.allocator.free(value);
    const effective_projection = projection_compaction orelse blk: {
        const projection_name = (feedRouteProjectionName(ctx, storage_route) catch return serverError(ctx)) orelse break :blk null;
        owned_projection_name = projection_name;
        break :blk FeedProjectionCompaction{ .name = projection_name };
    };
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const events_value = checkpointEventsValue(parsed.value.object) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint restore requires an events array");
    if (events_value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint restore requires an events array");
    const checkpoint_compacted_through = checkpointCompactedThrough(parsed.value.object);
    const feed_scopes = feedScopesJson(ctx) catch return serverError(ctx);
    defer ctx.allocator.free(feed_scopes);
    const status_before_restore = if (effective_projection) |projection| blk: {
        const projection_floor = ctx.store.feedProjectionCursorFloor(ctx.allocator, projection.name) catch return serverError(ctx);
        break :blk if (projection.object_type) |object_type|
            centralFeedStatusByObjectTypeFromFloor(ctx, feed_scopes, object_type, projection_floor) catch return serverError(ctx)
        else
            centralFeedStatusForRouteFromFloor(ctx, feed_scopes, storage_route, projection_floor) catch return serverError(ctx);
    } else ctx.store.feedStatus(ctx.allocator, .{ .scopes_json = feed_scopes, .actor_id = ctx.actor_id }) catch return serverError(ctx);

    var restored: usize = 0;
    var applied: usize = 0;
    var queued: usize = 0;
    var skipped: usize = 0;
    var local_compact_floor: i64 = 0;
    for (events_value.array.items) |event_value| {
        if (event_value != .object) return json.errorResponse(ctx.allocator, 400, "bad_request", "Checkpoint events must be JSON objects");
        const event_obj = event_value.object;
        const status = json.stringField(event_obj, "status") orelse "applied";
        var local_event_id: ?i64 = null;
        if (std.mem.eql(u8, status, "pending")) {
            local_event_id = restorePendingCheckpointEvent(ctx, event_obj, storage_route) catch |err| switch (err) {
                error.Forbidden => return forbidden(ctx),
                error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
                error.UnsupportedObjectType => return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type"),
                error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be restored through the feed"),
                error.InternalAgentSessionMessage => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be restored through the feed"),
                error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid checkpoint event"),
                else => return serverError(ctx),
            };
            queued += 1;
        } else if (std.mem.eql(u8, status, "applied") or std.mem.eql(u8, status, "applying")) {
            const event_body = json.jsonFromValue(ctx.allocator, event_value) catch return serverError(ctx);
            const response = applyMemoryEvent(ctx, event_body, query);
            if (!std.mem.eql(u8, response.status, "200 OK")) return response;
            local_event_id = responseEventId(ctx.allocator, response.body);
            applied += 1;
        } else {
            skipped += 1;
        }
        if (local_event_id) |event_id| {
            if (checkpointEventSequence(event_obj)) |source_sequence| {
                if (source_sequence <= checkpoint_compacted_through and event_id > local_compact_floor) {
                    local_compact_floor = event_id;
                }
            }
        }
        restored += 1;
    }

    var restored_cursor_floor: i64 = 0;
    var cursor_floor_restored = false;
    var cursor_floor_restore_skipped = false;
    if (checkpoint_compacted_through > 0 and local_compact_floor > 0) {
        const can_restore_floor = if (effective_projection != null)
            (status_before_restore.visible_events == 0 or status_before_restore.cursor_floor >= local_compact_floor)
        else
            (status_before_restore.max_event_id == 0 or status_before_restore.cursor_floor >= local_compact_floor);
        if (can_restore_floor) {
            const compacted = if (effective_projection) |projection| blk: {
                break :blk if (projection.object_type) |object_type|
                    ctx.store.compactFeedProjection(projection.name, object_type, local_compact_floor, ctx.actor_id) catch return serverError(ctx)
                else
                    ctx.store.compactFeedCursorProjection(projection.name, local_compact_floor, ctx.actor_id) catch return serverError(ctx);
            } else ctx.store.compactFeed(local_compact_floor, ctx.actor_id) catch return serverError(ctx);
            restored_cursor_floor = compacted.cursor_floor;
            cursor_floor_restored = true;
        } else {
            cursor_floor_restore_skipped = true;
        }
    }

    const response = std.fmt.allocPrint(ctx.allocator, "{{\"restored_events\":{d},\"applied_events\":{d},\"queued_events\":{d},\"skipped_events\":{d},\"checkpoint_compacted_through_sequence\":{d},\"restored_cursor_floor\":{d},\"cursor_floor_restored\":{s},\"cursor_floor_restore_skipped\":{s}}}", .{ restored, applied, queued, skipped, checkpoint_compacted_through, restored_cursor_floor, if (cursor_floor_restored) "true" else "false", if (cursor_floor_restore_skipped) "true" else "false" }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn checkpointEventsValue(obj: std.json.ObjectMap) ?std.json.Value {
    if (obj.get("events")) |events| return events;
    if (obj.get("checkpoint")) |checkpoint| {
        if (checkpoint == .object) return checkpoint.object.get("events");
    }
    return null;
}

fn checkpointCompactedThrough(obj: std.json.ObjectMap) i64 {
    if (json.intField(obj, "compacted_through_sequence")) |value| return value;
    if (json.intField(obj, "cursor_floor")) |value| return value;
    if (obj.get("checkpoint")) |checkpoint| {
        if (checkpoint == .object) {
            if (json.intField(checkpoint.object, "compacted_through_sequence")) |value| return value;
            if (json.intField(checkpoint.object, "cursor_floor")) |value| return value;
        }
    }
    return 0;
}

fn checkpointEventSequence(obj: std.json.ObjectMap) ?i64 {
    return json.intField(obj, "id") orelse
        json.intField(obj, "sequence") orelse
        json.intField(obj, "event_id");
}

fn nullClawCheckpointToNativeFeedCheckpoint(ctx: *Context, body: []const u8) ![]const u8 {
    var parsed = try parseBody(ctx, body);
    defer parsed.deinit();
    const events_value = checkpointEventsValue(parsed.value.object) orelse return error.NotNullClawCheckpoint;
    if (events_value != .array) return error.InvalidPayload;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    const compacted_through = checkpointCompactedThrough(parsed.value.object);
    try out.print(ctx.allocator, "{{\"cursor_floor\":{d},\"compacted_through_sequence\":{d},\"events\":[", .{ compacted_through, compacted_through });
    var transformed_any = false;
    for (events_value.array.items, 0..) |event_value, i| {
        if (event_value != .object) return error.InvalidPayload;
        if (i > 0) try out.append(ctx.allocator, ',');
        if (isNullClawTopLevelMemoryEvent(event_value.object)) {
            const native = try nullClawEventToNativeFeedEvent(ctx, event_value.object);
            defer ctx.allocator.free(native);
            try out.appendSlice(ctx.allocator, native);
            transformed_any = true;
        } else {
            const raw = try json.jsonFromValue(ctx.allocator, event_value);
            defer ctx.allocator.free(raw);
            try out.appendSlice(ctx.allocator, raw);
        }
    }
    try out.appendSlice(ctx.allocator, "]}");
    if (!transformed_any) return error.NotNullClawCheckpoint;
    return out.toOwnedSlice(ctx.allocator);
}

fn isNullClawTopLevelMemoryEvent(obj: std.json.ObjectMap) bool {
    return json.stringField(obj, "key") != null and obj.get("payload") == null and json.stringField(obj, "object_type") == null;
}

fn nullClawEventToNativeFeedEvent(ctx: *Context, obj: std.json.ObjectMap) ![]const u8 {
    const key = json.stringField(obj, "key") orelse return error.InvalidPayload;
    const operation = json.stringField(obj, "operation") orelse "put";
    if (!nullClawMemoryOperationSupported(operation)) return error.InvalidPayload;
    const event_type = try std.fmt.allocPrint(ctx.allocator, "agent_memory.{s}", .{operation});
    defer ctx.allocator.free(event_type);

    var out: std.ArrayListUnmanaged(u8) = .empty;
    errdefer out.deinit(ctx.allocator);
    try out.append(ctx.allocator, '{');
    try appendJsonStringField(ctx.allocator, &out, "event_type", event_type, true);
    try appendJsonStringField(ctx.allocator, &out, "operation", operation, false);
    try appendJsonStringField(ctx.allocator, &out, "object_type", "agent_memory", false);
    try appendJsonStringField(ctx.allocator, &out, "object_id", key, false);
    try appendJsonStringField(ctx.allocator, &out, "actor_id", json.stringField(obj, "actor_id") orelse ctx.actor_id, false);
    try appendOptionalStringField(ctx.allocator, &out, obj, "origin_instance_id");
    try appendOptionalRawField(ctx.allocator, &out, obj, "origin_sequence");
    try appendOptionalRawField(ctx.allocator, &out, obj, "sequence");
    try appendOptionalRawField(ctx.allocator, &out, obj, "timestamp_ms");
    try appendOptionalRawField(ctx.allocator, &out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, &out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, &out, obj, "dedupe_key");
    try appendNullClawCausalityField(ctx.allocator, &out, obj);
    try out.appendSlice(ctx.allocator, ",\"payload\":{");
    try appendNullClawEventPayload(ctx, &out, obj, operation, key);
    try out.append(ctx.allocator, '}');
    try out.append(ctx.allocator, '}');
    return out.toOwnedSlice(ctx.allocator);
}

fn nullClawMemoryOperationSupported(operation: []const u8) bool {
    return std.mem.eql(u8, operation, "put") or
        std.mem.eql(u8, operation, "merge_object") or
        std.mem.eql(u8, operation, "merge_string_set") or
        std.mem.eql(u8, operation, "delete_scoped") or
        std.mem.eql(u8, operation, "delete_all") or
        std.mem.eql(u8, operation, "delete") or
        std.mem.eql(u8, operation, "verify") or
        std.mem.eql(u8, operation, "mark_stale") or
        std.mem.eql(u8, operation, "stale") or
        std.mem.eql(u8, operation, "supersede");
}

fn appendNullClawEventPayload(ctx: *Context, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, operation: []const u8, key: []const u8) !void {
    try appendJsonStringField(ctx.allocator, out, "key", key, true);
    if (json.stringField(obj, "category")) |category| try appendJsonStringField(ctx.allocator, out, "category", category, false);
    if (nullableStringFieldAlias(obj, "session_id", "session")) |session_id| try appendJsonStringField(ctx.allocator, out, "session_id", session_id, false);
    try appendOptionalRawField(ctx.allocator, out, obj, "scope");
    try appendOptionalRawField(ctx.allocator, out, obj, "permissions");
    try appendOptionalRawField(ctx.allocator, out, obj, "store");
    try appendOptionalRawField(ctx.allocator, out, obj, "storage");
    try appendOptionalRawField(ctx.allocator, out, obj, "stores");

    if (std.mem.eql(u8, operation, "merge_string_set")) {
        if (obj.get("values")) |values| {
            try out.appendSlice(ctx.allocator, ",\"values\":");
            try appendRawJsonValue(ctx.allocator, out, values);
        } else if (json.stringField(obj, "content")) |content| {
            try out.appendSlice(ctx.allocator, ",\"values\":");
            try appendNullClawContentAsRawJsonOrString(ctx.allocator, out, content);
        } else if (obj.get("value")) |value| {
            try out.appendSlice(ctx.allocator, ",\"value\":");
            try appendRawJsonValue(ctx.allocator, out, value);
        } else {
            return error.InvalidPayload;
        }
    } else if (std.mem.eql(u8, operation, "merge_object")) {
        if (obj.get("object")) |object| {
            if (object != .object) return error.InvalidPayload;
            try out.appendSlice(ctx.allocator, ",\"object\":");
            try appendRawJsonValue(ctx.allocator, out, object);
        } else if (json.stringField(obj, "content")) |content| {
            if (!jsonStringIsObject(ctx.allocator, content)) return error.InvalidPayload;
            try out.appendSlice(ctx.allocator, ",\"object\":");
            try out.appendSlice(ctx.allocator, content);
        } else if (obj.get("value")) |value| {
            if (value != .object) return error.InvalidPayload;
            try out.appendSlice(ctx.allocator, ",\"object\":");
            try appendRawJsonValue(ctx.allocator, out, value);
        } else {
            return error.InvalidPayload;
        }
    } else if (std.mem.eql(u8, operation, "put")) {
        if (json.stringField(obj, "content")) |content| {
            try appendJsonStringField(ctx.allocator, out, "content", content, false);
        } else if (json.stringField(obj, "text")) |text| {
            try appendJsonStringField(ctx.allocator, out, "content", text, false);
        } else if (obj.get("value")) |value| {
            try out.appendSlice(ctx.allocator, ",\"value\":");
            try appendRawJsonValue(ctx.allocator, out, value);
        } else {
            return error.InvalidPayload;
        }
    }
}

fn appendJsonStringField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), name: []const u8, value: []const u8, first: bool) !void {
    if (!first) try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try json.appendString(out, allocator, value);
}

fn appendOptionalStringField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, name: []const u8) !void {
    if (json.stringField(obj, name)) |value| try appendJsonStringField(allocator, out, name, value, false);
}

fn appendOptionalRawField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap, name: []const u8) !void {
    const value = obj.get(name) orelse return;
    try out.append(allocator, ',');
    try json.appendString(out, allocator, name);
    try out.append(allocator, ':');
    try appendRawJsonValue(allocator, out, value);
}

fn appendNullClawCausalityField(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), obj: std.json.ObjectMap) !void {
    if (obj.get("causality")) |value| {
        try out.append(allocator, ',');
        try json.appendString(out, allocator, "causality");
        try out.append(allocator, ':');
        try appendRawJsonValue(allocator, out, value);
        return;
    }
    const timestamp_value = obj.get("timestamp_ms") orelse return;
    try out.appendSlice(allocator, ",\"causality\":{\"origin_timestamp_ms\":");
    try appendRawJsonValue(allocator, out, timestamp_value);
    try out.append(allocator, '}');
}

fn appendRawJsonValue(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), value: std.json.Value) !void {
    const raw = try json.jsonFromValue(allocator, value);
    defer allocator.free(raw);
    try out.appendSlice(allocator, raw);
}

fn appendNullClawContentAsRawJsonOrString(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), content: []const u8) !void {
    if (std.json.validate(allocator, content) catch false) {
        try out.appendSlice(allocator, content);
    } else {
        try json.appendString(out, allocator, content);
    }
}

fn jsonStringIsObject(allocator: std.mem.Allocator, content: []const u8) bool {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, content, .{}) catch return false;
    defer parsed.deinit();
    return parsed.value == .object;
}

fn responseEventId(allocator: std.mem.Allocator, body: []const u8) ?i64 {
    var parsed = std.json.parseFromSlice(std.json.Value, allocator, body, .{}) catch return null;
    defer parsed.deinit();
    if (parsed.value != .object) return null;
    return json.intField(parsed.value.object, "event_id");
}

fn restorePendingCheckpointEvent(ctx: *Context, obj: std.json.ObjectMap, fallback_route: store_mod.AgentMemoryStorageRoute) !i64 {
    const event_type = json.stringField(obj, "event_type") orelse return error.InvalidPayload;
    const operation = json.stringField(obj, "operation") orelse feed_contract.operationFromEventType(event_type);
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    if (!feed_contract.objectTypeSupported(object_type)) return error.UnsupportedObjectType;
    const object_id = json.stringField(obj, "object_id") orelse return error.InvalidPayload;
    const event_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!canApplyAsActor(ctx, event_actor_id)) return error.Forbidden;
    const payload_json = rawField(ctx.allocator, obj, "payload", "{}") catch return error.InvalidPayload;
    const explicit_or_fallback_route = storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route) catch return error.InvalidPayload;
    const payload_route = feedObjectPayloadRoute(ctx, object_type, explicit_or_fallback_route);
    const event_payload_json = store_mod.payloadWithStorageRouteJson(ctx.allocator, payload_json, payload_route) catch return error.InvalidPayload;
    defer ctx.allocator.free(event_payload_json);
    const scope = feed_contract.eventScope(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch return error.InvalidPayload;
    const permissions_json = feed_contract.eventPermissions(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch return error.InvalidPayload;
    const dedupe_key = feed_contract.dedupeKeyFromObject(ctx.allocator, obj) catch return error.InvalidPayload;
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        if (try feed_contract.agentMemoryPayloadIsInternal(ctx.allocator, event_payload_json)) return error.InternalAgentMemory;
        if (!canApplyAgentMemoryScope(ctx, event_actor_id, scope, permissions_json)) return error.Forbidden;
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        if (try feed_contract.agentSessionMessagePayloadIsInternal(ctx.allocator, event_payload_json)) return error.InternalAgentSessionMessage;
        if (!canProposeAgentSessionEvent(ctx, event_actor_id, scope, permissions_json)) return error.Forbidden;
    } else if (feed_contract.isAgentSessionObject(object_type)) {
        if (!canProposeAgentSessionEvent(ctx, event_actor_id, scope, permissions_json)) return error.Forbidden;
    } else if (!canWriteRecord(ctx, scope, permissions_json)) return error.Forbidden;
    const causality_json = rawField(ctx.allocator, obj, "causality", "{}") catch return error.InvalidPayload;

    if (dedupe_key) |key| {
        if (try ctx.store.getFeedEventByDedupeKey(ctx.allocator, key)) |event| {
            if (!recordVisibleToActor(ctx, event.scope, event.permissions_json)) return error.Forbidden;
            if (!feed_contract.dedupeMatches(event, .{ .event_type = event_type, .operation = operation, .object_type = object_type, .object_id = object_id, .scope = scope, .permissions_json = permissions_json, .actor_id = event_actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) return error.FeedDedupeMismatch;
            return event.id;
        }
    }

    return try ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = operation,
        .object_type = object_type,
        .object_id = object_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .actor_id = event_actor_id,
        .dedupe_key = dedupe_key,
        .causality_json = causality_json,
        .payload_json = event_payload_json,
        .status = "pending",
    });
}

fn appendMemoryFeed(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const event_type = json.stringField(obj, "event_type") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing event_type");
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    if (!feed_contract.objectTypeSupported(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type");
    }
    const payload_json = rawField(ctx.allocator, obj, "payload", "{}") catch return serverError(ctx);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch return serverError(ctx);
    const payload_route = feedObjectPayloadRoute(ctx, object_type, storage_route);
    const event_payload_json = store_mod.payloadWithStorageRouteJson(ctx.allocator, payload_json, payload_route) catch return serverError(ctx);
    defer ctx.allocator.free(event_payload_json);
    const scope = feed_contract.eventScope(ctx.allocator, obj, object_type, event_payload_json, ctx.actor_id) catch return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload");
    const permissions_json = feed_contract.eventPermissions(ctx.allocator, obj, object_type, event_payload_json, ctx.actor_id) catch return serverError(ctx);
    const dedupe_key = feed_contract.dedupeKeyFromObject(ctx.allocator, obj) catch return serverError(ctx);
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        const internal_payload = feed_contract.agentMemoryPayloadIsInternal(ctx.allocator, event_payload_json) catch return serverError(ctx);
        if (internal_payload) return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be queued through the feed");
        if (!canProposeRecord(ctx, scope, permissions_json) and !canApplyAgentMemoryScope(ctx, ctx.actor_id, scope, permissions_json)) return forbidden(ctx);
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        const internal_payload = feed_contract.agentSessionMessagePayloadIsInternal(ctx.allocator, event_payload_json) catch return serverError(ctx);
        if (internal_payload) return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be queued through the feed");
        if (!canProposeAgentSessionEvent(ctx, ctx.actor_id, scope, permissions_json)) return forbidden(ctx);
    } else if (feed_contract.isAgentSessionObject(object_type)) {
        if (!canProposeAgentSessionEvent(ctx, ctx.actor_id, scope, permissions_json)) return forbidden(ctx);
    } else if (!canProposeRecord(ctx, scope, permissions_json)) return forbidden(ctx);
    const event_object_id = json.stringField(obj, "object_id") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing object_id");
    if (dedupe_key) |key| {
        if (ctx.store.getFeedEventByDedupeKey(ctx.allocator, key) catch return serverError(ctx)) |event| {
            if (!recordVisibleToActor(ctx, event.scope, event.permissions_json)) return forbidden(ctx);
            if (!feed_contract.dedupeMatches(event, .{ .event_type = event_type, .operation = json.stringField(obj, "operation") orelse "put", .object_type = object_type, .object_id = event_object_id, .scope = scope, .permissions_json = permissions_json, .actor_id = ctx.actor_id, .causality_json = rawField(ctx.allocator, obj, "causality", "{}") catch return serverError(ctx), .payload_json = event_payload_json })) {
                return feedDedupeConflict(ctx);
            }
            const response = std.fmt.allocPrint(ctx.allocator, "{{\"event_id\":{d},\"queued\":true}}", .{event.id}) catch return serverError(ctx);
            return .{ .status = "200 OK", .body = response };
        }
    }
    const id = ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = json.stringField(obj, "operation") orelse "put",
        .object_type = object_type,
        .object_id = event_object_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .actor_id = ctx.actor_id,
        .dedupe_key = dedupe_key,
        .causality_json = rawField(ctx.allocator, obj, "causality", "{}") catch return serverError(ctx),
        .payload_json = event_payload_json,
        .status = "pending",
    }) catch |err| switch (err) {
        error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
        else => return serverError(ctx),
    };
    const response = std.fmt.allocPrint(ctx.allocator, "{{\"event_id\":{d},\"queued\":true}}", .{id}) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = response };
}

fn applyMemoryEvent(ctx: *Context, body: []const u8, query: []const u8) HttpResponse {
    if (!canApplyFeed(ctx)) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    if (checkpointEventsValue(obj) != null) return memoryFeedCheckpointRestoreInternal(ctx, body, query, null);
    const storage_route = storage_routes.fromObjectOrQuery(ctx.allocator, obj, query) catch return serverError(ctx);
    if (feedRuntimeForRoute(ctx, storage_route) catch return agentMemoryStorageUnavailable(ctx)) |runtime| {
        return runtimeMemoryFeedApply(ctx, runtime, body);
    }
    const event_type = json.stringField(obj, "event_type") orelse "memory_atom.upsert";
    const operation = json.stringField(obj, "operation") orelse feed_contract.operationFromEventType(event_type);
    const object_type = json.stringField(obj, "object_type") orelse "memory_atom";
    const event_object_id = json.nullableStringField(obj, "object_id");
    if (!feed_contract.objectTypeSupported(object_type)) {
        return json.errorResponse(ctx.allocator, 400, "bad_request", "Unsupported feed object_type");
    }
    const event_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!canApplyAsActor(ctx, event_actor_id)) return forbidden(ctx);
    const payload_json = rawField(ctx.allocator, obj, "payload", "{}") catch return serverError(ctx);
    const event_payload_route = feedObjectPayloadRoute(ctx, object_type, storage_route);
    const event_payload_json = store_mod.payloadWithStorageRouteJson(ctx.allocator, payload_json, event_payload_route) catch return serverError(ctx);
    defer ctx.allocator.free(event_payload_json);
    const causality_json = rawField(ctx.allocator, obj, "causality", "{}") catch return serverError(ctx);
    const event_dedupe_key = feed_contract.dedupeKeyFromObject(ctx.allocator, obj) catch return serverError(ctx);
    if (std.mem.eql(u8, object_type, "agent_memory") and isAgentMemoryStatusLifecycleOperation(operation)) {
        return applyAgentMemoryLifecycleMutation(ctx, obj, event_type, operation, event_actor_id, event_payload_json, event_payload_route, causality_json);
    }
    if (feed_contract.isLifecycleOperation(operation) and !feed_contract.objectTypeUsesAgentMemoryStorageRoute(object_type)) {
        return applyFeedLifecycleMutation(ctx, obj, event_type, operation, object_type, event_actor_id, event_payload_json, causality_json);
    }
    const scope = feed_contract.eventScope(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch return serverError(ctx);
    const event_permissions_json = feed_contract.eventPermissions(ctx.allocator, obj, object_type, event_payload_json, event_actor_id) catch return serverError(ctx);
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        if (!canApplyAgentMemoryScope(ctx, event_actor_id, scope, event_permissions_json)) return forbidden(ctx);
    } else if (std.mem.eql(u8, object_type, "agent_session_message")) {
        if (feed_contract.agentSessionMessagePayloadIsInternal(ctx.allocator, event_payload_json) catch return serverError(ctx)) return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be applied through the feed");
        if (!canApplyAgentSessionEvent(ctx, event_actor_id, scope, event_permissions_json)) return forbidden(ctx);
    } else if (feed_contract.isAgentSessionObject(object_type)) {
        if (!canApplyAgentSessionEvent(ctx, event_actor_id, scope, event_permissions_json)) return forbidden(ctx);
    } else if (!canWriteRecord(ctx, scope, event_permissions_json)) return forbidden(ctx);
    var memory_input: ?store_mod.MemoryAtomInput = null;
    if (std.mem.eql(u8, object_type, "memory_atom")) {
        memory_input = buildAppliedMemoryAtomInput(ctx, event_payload_json, scope, event_object_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.MissingText, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Memory apply payload must include text/content"),
            else => return serverError(ctx),
        };
    }
    var agent_memory_input: ?store_mod.AgentMemoryInput = null;
    var agent_memory_delete_key: ?[]const u8 = null;
    var agent_memory_delete_session_id: ?[]const u8 = null;
    var agent_memory_delete_actor_id: ?[]const u8 = null;
    var agent_memory_delete_all = false;
    var agent_memory_route: store_mod.AgentMemoryStorageRoute = .{};
    var agent_memory_prepared: ?AgentMemoryApplyInput = null;
    defer {
        if (agent_memory_prepared) |*prepared| prepared.deinit(ctx.allocator);
    }
    if (std.mem.eql(u8, object_type, "agent_memory")) {
        agent_memory_prepared = buildAppliedAgentMemoryInput(ctx, operation, event_payload_json, event_object_id, event_actor_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be applied through the feed"),
            error.MissingKey, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory apply payload must include key/object_id and valid merge content"),
            else => return serverError(ctx),
        };
        const prepared = agent_memory_prepared.?;
        agent_memory_route = prepared.route;
        if (prepared.delete_key) |key| {
            agent_memory_delete_key = key;
            agent_memory_delete_session_id = prepared.delete_session_id;
            agent_memory_delete_actor_id = prepared.delete_actor_id;
            agent_memory_delete_all = prepared.delete_all;
        } else {
            agent_memory_input = prepared.input;
        }
    }
    var session_message_input: ?AgentSessionMessageApplyInput = null;
    if (std.mem.eql(u8, object_type, "agent_session_message")) {
        session_message_input = buildAppliedAgentSessionMessageInput(ctx, operation, event_payload_json, event_actor_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.InternalAgentSessionMessage => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent session messages cannot be applied through the feed"),
            error.MissingRequiredField, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Session message feed payload must include session_id, role and content"),
            else => return serverError(ctx),
        };
    }
    var session_usage_input: ?AgentSessionUsageApplyInput = null;
    if (std.mem.eql(u8, object_type, "agent_session_usage")) {
        session_usage_input = buildAppliedAgentSessionUsageInput(ctx, operation, event_payload_json, event_actor_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            error.MissingRequiredField, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Session usage feed payload must include session_id and total_tokens"),
            else => return serverError(ctx),
        };
    }
    var reserved_event_id: ?i64 = null;
    if (event_dedupe_key) |dedupe_key| {
        if (ctx.store.getFeedEventByDedupeKey(ctx.allocator, dedupe_key) catch return serverError(ctx)) |event| {
            if (!recordVisibleToActor(ctx, event.scope, event.permissions_json)) return forbidden(ctx);
            if (!std.mem.eql(u8, event.status, "applied")) {
                const stale_apply_ms: i64 = 5 * 60 * 1000;
                if (std.mem.eql(u8, event.status, "applying") and ids.nowMs() - event.created_at_ms > stale_apply_ms) {
                    _ = ctx.store.releaseFeedEventReservation(event.id) catch return serverError(ctx);
                } else {
                    return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying");
                }
            } else {
                if (!feed_contract.dedupeMatches(event, .{ .event_type = event_type, .operation = operation, .object_type = object_type, .object_id = event_object_id, .scope = scope, .permissions_json = event_permissions_json, .actor_id = event_actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) return feedDedupeConflict(ctx);
                return appliedFeedObjectResponse(ctx, event.id, event.object_type, event.object_id, if (std.mem.eql(u8, event.object_type, "memory_atom")) event.object_id else null);
            }
        }
        const reservation_id = ids.make(ctx.allocator, "apply_") catch return serverError(ctx);
        reserved_event_id = ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = reservation_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applying",
        }) catch return serverError(ctx);
        const reservation = (ctx.store.getFeedEventByDedupeKey(ctx.allocator, dedupe_key) catch return serverError(ctx)) orelse return serverError(ctx);
        if (reservation.id != reserved_event_id.? or !std.mem.eql(u8, reservation.status, "applying") or !std.mem.eql(u8, reservation.object_id, reservation_id)) {
            if (std.mem.eql(u8, reservation.status, "applied")) {
                if (!feed_contract.dedupeMatches(reservation, .{ .event_type = event_type, .operation = operation, .object_type = object_type, .object_id = event_object_id, .scope = scope, .permissions_json = event_permissions_json, .actor_id = event_actor_id, .causality_json = causality_json, .payload_json = event_payload_json })) return feedDedupeConflict(ctx);
                return appliedFeedObjectResponse(ctx, reservation.id, reservation.object_type, reservation.object_id, if (std.mem.eql(u8, reservation.object_type, "memory_atom")) reservation.object_id else null);
            }
            return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying");
        }
    }
    const memory_atom_id: ?[]const u8 = null;
    if (memory_input) |input| {
        var prepared = prepareAppliedMemoryProvenance(ctx, input) catch |err| switch (err) {
            error.Forbidden => return forbidden(ctx),
            else => return serverError(ctx),
        };
        prepared.atom.actor_id = event_actor_id;
        if (prepared.generated_source) |source_input| {
            var auditable_source = source_input;
            auditable_source.actor_id = event_actor_id;
            prepared.generated_source = auditable_source;
        }
        const applied = ctx.store.applyFeedMemoryAtomAtomic(ctx.allocator, .{
            .reserved_event_id = reserved_event_id,
            .event = .{
                .event_type = event_type,
                .operation = operation,
                .object_type = object_type,
                .object_id = "pending",
                .scope = scope,
                .permissions_json = event_permissions_json,
                .actor_id = event_actor_id,
                .dedupe_key = event_dedupe_key,
                .causality_json = causality_json,
                .payload_json = event_payload_json,
                .status = "applied",
            },
            .prepared = prepared,
        }) catch |err| {
            if (reserved_event_id) |event_id| {
                _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
            }
            return switch (err) {
                error.FeedReservationConsumed => json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed"),
                error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                else => serverError(ctx),
            };
        };
        return appliedFeedResponse(ctx, applied.event_id, applied.atom.id);
    }
    if (agent_memory_input) |input| {
        const applied = ctx.store.applyFeedAgentMemoryRouted(ctx.allocator, .{
            .reserved_event_id = reserved_event_id,
            .event = .{
                .event_type = event_type,
                .operation = operation,
                .object_type = object_type,
                .object_id = "pending",
                .scope = scope,
                .permissions_json = event_permissions_json,
                .actor_id = event_actor_id,
                .dedupe_key = event_dedupe_key,
                .causality_json = causality_json,
                .payload_json = event_payload_json,
                .status = "applied",
            },
            .input = input,
            .writer_actor_id = event_actor_id,
        }, agent_memory_route) catch |err| {
            if (reserved_event_id) |event_id| {
                _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
            }
            return switch (err) {
                error.MissingActorId => json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory events require an actor"),
                error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                error.FeedReservationConsumed => json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed"),
                else => serverError(ctx),
            };
        };
        return appliedFeedObjectResponse(ctx, applied.event_id, object_type, applied.object_id, null);
    }
    if (agent_memory_delete_key) |delete_key| {
        const applied = ctx.store.applyFeedAgentMemoryRouted(ctx.allocator, .{
            .reserved_event_id = reserved_event_id,
            .event = .{
                .event_type = event_type,
                .operation = operation,
                .object_type = object_type,
                .object_id = delete_key,
                .scope = scope,
                .permissions_json = event_permissions_json,
                .actor_id = event_actor_id,
                .dedupe_key = event_dedupe_key,
                .causality_json = causality_json,
                .payload_json = event_payload_json,
                .status = "applied",
            },
            .delete_key = delete_key,
            .delete_session_id = agent_memory_delete_session_id,
            .delete_owner_actor_id = agent_memory_delete_actor_id orelse event_actor_id,
            .delete_all = agent_memory_delete_all,
            .writer_actor_id = event_actor_id,
        }, agent_memory_route) catch |err| {
            if (reserved_event_id) |event_id| {
                _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
            }
            return switch (err) {
                error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                error.FeedReservationConsumed => json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed"),
                else => serverError(ctx),
            };
        };
        return appliedFeedObjectResponse(ctx, applied.event_id, object_type, applied.object_id, null);
    }
    if (session_message_input) |input| {
        const object_id = event_object_id orelse blk: {
            if (input.delete_autosaved) break :blk store_mod.agentSessionAutosaveSetObjectId(ctx.allocator, input.session_id, input.actor_id) catch return serverError(ctx);
            const sid = input.session_id orelse return serverError(ctx);
            if (input.delete_all) break :blk store_mod.agentSessionMessageSetObjectId(ctx.allocator, sid, input.actor_id) catch return serverError(ctx);
            break :blk store_mod.agentSessionMessageObjectId(ctx.allocator, sid, input.role, input.content, input.created_at_ms, input.actor_id) catch return serverError(ctx);
        };
        if (input.delete_autosaved) {
            ctx.store.clearAutoSavedRoutedSuppressFeed(input.session_id, input.actor_id, input.route) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        } else if (input.delete_all) {
            const sid = input.session_id orelse return serverError(ctx);
            ctx.store.clearMessagesRoutedSuppressFeed(sid, input.actor_id, input.route) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        } else {
            const sid = input.session_id orelse return serverError(ctx);
            ctx.store.saveMessageRoutedAtSuppressFeed(sid, input.role, input.content, input.created_at_ms, input.actor_id, input.route) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        }
        const event_id = if (reserved_event_id) |event_id| blk: {
            if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
                return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
            }
            break :blk event_id;
        } else ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = event_dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        }) catch return serverError(ctx);
        return appliedFeedObjectResponse(ctx, event_id, object_type, object_id, null);
    }
    if (session_usage_input) |input| {
        const object_id = event_object_id orelse (store_mod.agentSessionUsageObjectId(ctx.allocator, input.session_id, input.actor_id) catch return serverError(ctx));
        if (input.delete_usage) {
            _ = ctx.store.deleteUsageRoutedSuppressFeed(input.session_id, input.actor_id, input.route) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        } else {
            ctx.store.saveUsageRoutedSuppressFeed(input.session_id, input.total_tokens, input.actor_id, input.route) catch |err| {
                if (reserved_event_id) |event_id| _ = ctx.store.releaseFeedEventReservation(event_id) catch {};
                return switch (err) {
                    error.AgentMemoryStorageUnavailable => agentMemoryStorageUnavailable(ctx),
                    else => serverError(ctx),
                };
            };
        }
        const event_id = if (reserved_event_id) |event_id| blk: {
            if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
                return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
            }
            break :blk event_id;
        } else ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = event_dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        }) catch return serverError(ctx);
        return appliedFeedObjectResponse(ctx, event_id, object_type, object_id, null);
    }
    if (!std.mem.eql(u8, object_type, "memory_atom") and !std.mem.eql(u8, object_type, "agent_memory")) {
        const object_id = applyFeedObjectPut(ctx, object_type, event_payload_json, scope, event_permissions_json, event_actor_id, event_object_id, event_payload_route) catch |err| switch (err) {
            error.Forbidden,
            error.RelatedEntityNotFound,
            error.RecordAclBroaderThanRelatedEntity,
            error.SpaceNotFound,
            error.ArtifactAclBroaderThanSpace,
            error.CanonicalArtifactNotFound,
            error.EntityAclBroaderThanCanonicalArtifact,
            => return forbidden(ctx),
            error.InvalidPayload, error.MissingRequiredField => return json.errorResponse(ctx.allocator, 400, "bad_request", "Invalid feed payload for object_type"),
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        const event_id = if (reserved_event_id) |event_id| blk: {
            if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
                return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
            }
            break :blk event_id;
        } else ctx.store.appendFeedEvent(.{
            .event_type = event_type,
            .operation = operation,
            .object_type = object_type,
            .object_id = object_id,
            .scope = scope,
            .permissions_json = event_permissions_json,
            .actor_id = event_actor_id,
            .dedupe_key = event_dedupe_key,
            .causality_json = causality_json,
            .payload_json = event_payload_json,
            .status = "applied",
        }) catch return serverError(ctx);
        return appliedFeedObjectResponse(ctx, event_id, object_type, object_id, null);
    }
    if (reserved_event_id) |event_id| {
        const object_id = memory_atom_id orelse (event_object_id orelse "unknown");
        if (!(ctx.store.markFeedEventApplied(event_id, object_type, object_id, event_payload_json) catch return serverError(ctx))) {
            return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event reservation was already consumed");
        }
        return appliedFeedResponse(ctx, event_id, memory_atom_id);
    }
    const id = ctx.store.appendFeedEvent(.{
        .event_type = event_type,
        .operation = operation,
        .object_type = object_type,
        .object_id = memory_atom_id orelse (event_object_id orelse "unknown"),
        .scope = scope,
        .permissions_json = event_permissions_json,
        .actor_id = event_actor_id,
        .dedupe_key = event_dedupe_key,
        .causality_json = causality_json,
        .payload_json = event_payload_json,
        .status = "applied",
    }) catch return serverError(ctx);
    return appliedFeedResponse(ctx, id, memory_atom_id);
}

fn feedIdOverride(obj: std.json.ObjectMap, event_object_id: ?[]const u8, prefix: []const u8) !?[]const u8 {
    if (json.stringField(obj, "id")) |id| {
        if (std.mem.startsWith(u8, id, prefix) and id.len > prefix.len) return id;
        return error.InvalidPayload;
    }
    if (event_object_id) |id| {
        if (std.mem.startsWith(u8, id, prefix) and id.len > prefix.len) return id;
    }
    return null;
}

fn buildAppliedMemoryAtomInput(ctx: *Context, payload_json: []const u8, fallback_scope: []const u8, event_object_id: ?[]const u8, fallback_route: store_mod.AgentMemoryStorageRoute) !store_mod.MemoryAtomInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const text = json.stringField(obj, "text") orelse json.stringField(obj, "content") orelse return error.MissingText;
    const atom_scope = json.stringField(obj, "scope") orelse fallback_scope;
    const permissions_json = rawField(ctx.allocator, obj, "permissions", "[]") catch return error.InvalidPayload;
    const input = store_mod.MemoryAtomInput{
        .id = try feedIdOverride(obj, event_object_id, "mem_"),
        .subject_entity_id = json.nullableStringField(obj, "subject_entity_id"),
        .text = text,
        .scope = atom_scope,
        .predicate = json.stringField(obj, "predicate") orelse "states",
        .object = json.stringField(obj, "object") orelse "",
        .confidence = json.floatField(obj, "confidence") orelse 0.7,
        .status = json.nullableStringField(obj, "status"),
        .source_ids_json = rawField(ctx.allocator, obj, "source_ids", "[]") catch "[]",
        .evidence_ranges_json = rawField(ctx.allocator, obj, "evidence_ranges", "[]") catch "[]",
        .created_by = json.stringField(obj, "created_by") orelse "agent",
        .valid_from_ms = json.intField(obj, "valid_from_ms"),
        .valid_until_ms = json.intField(obj, "valid_until_ms"),
        .owner = json.nullableStringField(obj, "owner"),
        .permissions_json = permissions_json,
        .tags_json = rawField(ctx.allocator, obj, "tags", "[\"feed\"]") catch "[\"feed\"]",
        .storage_route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route),
        .suppress_feed = true,
    };
    if (!canCreateMemoryAtom(ctx, input)) return error.Forbidden;
    return input;
}

const AgentMemoryApplyInput = struct {
    input: ?store_mod.AgentMemoryInput = null,
    delete_key: ?[]const u8 = null,
    delete_session_id: ?[]const u8 = null,
    delete_actor_id: ?[]const u8 = null,
    delete_all: bool = false,
    route: store_mod.AgentMemoryStorageRoute = .{},
    owned_owner_actor_id: ?[]const u8 = null,

    fn deinit(self: *AgentMemoryApplyInput, allocator: std.mem.Allocator) void {
        if (self.owned_owner_actor_id) |owner| allocator.free(owner);
        self.owned_owner_actor_id = null;
    }
};

const AgentMemoryOwnerLease = struct {
    value: []const u8,
    owned: ?[]const u8 = null,

    fn deinit(self: *AgentMemoryOwnerLease, allocator: std.mem.Allocator) void {
        if (self.owned) |owner| allocator.free(owner);
        self.owned = null;
    }

    fn transfer(self: *AgentMemoryOwnerLease) ?[]const u8 {
        const owned = self.owned;
        self.owned = null;
        return owned;
    }
};

fn agentMemoryOwnerLease(ctx: *Context, event_actor_id: []const u8, scope: ?[]const u8, obj: std.json.ObjectMap) !AgentMemoryOwnerLease {
    const computed_owner_id = try access.agentMemoryOwner(ctx.allocator, event_actor_id, scope);
    errdefer ctx.allocator.free(computed_owner_id);
    if (json.stringField(obj, "owner_id")) |explicit_owner_id| {
        if (!std.mem.eql(u8, explicit_owner_id, computed_owner_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
        ctx.allocator.free(computed_owner_id);
        return .{ .value = explicit_owner_id };
    }
    return .{ .value = computed_owner_id, .owned = computed_owner_id };
}

test "agent memory owner lease owns computed shared owner and rejects spoofed owner" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();

    var ctx = Context{
        .allocator = std.testing.allocator,
        .store = &store,
        .actor_id = "agent:a",
        .actor_scopes_json = "[\"team:alpha\",\"write:team:alpha\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"feed_apply\"]",
    };

    var parsed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{\"scope\":\"team:alpha\"}", .{});
    defer parsed.deinit();

    var lease = try agentMemoryOwnerLease(&ctx, "agent:a", "team:alpha", parsed.value.object);
    defer lease.deinit(std.testing.allocator);
    try std.testing.expectEqualStrings("shared:team:alpha", lease.value);
    try std.testing.expect(lease.owned != null);

    var explicit = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{\"owner_id\":\"shared:team:alpha\"}", .{});
    defer explicit.deinit();

    var explicit_lease = try agentMemoryOwnerLease(&ctx, "agent:a", "team:alpha", explicit.value.object);
    defer explicit_lease.deinit(std.testing.allocator);
    try std.testing.expectEqualStrings("shared:team:alpha", explicit_lease.value);
    try std.testing.expect(explicit_lease.owned == null);

    var spoofed = try std.json.parseFromSlice(std.json.Value, std.testing.allocator, "{\"owner_id\":\"shared:team:beta\"}", .{});
    defer spoofed.deinit();

    try std.testing.expectError(error.Forbidden, agentMemoryOwnerLease(&ctx, "agent:a", "team:alpha", spoofed.value.object));
}

const AgentMemoryLifecycleApplyInput = struct {
    key: []const u8,
    session_id: ?[]const u8,
    owner_actor_id: []const u8,
    scope: []const u8,
    permissions_json: []const u8,
    status: []const u8,
    route: store_mod.AgentMemoryStorageRoute = .{},
};

const AgentSessionMessageApplyInput = struct {
    session_id: ?[]const u8,
    role: []const u8 = "",
    content: []const u8 = "",
    created_at_ms: i64 = 0,
    actor_id: ?[]const u8,
    delete_all: bool = false,
    delete_autosaved: bool = false,
    route: store_mod.AgentMemoryStorageRoute = .{},
};

const AgentSessionUsageApplyInput = struct {
    session_id: []const u8,
    total_tokens: u64 = 0,
    actor_id: ?[]const u8,
    delete_usage: bool = false,
    route: store_mod.AgentMemoryStorageRoute = .{},
};

fn canApplyAsActor(ctx: *Context, event_actor_id: []const u8) bool {
    return std.mem.eql(u8, event_actor_id, ctx.actor_id) or domain.hasActorScope(ctx.actor_scopes_json, "admin");
}

fn canApplyAgentMemoryScope(ctx: *Context, event_actor_id: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (canWriteRecord(ctx, scope, permissions_json)) return true;
    if (!domain.isActorOwnedAgentMemoryScope(scope, event_actor_id)) return false;
    return (hasCapability(ctx, "write") or hasCapability(ctx, "propose")) and
        access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn isAgentMemoryStatusLifecycleOperation(operation: []const u8) bool {
    return std.mem.eql(u8, operation, "verify") or
        std.mem.eql(u8, operation, "mark_stale") or
        std.mem.eql(u8, operation, "stale") or
        std.mem.eql(u8, operation, "supersede") or
        std.mem.eql(u8, operation, "forget");
}

fn applyAgentMemoryLifecycleMutation(ctx: *Context, obj: std.json.ObjectMap, event_type: []const u8, operation: []const u8, event_actor_id: []const u8, payload_json: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute, causality_json: []const u8) HttpResponse {
    const input = buildAppliedAgentMemoryLifecycleInput(ctx, operation, payload_json, json.nullableStringField(obj, "object_id"), event_actor_id, fallback_route) catch |err| switch (err) {
        error.Forbidden => return forbidden(ctx),
        error.NotFound => return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory target not found"),
        error.InternalAgentMemory => return json.errorResponse(ctx.allocator, 400, "bad_request", "Internal agent memory cannot be applied through the feed"),
        error.MissingKey, error.InvalidPayload => return json.errorResponse(ctx.allocator, 400, "bad_request", "Agent memory lifecycle payload must include key/object_id"),
        else => return serverError(ctx),
    };
    if (!(ctx.store.patchAgentMemoryStatusRouted(ctx.allocator, input.key, input.session_id, input.owner_actor_id, input.status, event_actor_id, input.route) catch return serverError(ctx))) {
        return json.errorResponse(ctx.allocator, 404, "not_found", "Agent memory target not found");
    }
    const event_id = applyOrAppendFeedEventRecord(ctx, obj, event_type, operation, "agent_memory", input.key, input.scope, input.permissions_json, event_actor_id, causality_json, payload_json) catch |err| switch (err) {
        error.FeedConflict => return json.errorResponse(ctx.allocator, 409, "conflict", "Feed event with this dedupe key is already queued or applying"),
        error.FeedDedupeMismatch => return feedDedupeConflict(ctx),
        error.Forbidden => return forbidden(ctx),
        else => return serverError(ctx),
    };
    return appliedFeedObjectResponse(ctx, event_id, "agent_memory", input.key, null);
}

fn canApplyAgentSessionEvent(ctx: *Context, event_actor_id: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (!std.mem.startsWith(u8, scope, "session:")) return false;
    if (!hasCapability(ctx, "write")) return false;
    if (!domain.scopeWritable(scope, ctx.actor_scopes_json)) return false;
    return access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn canProposeAgentSessionEvent(ctx: *Context, event_actor_id: []const u8, scope: []const u8, permissions_json: []const u8) bool {
    if (!std.mem.startsWith(u8, scope, "session:")) return false;
    if (!(hasCapability(ctx, "write") or hasCapability(ctx, "propose"))) return false;
    if (!domain.scopeVisible(scope, ctx.actor_scopes_json)) return false;
    return access.permissionsVisibleForActor(ctx.allocator, permissions_json, ctx.actor_scopes_json, event_actor_id);
}

fn buildAppliedAgentMemoryInput(ctx: *Context, operation: []const u8, payload_json: []const u8, object_id: ?[]const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute) !AgentMemoryApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const key = json.stringField(obj, "key") orelse object_id orelse return error.MissingKey;
    if (domain.isInternalMemoryKey(key)) return error.InternalAgentMemory;
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!agentSessionWriteAllowed(ctx, sid)) return error.Forbidden;
    }
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    const scope = json.nullableStringField(obj, "scope");
    var owner = try agentMemoryOwnerLease(ctx, event_actor_id, scope, obj);
    defer owner.deinit(ctx.allocator);
    if (std.mem.eql(u8, operation, "delete_all")) {
        const owner_value = owner.value;
        const owned_owner_actor_id = owner.transfer();
        return .{ .delete_key = key, .delete_session_id = null, .delete_actor_id = owner_value, .delete_all = true, .route = route, .owned_owner_actor_id = owned_owner_actor_id };
    }
    if (std.mem.eql(u8, operation, "delete") or std.mem.eql(u8, operation, "forget") or std.mem.eql(u8, operation, "delete_scoped")) {
        const owner_value = owner.value;
        const owned_owner_actor_id = owner.transfer();
        return .{ .delete_key = key, .delete_session_id = session_id, .delete_actor_id = owner_value, .route = route, .owned_owner_actor_id = owned_owner_actor_id };
    }
    const permissions_json = rawField(ctx.allocator, obj, "permissions", "[]") catch return error.InvalidPayload;
    if (scope) |requested_scope| {
        const probe_content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse "";
        if (!canCreateMemoryAtom(ctx, .{ .text = probe_content, .scope = requested_scope, .permissions_json = permissions_json, .created_by = "agent", .actor_id = event_actor_id })) return error.Forbidden;
    } else if (!domain.permissionsAreOpen(permissions_json) and !domain.permissionsWritable(permissions_json, ctx.actor_scopes_json)) {
        return error.Forbidden;
    }

    const memory_operation = domain.AgentMemoryOperation.parse(operation);
    const content = switch (memory_operation) {
        .put => json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse try rawField(ctx.allocator, obj, "value", "{}"),
        .merge_string_set => try agent_memory_reducer.stringSetPatchFromObject(ctx.allocator, obj),
        .merge_object => try agent_memory_reducer.objectPatchFromObject(ctx.allocator, obj),
    };
    if (domain.isInternalMemoryEntryKeyOrContent(key, content)) return error.InternalAgentMemory;

    const owner_value = owner.value;
    const owned_owner_actor_id = owner.transfer();
    return .{ .input = .{
        .key = key,
        .content = content,
        .category = json.stringField(obj, "category") orelse "core",
        .session_id = session_id,
        .scope = scope,
        .permissions_json = permissions_json,
        .metadata_json = rawField(ctx.allocator, obj, "metadata", "{}") catch "{}",
        .actor_id = owner_value,
        .writer_actor_id = event_actor_id,
        .operation = memory_operation,
    }, .route = route, .owned_owner_actor_id = owned_owner_actor_id };
}

fn buildAppliedAgentMemoryLifecycleInput(ctx: *Context, operation: []const u8, payload_json: []const u8, object_id: ?[]const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute) !AgentMemoryLifecycleApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const key = json.stringField(obj, "key") orelse object_id orelse return error.MissingKey;
    if (domain.isInternalMemoryKey(key)) return error.InternalAgentMemory;
    const session_id = nullableStringFieldAlias(obj, "session_id", "session");
    if (session_id) |sid| {
        if (!agentSessionWriteAllowed(ctx, sid)) return error.Forbidden;
    }
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    const scope = json.nullableStringField(obj, "scope");
    var owner = try agentMemoryOwnerLease(ctx, event_actor_id, scope, obj);
    defer owner.deinit(ctx.allocator);

    var existing = (try ctx.store.agentMemoryGetRouted(ctx.allocator, key, session_id, owner.value, route)) orelse return error.NotFound;
    defer agent_memory_runtime.freeAgentMemory(ctx.allocator, &existing);
    const visible = access.agentMemoryVisible(ctx.allocator, .{
        .owner_actor_id = existing.actor_id,
        .scope = existing.scope,
        .permissions_json = existing.permissions_json,
        .session_id = existing.session_id,
        .request_actor_id = event_actor_id,
        .request_scopes_json = ctx.actor_scopes_json,
        .record_visible = recordVisibleToActor(ctx, existing.scope, existing.permissions_json),
        .session_visible = if (existing.session_id) |sid| access.sessionVisibleForScopes(ctx.allocator, sid, ctx.actor_scopes_json) else true,
    });
    if (!visible) return error.Forbidden;
    if (!feedLifecycleMutationAllowed(ctx, operation, existing.scope, existing.permissions_json)) return error.Forbidden;
    const payload_status = feed_contract.statusFromLifecycleOperation(operation, obj);
    return .{
        .key = try ctx.allocator.dupe(u8, key),
        .session_id = if (session_id) |sid| try ctx.allocator.dupe(u8, sid) else null,
        .owner_actor_id = try ctx.allocator.dupe(u8, owner.value),
        .scope = try ctx.allocator.dupe(u8, existing.scope),
        .permissions_json = try ctx.allocator.dupe(u8, existing.permissions_json),
        .status = try ctx.allocator.dupe(u8, payload_status),
        .route = route,
    };
}

fn buildAppliedAgentSessionMessageInput(ctx: *Context, operation: []const u8, payload_json: []const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute) !AgentSessionMessageApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!agentSessionWriteAllowed(ctx, sid)) return error.Forbidden;
    } else if (!std.mem.eql(u8, operation, "delete_autosaved") or !allAgentSessionsWriteAllowed(ctx)) {
        return error.Forbidden;
    }
    const payload_actor = json.nullableStringField(obj, "actor_id") orelse event_actor_id;
    if (!std.mem.eql(u8, payload_actor, event_actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    if (std.mem.eql(u8, operation, "delete_autosaved")) {
        return .{ .session_id = session_id, .actor_id = payload_actor, .delete_autosaved = true, .route = route };
    }
    const concrete_session_id = session_id orelse return error.MissingRequiredField;
    if (std.mem.eql(u8, operation, "delete") or std.mem.eql(u8, operation, "forget")) {
        return .{ .session_id = concrete_session_id, .actor_id = payload_actor, .delete_all = true, .route = route };
    }
    const role = json.stringField(obj, "role") orelse return error.MissingRequiredField;
    if (domain.isRuntimeCommandRole(role)) return error.InternalAgentSessionMessage;
    const content = json.stringField(obj, "content") orelse return error.MissingRequiredField;
    return .{
        .session_id = concrete_session_id,
        .role = role,
        .content = content,
        .created_at_ms = json.intField(obj, "created_at_ms") orelse ids.nowMs(),
        .actor_id = payload_actor,
        .route = route,
    };
}

fn buildAppliedAgentSessionUsageInput(ctx: *Context, operation: []const u8, payload_json: []const u8, event_actor_id: []const u8, fallback_route: store_mod.AgentMemoryStorageRoute) !AgentSessionUsageApplyInput {
    const payload = try std.json.parseFromSlice(std.json.Value, ctx.allocator, payload_json, .{});
    // Returned input fields borrow slices from this request-arena parse tree.
    if (payload.value != .object) return error.InvalidPayload;
    const obj = payload.value.object;
    const session_id = json.stringField(obj, "session_id") orelse return error.MissingRequiredField;
    if (!agentSessionWriteAllowed(ctx, session_id)) return error.Forbidden;
    const payload_actor = json.nullableStringField(obj, "actor_id") orelse event_actor_id;
    if (!std.mem.eql(u8, payload_actor, event_actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
    const route = try storage_routes.fromObjectOrFallback(ctx.allocator, obj, fallback_route);
    if (std.mem.eql(u8, operation, "delete") or std.mem.eql(u8, operation, "forget")) {
        return .{ .session_id = session_id, .actor_id = payload_actor, .delete_usage = true, .route = route };
    }
    const total = json.intField(obj, "total_tokens") orelse return error.MissingRequiredField;
    return .{
        .session_id = session_id,
        .total_tokens = @intCast(@max(total, 0)),
        .actor_id = payload_actor,
        .route = route,
    };
}

fn lifecycleDiagnostics(ctx: *Context) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const store_diag = ctx.store.lifecycleDiagnostics() catch return serverError(ctx);
    const schema_version = ctx.store.schemaVersion() catch -1;
    const schema_ok = schema_version >= migrations.expected_schema_version;
    const diagnostics = lifecycle.Diagnostics{
        .total_memory_atoms = store_diag.total_memory_atoms,
        .stale_memory_atoms = store_diag.stale_memory_atoms,
        .vector_outbox_pending = store_diag.vector_outbox_pending,
        .lucid_projection_pending = store_diag.lucid_projection_pending,
        .lucid_projection_failed = store_diag.lucid_projection_failed,
        .cache_entries = store_diag.cache_entries,
        .queued_jobs = store_diag.queued_jobs,
        .running_jobs = store_diag.running_jobs,
        .failed_jobs = store_diag.failed_jobs,
        .pending_feed_events = store_diag.pending_feed_events,
        .open_conflicts = store_diag.open_conflicts,
        .agent_memories = store_diag.agent_memories,
        .sessions = store_diag.sessions,
    };
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(
        ctx.allocator,
        "{{\"diagnostics\":{{\"health\":\"{s}\",\"total_memory_atoms\":{d},\"stale_memory_atoms\":{d},\"vector_outbox_pending\":{d},\"lucid_projection_pending\":{d},\"lucid_projection_failed\":{d},\"cache_entries\":{d},\"queued_jobs\":{d},\"running_jobs\":{d},\"failed_jobs\":{d},\"pending_feed_events\":{d},\"open_conflicts\":{d},\"agent_memories\":{d},\"sessions\":{d},\"runtime\":",
        .{ diagnostics.health(), diagnostics.total_memory_atoms, diagnostics.stale_memory_atoms, diagnostics.vector_outbox_pending, diagnostics.lucid_projection_pending, diagnostics.lucid_projection_failed, diagnostics.cache_entries, diagnostics.queued_jobs, diagnostics.running_jobs, diagnostics.failed_jobs, diagnostics.pending_feed_events, diagnostics.open_conflicts, diagnostics.agent_memories, diagnostics.sessions },
    ) catch return serverError(ctx);
    appendRuntimeDiagnostics(ctx, &out, schema_version, schema_ok, store_diag) catch return serverError(ctx);
    if (ctx.provider_runtime) |runtime| {
        out.appendSlice(ctx.allocator, ",\"providers\":") catch return serverError(ctx);
        runtime.appendStatusJson(ctx.allocator, &out) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn memoryStats(ctx: *Context) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const store_diag = ctx.store.lifecycleDiagnostics() catch return serverError(ctx);
    const visible_sources = ctx.store.countSourcesVisible(ctx.allocator, ctx.actor_scopes_json, ctx.actor_id) catch return serverError(ctx);
    const visible_entries = ctx.store.agentMemoryCount(ctx.actor_id, ctx.actor_scopes_json) catch return serverError(ctx);
    const vector_entries = ctx.store.countVectorChunks() catch return serverError(ctx);
    const outbox_pending = ctx.store.countVectorOutbox("pending") catch return serverError(ctx);
    const embedding_name = if (embeddingProviderConfigured(ctx)) ctx.embedding_provider.name() else "local-deterministic";
    const llm_rerank_configured = ctx.llm_base_url != null and ctx.llm_model != null;

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"backend\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.agentMemoryBackendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"retrieval\":\"hybrid\",\"vector\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.effectiveVectorSearchEngineName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"embedding\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, embedding_name) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"rollout\":\"policy\",\"sync\":\"central_feed\"") catch return serverError(ctx);
    out.print(ctx.allocator, ",\"sources\":{d},\"fallback\":\"permission_filtered_keyword_graph\",\"entries\":{d},\"vector_entries\":{d},\"outbox_pending\":{d},\"nullpantry\":{{\"record_backend\":", .{ visible_sources, visible_entries, vector_entries, outbox_pending }) catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.backendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"agent_memory_backend\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.agentMemoryBackendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"vector_backend\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.vectorBackendName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"local_vector_engine\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.localVectorEngineName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"search_engine\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.store.effectiveVectorSearchEngineName()) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"embedding_provider\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, ctx.embedding_provider.name()) catch return serverError(ctx);
    out.print(
        ctx.allocator,
        ",\"embedding_external_configured\":{s},\"llm_rerank_configured\":{s},\"visible_sources\":{d},\"visible_agent_memories\":{d},\"total_memory_atoms\":{d},\"stale_memory_atoms\":{d},\"native_agent_memories\":{d},\"sessions\":{d},\"cache_entries\":{d},\"queued_jobs\":{d},\"running_jobs\":{d},\"failed_jobs\":{d},\"pending_feed_events\":{d},\"open_conflicts\":{d}",
        .{
            if (embeddingProviderConfigured(ctx)) "true" else "false",
            if (llm_rerank_configured) "true" else "false",
            visible_sources,
            visible_entries,
            store_diag.total_memory_atoms,
            store_diag.stale_memory_atoms,
            store_diag.agent_memories,
            store_diag.sessions,
            store_diag.cache_entries,
            store_diag.queued_jobs,
            store_diag.running_jobs,
            store_diag.failed_jobs,
            store_diag.pending_feed_events,
            store_diag.open_conflicts,
        },
    ) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleMigrate(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "write")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;

    const kind = json.stringField(obj, "object_type") orelse json.stringField(obj, "kind") orelse "agent_memory";
    const source_route = (storage_routes.fromAliasedObject(ctx.allocator, obj, &.{
        "from",
        "source",
        "from_storage",
        "source_storage",
        "from_store",
        "source_store",
        "from_stores",
        "source_stores",
    }) catch return serverError(ctx)) orelse store_mod.AgentMemoryStorageRoute{};
    const target_route = (storage_routes.fromAliasedObject(ctx.allocator, obj, &.{
        "to",
        "target",
        "to_storage",
        "target_storage",
        "to_store",
        "target_store",
        "to_stores",
        "target_stores",
    }) catch return serverError(ctx)) orelse return json.errorResponse(ctx.allocator, 400, "missing_target_storage", "Migration target storage is required");

    const execute = json.boolField(obj, "execute") orelse false;
    const dry_run = json.boolField(obj, "dry_run") orelse !execute;
    const delete_source = json.boolField(obj, "delete_source") orelse false;
    if (delete_source and !hasCapability(ctx, "delete")) return forbidden(ctx);

    if (isAllMigrationKind(kind)) {
        return lifecycleMigrateAll(ctx, obj, source_route, target_route, dry_run, delete_source);
    }
    if (isAgentSessionMigrationKind(kind)) {
        return lifecycleMigrateAgentSessions(ctx, obj, kind, source_route, target_route, dry_run, delete_source);
    }
    if (!isAgentMemoryMigrationKind(kind)) {
        return json.errorResponse(ctx.allocator, 400, "unsupported_migration_kind", "Supported migration kinds are agent_memory, agent_sessions, and all");
    }

    return lifecycleMigrateAgentMemory(ctx, obj, kind, source_route, target_route, dry_run, delete_source);
}

fn lifecycleMigrateAgentMemory(
    ctx: *Context,
    obj: std.json.ObjectMap,
    kind: []const u8,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    dry_run: bool,
    delete_source: bool,
) HttpResponse {
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!agentSessionReadAllowed(ctx, sid)) return forbidden(ctx);
        if (!dry_run and !agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);
    }
    const category = json.nullableStringField(obj, "category");
    const query = std.mem.trim(u8, json.stringField(obj, "query") orelse json.stringField(obj, "q") orelse "", " \t\r\n");
    const scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx);
    const limit = positiveLimit(json.intField(obj, "limit"), 100);
    const offset = positiveLimit(json.intField(obj, "offset"), 0);
    const include_global = json.boolField(obj, "include_global") orelse false;
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const suppress_feed = json.boolField(obj, "suppress_feed") orelse false;

    var candidates: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    const fetch_limit = @min(limit + offset, 500);
    if (query.len > 0) {
        const primary = ctx.store.agentMemorySearchRouted(ctx.allocator, query, fetch_limit, session_id, scopes_json, ctx.actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        appendAgentMemoryEntries(ctx.allocator, &candidates, primary) catch return serverError(ctx);
        if (include_global and session_id != null) {
            const global = ctx.store.agentMemorySearchRouted(ctx.allocator, query, fetch_limit, null, scopes_json, ctx.actor_id, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &candidates, global) catch return serverError(ctx);
        }
    } else {
        const primary = ctx.store.agentMemoryListVisibleRouted(ctx.allocator, category, session_id, ctx.actor_id, scopes_json, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        appendAgentMemoryEntries(ctx.allocator, &candidates, primary) catch return serverError(ctx);
        if (include_global and session_id != null) {
            const global = ctx.store.agentMemoryListVisibleRouted(ctx.allocator, category, null, ctx.actor_id, scopes_json, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            appendMissingAgentMemoryEntries(ctx.allocator, &candidates, global) catch return serverError(ctx);
        }
    }
    dedupeAgentMemoryEntries(ctx.allocator, &candidates);

    var selected: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    var skipped: usize = 0;
    var visible_seen: usize = 0;
    for (candidates.items) |entry| {
        if (!agentMemoryEntryVisible(ctx, entry)) {
            skipped += 1;
            continue;
        }
        if (!include_internal and domain.isInternalMemoryEntryKeyOrContent(entry.key, entry.content)) {
            skipped += 1;
            continue;
        }
        if (visible_seen < offset) {
            visible_seen += 1;
            skipped += 1;
            continue;
        }
        if (selected.items.len >= limit) {
            skipped += 1;
            continue;
        }
        visible_seen += 1;
        if (!agentMemoryEntryMigratable(ctx, entry)) return forbidden(ctx);
        if (delete_source and !agentMemoryEntryDeletable(ctx, entry)) return forbidden(ctx);
        selected.append(ctx.allocator, entry) catch return serverError(ctx);
    }

    var migrated: std.ArrayListUnmanaged(domain.AgentMemory) = .empty;
    if (!dry_run) {
        for (selected.items) |entry| {
            const saved = ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
                .key = entry.key,
                .content = entry.content,
                .category = entry.category,
                .session_id = entry.session_id,
                .scope = entry.scope,
                .permissions_json = entry.permissions_json,
                .actor_id = entry.actor_id,
                .writer_actor_id = ctx.actor_id,
                .suppress_feed = suppress_feed,
            }, target_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            migrated.append(ctx.allocator, saved) catch return serverError(ctx);
            if (delete_source) {
                _ = ctx.store.agentMemoryDeleteRouted(entry.key, entry.session_id, entry.actor_id, ctx.actor_id, source_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
            }
        }
    }

    return lifecycleMigrationResponse(ctx, .{
        .kind = kind,
        .dry_run = dry_run,
        .delete_source = delete_source,
        .source_route = source_route,
        .target_route = target_route,
        .matched = candidates.items.len,
        .selected = selected.items,
        .migrated = migrated.items,
        .skipped = skipped,
        .limit = limit,
        .offset = offset,
    });
}

const AgentMemoryMigrationResponseInput = struct {
    kind: []const u8,
    dry_run: bool,
    delete_source: bool,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    matched: usize,
    selected: []const domain.AgentMemory,
    migrated: []const domain.AgentMemory,
    skipped: usize,
    limit: usize,
    offset: usize,
};

fn lifecycleMigrationResponse(ctx: *Context, input: AgentMemoryMigrationResponseInput) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"ok\":true,\"migration\":{\"kind\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.kind) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"delete_source\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.delete_source) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.source_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.target_route) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"matched\":{d},\"selected\":{d},\"migrated\":{d},\"skipped\":{d},\"limit\":{d},\"offset\":{d},\"entries\":[", .{
        input.matched,
        input.selected.len,
        input.migrated.len,
        input.skipped,
        input.limit,
        input.offset,
    }) catch return serverError(ctx);
    for (input.selected, 0..) |entry, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        const saved: ?domain.AgentMemory = if (i < input.migrated.len) input.migrated[i] else null;
        appendAgentMemoryMigrationEntryJson(ctx.allocator, &out, entry, saved) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendAgentMemoryMigrationEntryJson(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), entry: domain.AgentMemory, migrated: ?domain.AgentMemory) !void {
    try out.appendSlice(allocator, "{\"key\":");
    try json.appendString(out, allocator, entry.key);
    try out.appendSlice(allocator, ",\"category\":");
    try json.appendString(out, allocator, entry.category);
    try out.appendSlice(allocator, ",\"session_id\":");
    try json.appendNullableString(out, allocator, entry.session_id);
    try out.appendSlice(allocator, ",\"actor_id\":");
    try json.appendString(out, allocator, entry.actor_id);
    try out.appendSlice(allocator, ",\"scope\":");
    try json.appendString(out, allocator, entry.scope);
    try out.appendSlice(allocator, ",\"source_store\":");
    try json.appendString(out, allocator, if (entry.store.len > 0) entry.store else "primary");
    if (migrated) |saved| {
        try out.appendSlice(allocator, ",\"migrated_id\":");
        try json.appendString(out, allocator, saved.id);
        try out.appendSlice(allocator, ",\"target_store\":");
        try json.appendString(out, allocator, if (saved.store.len > 0) saved.store else "primary");
    }
    try out.append(allocator, '}');
}

fn isAgentMemoryMigrationKind(kind: []const u8) bool {
    return std.mem.eql(u8, kind, "agent_memory") or std.mem.eql(u8, kind, "agent_memories") or std.mem.eql(u8, kind, "memory");
}

fn isAgentSessionMigrationKind(kind: []const u8) bool {
    return std.mem.eql(u8, kind, "agent_session") or std.mem.eql(u8, kind, "agent_sessions") or std.mem.eql(u8, kind, "session") or std.mem.eql(u8, kind, "sessions");
}

fn isAllMigrationKind(kind: []const u8) bool {
    return std.mem.eql(u8, kind, "all") or std.mem.eql(u8, kind, "agent_runtime") or std.mem.eql(u8, kind, "agent_state");
}

fn lifecycleMigrateAll(
    ctx: *Context,
    obj: std.json.ObjectMap,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    dry_run: bool,
    delete_source: bool,
) HttpResponse {
    const memory_preflight = lifecycleMigrateAgentMemory(ctx, obj, "agent_memory", source_route, target_route, true, delete_source);
    if (!isOkResponse(memory_preflight)) return memory_preflight;
    const session_preflight = lifecycleMigrateAgentSessions(ctx, obj, "agent_sessions", source_route, target_route, true, delete_source);
    if (!isOkResponse(session_preflight)) return session_preflight;

    if (dry_run) {
        return lifecycleAllMigrationResponse(ctx, .{
            .dry_run = true,
            .delete_source = delete_source,
            .preflight = true,
            .source_route = source_route,
            .target_route = target_route,
            .agent_memory = memory_preflight.body,
            .agent_sessions = session_preflight.body,
        });
    }

    const memory_execute = lifecycleMigrateAgentMemory(ctx, obj, "agent_memory", source_route, target_route, false, false);
    if (!isOkResponse(memory_execute)) return memory_execute;
    const session_execute = lifecycleMigrateAgentSessions(ctx, obj, "agent_sessions", source_route, target_route, false, false);
    if (!isOkResponse(session_execute)) return session_execute;

    const cleanup_memory = if (delete_source)
        lifecycleMigrateAgentMemory(ctx, obj, "agent_memory", source_route, target_route, false, true)
    else
        nullResponse(ctx);
    if (!isOkResponse(cleanup_memory)) return cleanup_memory;
    const cleanup_sessions = if (delete_source)
        lifecycleDeleteSourceAgentSessions(ctx, obj, source_route)
    else
        nullResponse(ctx);
    if (!isOkResponse(cleanup_sessions)) return cleanup_sessions;

    return lifecycleAllMigrationResponse(ctx, .{
        .dry_run = false,
        .delete_source = delete_source,
        .preflight = true,
        .source_route = source_route,
        .target_route = target_route,
        .agent_memory = memory_execute.body,
        .agent_sessions = session_execute.body,
        .source_cleanup_memory = cleanup_memory.body,
        .source_cleanup_sessions = cleanup_sessions.body,
    });
}

const LifecycleAllMigrationResponseInput = struct {
    dry_run: bool,
    delete_source: bool,
    preflight: bool,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    agent_memory: []const u8,
    agent_sessions: []const u8,
    source_cleanup_memory: []const u8 = "null",
    source_cleanup_sessions: []const u8 = "null",
};

fn lifecycleAllMigrationResponse(ctx: *Context, input: LifecycleAllMigrationResponseInput) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"ok\":true,\"migration\":{\"kind\":\"all\",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"delete_source\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.delete_source) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"preflight\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.preflight) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.source_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.target_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"results\":{\"agent_memory\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.agent_memory) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"agent_sessions\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.agent_sessions) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "},\"source_cleanup\":{\"agent_memory\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.source_cleanup_memory) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"agent_sessions\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, input.source_cleanup_sessions) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn isOkResponse(response: HttpResponse) bool {
    return std.mem.eql(u8, response.status, "200 OK");
}

fn nullResponse(ctx: *Context) HttpResponse {
    return .{ .status = "200 OK", .body = ctx.allocator.dupe(u8, "null") catch return serverError(ctx) };
}

fn positiveBoundedInt(value: ?i64, default_value: usize, max_value: usize) usize {
    const raw = value orelse return default_value;
    if (raw <= 0) return default_value;
    return @intCast(@min(raw, @as(i64, @intCast(max_value))));
}

const AgentSessionMigrationEntry = struct {
    session_id: []const u8,
    source_message_count: u64,
    target_message_count: u64,
    source_usage_tokens: ?u64,
    target_usage_exists: bool,
    action: []const u8,
    messages_copied: usize = 0,
    usage_copied: bool = false,
};

const AgentSessionMigrationResponseInput = struct {
    kind: []const u8,
    dry_run: bool,
    delete_source: bool,
    append: bool,
    overwrite: bool,
    actor_id: []const u8,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    matched: usize,
    skipped: usize,
    limit: usize,
    offset: usize,
    message_limit: usize,
    entries: []const AgentSessionMigrationEntry,
};

fn lifecycleMigrateAgentSessions(
    ctx: *Context,
    obj: std.json.ObjectMap,
    kind: []const u8,
    source_route: store_mod.AgentMemoryStorageRoute,
    target_route: store_mod.AgentMemoryStorageRoute,
    dry_run: bool,
    delete_source: bool,
) HttpResponse {
    const migration_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!domain.hasActorScope(ctx.actor_scopes_json, "admin") and !std.mem.eql(u8, migration_actor_id, ctx.actor_id)) return forbidden(ctx);

    const append = json.boolField(obj, "append") orelse false;
    const overwrite = json.boolField(obj, "overwrite") orelse false;
    if (append and overwrite) return json.errorResponse(ctx.allocator, 400, "bad_request", "append and overwrite cannot both be true");

    const limit = positiveLimit(json.intField(obj, "limit"), 100);
    const offset = positiveLimit(json.intField(obj, "offset"), 0);
    const message_limit = positiveBoundedInt(json.intField(obj, "message_limit"), 10000, 100000);

    var requested: std.ArrayListUnmanaged([]const u8) = .empty;
    if (json.stringField(obj, "session_id")) |sid| {
        tryAppendUniqueSessionId(ctx.allocator, &requested, sid) catch return serverError(ctx);
    }
    if (obj.get("session_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must be an array");
        for (value.array.items) |item| {
            if (item != .string) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must contain strings");
            tryAppendUniqueSessionId(ctx.allocator, &requested, item.string) catch return serverError(ctx);
        }
    }

    var candidates: std.ArrayListUnmanaged(store_mod.SessionInfo) = .empty;
    var matched: usize = 0;
    if (requested.items.len > 0) {
        matched = requested.items.len;
        const start = @min(offset, requested.items.len);
        const end = @min(start + limit, requested.items.len);
        for (requested.items[start..end]) |sid| {
            if (!agentSessionReadAllowed(ctx, sid)) return forbidden(ctx);
            const history = ctx.store.historyRouted(ctx.allocator, sid, 1, 0, migration_actor_id, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            const usage = ctx.store.loadUsageRouted(sid, migration_actor_id, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            if (history.total == 0 and usage == null) continue;
            const first = if (history.messages.len > 0) history.messages[0].created_at_ms else 0;
            candidates.append(ctx.allocator, .{
                .session_id = sid,
                .message_count = history.total,
                .first_message_at = first,
                .last_message_at = first,
            }) catch return serverError(ctx);
        }
    } else {
        if (!allAgentSessionsReadAllowed(ctx)) return forbidden(ctx);
        const listed = ctx.store.listSessionsRouted(ctx.allocator, limit, offset, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        matched = @intCast(listed.total);
        candidates.appendSlice(ctx.allocator, listed.sessions) catch return serverError(ctx);
    }

    var entries: std.ArrayListUnmanaged(AgentSessionMigrationEntry) = .empty;
    var skipped: usize = if (requested.items.len > 0) @min(offset, requested.items.len) else offset;
    const message_limit_u64: u64 = @intCast(message_limit);

    for (candidates.items) |candidate| {
        const sid = candidate.session_id;
        if (!agentSessionReadAllowed(ctx, sid)) return forbidden(ctx);
        if (!dry_run and !agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);
        if (delete_source and !agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);

        const source_history = ctx.store.historyRouted(ctx.allocator, sid, message_limit, 0, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (source_history.total > message_limit_u64) {
            return json.errorResponse(ctx.allocator, 400, "message_limit_exceeded", "Session has more messages than message_limit; raise message_limit before migrating");
        }
        const source_usage = ctx.store.loadUsageRouted(sid, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (source_history.total == 0 and source_usage == null) {
            skipped += 1;
            continue;
        }

        const target_history = ctx.store.historyRouted(ctx.allocator, sid, 1, 0, migration_actor_id, target_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        const target_usage = ctx.store.loadUsageRouted(sid, migration_actor_id, target_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (!append and !overwrite and (target_history.total > 0 or target_usage != null)) {
            return json.errorResponse(ctx.allocator, 409, "target_session_exists", "Target session already contains messages or usage; use overwrite or append");
        }

        entries.append(ctx.allocator, .{
            .session_id = sid,
            .source_message_count = source_history.total,
            .target_message_count = target_history.total,
            .source_usage_tokens = source_usage,
            .target_usage_exists = target_usage != null,
            .action = if (dry_run) "dry_run" else if (overwrite) "overwrite" else if (append) "append" else "copy",
        }) catch return serverError(ctx);
    }

    if (!dry_run) {
        for (entries.items) |*entry| {
            if (overwrite) {
                ctx.store.clearMessagesRouted(entry.session_id, migration_actor_id, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                _ = ctx.store.deleteUsageRouted(entry.session_id, migration_actor_id, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
            }

            const source_history = ctx.store.historyRouted(ctx.allocator, entry.session_id, message_limit, 0, migration_actor_id, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            if (source_history.total > message_limit_u64) {
                return json.errorResponse(ctx.allocator, 400, "message_limit_exceeded", "Session has more messages than message_limit; raise message_limit before migrating");
            }
            for (source_history.messages) |message| {
                ctx.store.saveMessageRoutedAt(entry.session_id, message.role, message.content, message.created_at_ms, migration_actor_id, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                entry.messages_copied += 1;
            }
            if (entry.source_usage_tokens) |total| {
                ctx.store.saveUsageRouted(entry.session_id, total, migration_actor_id, target_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                entry.usage_copied = true;
            }
            if (delete_source) {
                ctx.store.clearMessagesRouted(entry.session_id, migration_actor_id, source_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
                _ = ctx.store.deleteUsageRouted(entry.session_id, migration_actor_id, source_route) catch |err| switch (err) {
                    error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                    else => return serverError(ctx),
                };
            }
        }
    }

    return lifecycleSessionMigrationResponse(ctx, .{
        .kind = kind,
        .dry_run = dry_run,
        .delete_source = delete_source,
        .append = append,
        .overwrite = overwrite,
        .actor_id = migration_actor_id,
        .source_route = source_route,
        .target_route = target_route,
        .matched = matched,
        .skipped = skipped,
        .limit = limit,
        .offset = offset,
        .message_limit = message_limit,
        .entries = entries.items,
    });
}

fn tryAppendUniqueSessionId(allocator: std.mem.Allocator, ids_list: *std.ArrayListUnmanaged([]const u8), session_id: []const u8) !void {
    for (ids_list.items) |existing| {
        if (std.mem.eql(u8, existing, session_id)) return;
    }
    try ids_list.append(allocator, session_id);
}

fn lifecycleSessionMigrationResponse(ctx: *Context, input: AgentSessionMigrationResponseInput) HttpResponse {
    var migrated: usize = 0;
    var messages_copied: usize = 0;
    var usage_copied: usize = 0;
    for (input.entries) |entry| {
        if (!input.dry_run) migrated += 1;
        messages_copied += entry.messages_copied;
        if (entry.usage_copied) usage_copied += 1;
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"ok\":true,\"migration\":{\"kind\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.kind) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"dry_run\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.dry_run) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"delete_source\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.delete_source) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"append\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.append) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"overwrite\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (input.overwrite) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"actor_id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, input.actor_id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"source_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.source_route) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"target_route\":") catch return serverError(ctx);
    storage_routes.appendRouteJson(ctx.allocator, &out, input.target_route) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"matched\":{d},\"selected\":{d},\"migrated\":{d},\"messages_copied\":{d},\"usage_copied\":{d},\"skipped\":{d},\"limit\":{d},\"offset\":{d},\"message_limit\":{d},\"entries\":[", .{
        input.matched,
        input.entries.len,
        migrated,
        messages_copied,
        usage_copied,
        input.skipped,
        input.limit,
        input.offset,
        input.message_limit,
    }) catch return serverError(ctx);
    for (input.entries, 0..) |entry, i| {
        if (i > 0) out.append(ctx.allocator, ',') catch return serverError(ctx);
        appendAgentSessionMigrationEntryJson(ctx.allocator, &out, entry) catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "]}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleDeleteSourceAgentSessions(ctx: *Context, obj: std.json.ObjectMap, source_route: store_mod.AgentMemoryStorageRoute) HttpResponse {
    const migration_actor_id = json.stringField(obj, "actor_id") orelse ctx.actor_id;
    if (!domain.hasActorScope(ctx.actor_scopes_json, "admin") and !std.mem.eql(u8, migration_actor_id, ctx.actor_id)) return forbidden(ctx);

    const limit = positiveLimit(json.intField(obj, "limit"), 100);
    const offset = positiveLimit(json.intField(obj, "offset"), 0);
    const message_limit = positiveBoundedInt(json.intField(obj, "message_limit"), 10000, 100000);

    var requested: std.ArrayListUnmanaged([]const u8) = .empty;
    if (json.stringField(obj, "session_id")) |sid| {
        tryAppendUniqueSessionId(ctx.allocator, &requested, sid) catch return serverError(ctx);
    }
    if (obj.get("session_ids")) |value| {
        if (value != .array) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must be an array");
        for (value.array.items) |item| {
            if (item != .string) return json.errorResponse(ctx.allocator, 400, "bad_request", "session_ids must contain strings");
            tryAppendUniqueSessionId(ctx.allocator, &requested, item.string) catch return serverError(ctx);
        }
    }

    var candidates: std.ArrayListUnmanaged([]const u8) = .empty;
    var matched: usize = 0;
    if (requested.items.len > 0) {
        matched = requested.items.len;
        const start = @min(offset, requested.items.len);
        const end = @min(start + limit, requested.items.len);
        for (requested.items[start..end]) |sid| {
            if (!agentSessionReadAllowed(ctx, sid) or !agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);
            candidates.append(ctx.allocator, sid) catch return serverError(ctx);
        }
    } else {
        if (!allAgentSessionsReadAllowed(ctx) or !allAgentSessionsWriteAllowed(ctx)) return forbidden(ctx);
        const listed = ctx.store.listSessionsRouted(ctx.allocator, limit, offset, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        matched = @intCast(listed.total);
        for (listed.sessions) |session| {
            candidates.append(ctx.allocator, session.session_id) catch return serverError(ctx);
        }
    }

    const message_limit_u64: u64 = @intCast(message_limit);
    var sessions_deleted: usize = 0;
    var messages_deleted: usize = 0;
    var usage_deleted: usize = 0;
    var skipped: usize = if (requested.items.len > 0) @min(offset, requested.items.len) else offset;

    for (candidates.items) |sid| {
        if (!agentSessionReadAllowed(ctx, sid) or !agentSessionWriteAllowed(ctx, sid)) return forbidden(ctx);
        const history = ctx.store.historyRouted(ctx.allocator, sid, message_limit, 0, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (history.total > message_limit_u64) {
            return json.errorResponse(ctx.allocator, 400, "message_limit_exceeded", "Session has more messages than message_limit; raise message_limit before deleting migrated source sessions");
        }
        const usage = ctx.store.loadUsageRouted(sid, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        if (history.total == 0 and usage == null) {
            skipped += 1;
            continue;
        }
        if (usage != null) {
            const deleted = ctx.store.deleteUsageRouted(sid, migration_actor_id, source_route) catch |err| switch (err) {
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                else => return serverError(ctx),
            };
            if (deleted) usage_deleted += 1;
        }
        ctx.store.clearMessagesRouted(sid, migration_actor_id, source_route) catch |err| switch (err) {
            error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
            else => return serverError(ctx),
        };
        sessions_deleted += 1;
        messages_deleted += @intCast(history.total);
    }

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"ok\":true,\"cleanup\":{{\"kind\":\"agent_sessions\",\"matched\":{d},\"selected\":{d},\"sessions_deleted\":{d},\"messages_deleted\":{d},\"usage_deleted\":{d},\"skipped\":{d},\"limit\":{d},\"offset\":{d},\"message_limit\":{d}}}}}", .{
        matched,
        candidates.items.len,
        sessions_deleted,
        messages_deleted,
        usage_deleted,
        skipped,
        limit,
        offset,
        message_limit,
    }) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn appendAgentSessionMigrationEntryJson(allocator: std.mem.Allocator, out: *std.ArrayListUnmanaged(u8), entry: AgentSessionMigrationEntry) !void {
    try out.appendSlice(allocator, "{\"session_id\":");
    try json.appendString(out, allocator, entry.session_id);
    try out.print(allocator, ",\"source_message_count\":{d},\"target_message_count\":{d},\"source_usage_tokens\":", .{ entry.source_message_count, entry.target_message_count });
    if (entry.source_usage_tokens) |total| {
        try out.print(allocator, "{d}", .{total});
    } else {
        try out.appendSlice(allocator, "null");
    }
    try out.appendSlice(allocator, ",\"target_usage_exists\":");
    try out.appendSlice(allocator, if (entry.target_usage_exists) "true" else "false");
    try out.appendSlice(allocator, ",\"action\":");
    try json.appendString(out, allocator, entry.action);
    try out.print(allocator, ",\"messages_copied\":{d},\"usage_copied\":{s}}}", .{ entry.messages_copied, if (entry.usage_copied) "true" else "false" });
}

fn appendRuntimeDiagnostics(ctx: *Context, out: *std.ArrayListUnmanaged(u8), schema_version: i64, schema_ok: bool, store_diag: store_mod.LifecycleDiagnostics) !void {
    try out.appendSlice(ctx.allocator, "{\"record_backend\":");
    try json.appendString(out, ctx.allocator, ctx.store.backendName());
    try out.appendSlice(ctx.allocator, ",\"record_backend_healthy\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.health()) "true" else "false");
    try out.print(ctx.allocator, ",\"schema_version\":{d},\"expected_schema_version\":{d},\"schema_ok\":{s},\"agent_memory_backend\":", .{ schema_version, migrations.expected_schema_version, if (schema_ok) "true" else "false" });
    try json.appendString(out, ctx.allocator, ctx.store.agentMemoryBackendName());
    try out.appendSlice(ctx.allocator, ",\"agent_memory\":");
    try appendAgentMemoryRuntimeDiagnostics(ctx, out);
    try out.appendSlice(ctx.allocator, ",\"vector\":{\"backend\":");
    try json.appendString(out, ctx.allocator, ctx.store.vectorBackendName());
    try out.appendSlice(ctx.allocator, ",\"local_engine\":");
    try json.appendString(out, ctx.allocator, ctx.store.localVectorEngineName());
    try out.appendSlice(ctx.allocator, ",\"search_engine\":");
    try json.appendString(out, ctx.allocator, ctx.store.effectiveVectorSearchEngineName());
    try out.appendSlice(ctx.allocator, ",\"external_enabled\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.vector_backend.externalEnabled()) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"external_sinks\":");
    try json.appendRawJsonOr(out, ctx.allocator, ctx.store.vectorExternalSinksJson(), "[]");
    try out.appendSlice(ctx.allocator, ",\"circuit_breaker\":{\"enabled\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.vector_runtime.circuit_breaker.enabled) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"state\":");
    try json.appendString(out, ctx.allocator, ctx.store.vector_runtime.stateName());
    try out.print(ctx.allocator, ",\"failure_count\":{d},\"threshold\":{d},\"cooldown_ms\":{d}}}", .{ ctx.store.vector_runtime.circuit_breaker.failure_count, ctx.store.vector_runtime.circuit_breaker.threshold, ctx.store.vector_runtime.circuit_breaker.cooldown_ms });
    try out.print(ctx.allocator, ",\"outbox_active\":true,\"outbox_pending\":{d}}}", .{store_diag.vector_outbox_pending});
    try out.appendSlice(ctx.allocator, ",\"lucid\":{\"backend\":");
    try json.appendString(out, ctx.allocator, ctx.store.lucidBackendName());
    try out.appendSlice(ctx.allocator, ",\"enabled\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.lucid_projection.isEnabled()) "true" else "false");
    try out.print(ctx.allocator, ",\"pending\":{d},\"failed\":{d}}}", .{ store_diag.lucid_projection_pending, store_diag.lucid_projection_failed });
    try out.appendSlice(ctx.allocator, ",\"analytics\":{\"backend\":");
    try json.appendString(out, ctx.allocator, ctx.store.analyticsBackendName());
    try out.appendSlice(ctx.allocator, "},\"cache\":{\"response_cache_active\":true,\"semantic_cache_active\":true,\"entries\":");
    try out.print(ctx.allocator, "{d}", .{store_diag.cache_entries});
    try out.appendSlice(ctx.allocator, "},\"retrieval\":{\"keyword\":true,\"vector\":true,\"adaptive_retrieval\":true,\"graph\":true,\"query_expansion\":true,\"rrf\":true,\"min_relevance\":true,\"temporal_decay\":true,\"mmr\":true,\"llm_rerank_configured\":");
    try out.appendSlice(ctx.allocator, if (ctx.llm_base_url != null and ctx.llm_model != null) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"summarizer\":true},\"embedding_provider\":{\"provider\":");
    try json.appendString(out, ctx.allocator, ctx.embedding_provider.name());
    try out.appendSlice(ctx.allocator, ",\"external_configured\":");
    try out.appendSlice(ctx.allocator, if (embeddingProviderConfigured(ctx)) "true" else "false");
    try out.print(ctx.allocator, ",\"fallback_count\":{d},\"dimensions\":{d}}}", .{ ctx.embedding_fallbacks.len, ctx.embedding_dimensions });
    try out.appendSlice(ctx.allocator, ",\"completion_provider\":{\"configured\":");
    try out.appendSlice(ctx.allocator, if (ctx.llm_base_url != null and ctx.llm_model != null) "true" else "false");
    try out.appendSlice(ctx.allocator, "}}");
}

fn appendAgentMemoryRuntimeDiagnostics(ctx: *Context, out: *std.ArrayListUnmanaged(u8)) !void {
    try out.appendSlice(ctx.allocator, "{\"backend\":");
    try json.appendString(out, ctx.allocator, ctx.store.agent_memory.backendName());
    try out.appendSlice(ctx.allocator, ",\"external\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.agent_memory.isExternal()) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"noop\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.agent_memory.isNoop()) "true" else "false");
    try out.appendSlice(ctx.allocator, ",\"supports_feed\":");
    try out.appendSlice(ctx.allocator, if (ctx.store.agent_memory.supportsFeed()) "true" else "false");
    try out.print(ctx.allocator, ",\"named_store_count\":{d},\"named_stores\":[", .{ctx.store.agent_memory_stores.count()});
    for (ctx.store.agent_memory_stores.stores.items, 0..) |*named, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try out.appendSlice(ctx.allocator, "{\"name\":");
        try json.appendString(out, ctx.allocator, named.name);
        try out.appendSlice(ctx.allocator, ",\"backend\":");
        try json.appendString(out, ctx.allocator, named.runtime.backendName());
        try out.appendSlice(ctx.allocator, ",\"noop\":");
        try out.appendSlice(ctx.allocator, if (named.runtime.isNoop()) "true" else "false");
        try out.appendSlice(ctx.allocator, ",\"supports_feed\":");
        try out.appendSlice(ctx.allocator, if (named.runtime.supportsFeed()) "true" else "false");
        try out.append(ctx.allocator, '}');
    }
    try out.appendSlice(ctx.allocator, "]}");
}

fn embeddingProviderConfigured(ctx: *Context) bool {
    return switch (ctx.embedding_provider) {
        .local_deterministic => false,
        .openai_compatible => ctx.embedding_base_url != null and ctx.embedding_model != null,
        .ollama => true,
        .gemini, .voyage => ctx.embedding_api_key != null,
    };
}

fn lifecycleLucidStatus(ctx: *Context) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    const diag = ctx.store.lifecycleDiagnostics() catch return serverError(ctx);
    const body = std.fmt.allocPrint(
        ctx.allocator,
        "{{\"lucid\":{{\"enabled\":{s},\"backend\":\"{s}\",\"pending\":{d},\"failed\":{d},\"cooldown_until_ms\":{d}}}}}",
        .{ if (ctx.store.lucid_projection.isEnabled()) "true" else "false", ctx.store.lucidBackendName(), diag.lucid_projection_pending, diag.lucid_projection_failed, ctx.store.lucid_projection.cooldown_until_ms },
    ) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body };
}

fn lifecycleLucidRebuild(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "verify")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const limit = @as(usize, @intCast(@max(@as(i64, 1), @min(json.intField(parsed.value.object, "limit") orelse 1000, 5000))));
    const result = ctx.store.rebuildLucidProjection(ctx.allocator, .{
        .scopes_json = ctx.actor_scopes_json,
        .actor_id = ctx.actor_id,
        .limit = limit,
    }) catch return serverError(ctx);
    const body_out = std.fmt.allocPrint(
        ctx.allocator,
        "{{\"lucid_rebuild\":{{\"enabled\":{s},\"scanned\":{d},\"enqueued\":{d}}}}}",
        .{ if (result.enabled) "true" else "false", result.scanned, result.enqueued },
    ) catch return serverError(ctx);
    return .{ .status = "200 OK", .body = body_out };
}

fn analyticsAllowed(ctx: *Context) bool {
    return hasCapability(ctx, "export") and domain.hasActorScope(ctx.actor_scopes_json, "admin");
}

fn analyticsError(ctx: *Context, err: anyerror) HttpResponse {
    return switch (err) {
        error.AnalyticsBackendNotConfigured => json.errorResponse(ctx.allocator, 400, "bad_request", "Analytics backend is not configured"),
        error.AnalyticsBackendUnavailable => json.errorResponse(ctx.allocator, 500, "analytics_unavailable", "Analytics backend is unavailable"),
        error.AnalyticsBackendHttpError => json.errorResponse(ctx.allocator, 500, "analytics_error", "Analytics backend rejected the request"),
        error.AnalyticsBackendResponseTooLarge => json.errorResponse(ctx.allocator, 500, "analytics_response_too_large", "Analytics backend response exceeded the configured safety limit"),
        else => serverError(ctx),
    };
}

fn lifecycleAnalyticsStatus(ctx: *Context) HttpResponse {
    if (!analyticsAllowed(ctx)) return forbidden(ctx);
    const status = ctx.store.analyticsStatus(ctx.allocator) catch |err| return analyticsError(ctx, err);
    const cursor = ctx.store.getConnectorCursor(ctx.allocator, "clickhouse_analytics", "admin") catch null;
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(
        ctx.allocator,
        "{{\"analytics_status\":{{\"backend\":\"{s}\",\"rows\":{d},\"audit_max_id\":{d},\"feed_max_id\":{d},\"latest_created_at_ms\":{d},\"cursor\":",
        .{ ctx.store.analyticsBackendName(), status.rows, status.audit_max_id, status.feed_max_id, status.latest_created_at_ms },
    ) catch return serverError(ctx);
    if (cursor) |loaded| {
        loaded.writeJson(ctx.allocator, &out) catch return serverError(ctx);
    } else {
        out.appendSlice(ctx.allocator, "null") catch return serverError(ctx);
    }
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleAnalyticsQuery(ctx: *Context, body: []const u8) HttpResponse {
    if (!analyticsAllowed(ctx)) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const events_json = ctx.store.queryAnalyticsEventsJson(ctx.allocator, .{
        .event_source = json.stringField(obj, "event_source"),
        .object_type = json.stringField(obj, "object_type"),
        .object_id = json.stringField(obj, "object_id"),
        .actor_id = json.stringField(obj, "actor_id"),
        .since_id = json.intField(obj, "since_id") orelse 0,
        .limit = positiveLimit(json.intField(obj, "limit"), 100),
        .newest_first = json.boolField(obj, "newest_first") orelse true,
    }) catch |err| return analyticsError(ctx, err);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"analytics_events\":") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, events_json) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleAnalyticsExport(ctx: *Context, body: []const u8) HttpResponse {
    if (!analyticsAllowed(ctx)) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const since_id = json.intField(obj, "since_id") orelse 0;
    const result = ctx.store.exportAnalytics(ctx.allocator, .{
        .audit_since_id = json.intField(obj, "audit_since_id") orelse since_id,
        .feed_since_id = json.intField(obj, "feed_since_id") orelse since_id,
        .limit = positiveLimit(json.intField(obj, "limit"), 1000),
        .scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx),
        .use_cursor = json.boolField(obj, "use_cursor") orelse false,
        .advance_cursor = json.boolField(obj, "advance_cursor") orelse false,
        .cursor_name = json.stringField(obj, "cursor_name") orelse "clickhouse_analytics",
        .cursor_scope = json.stringField(obj, "cursor_scope") orelse "admin",
        .cursor_permissions_json = rawField(ctx.allocator, obj, "cursor_permissions", "[\"admin\"]") catch return badJson(ctx),
        .actor_id = ctx.actor_id,
    }) catch |err| return analyticsError(ctx, err);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(
        ctx.allocator,
        "{{\"analytics_export\":{{\"backend\":\"{s}\",\"audit_events\":{d},\"feed_events\":{d},\"attempted\":{d},\"exported\":{d},\"skipped_existing\":{d},\"audit_since_id\":{d},\"feed_since_id\":{d},\"next_audit_id\":{d},\"next_feed_id\":{d},\"cursor_advanced\":",
        .{ ctx.store.analyticsBackendName(), result.audit_events, result.feed_events, result.attempted, result.exported, result.skipped_existing, result.audit_since_id, result.feed_since_id, result.next_audit_id, result.next_feed_id },
    ) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, if (result.cursor_advanced) "true" else "false") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleSnapshot(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const summary_json = rawField(ctx.allocator, obj, "summary", "{}") catch return serverError(ctx);
    const snapshot = ctx.store.createLifecycleSnapshot(ctx.allocator, json.stringField(obj, "type") orelse "manual", summary_json) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"snapshot\":{\"id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"type\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.snapshot_type) catch return serverError(ctx);
    out.print(ctx.allocator, ",\"created_at_ms\":{d}}}", .{snapshot.created_at_ms}) catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleSnapshotExport(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const persist_snapshot = json.boolField(obj, "persist") orelse json.boolField(obj, "record_snapshot") orelse (hasCapability(ctx, "write") or hasCapability(ctx, "propose"));
    if (persist_snapshot and !hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    const query = json.stringField(obj, "query") orelse "";
    var input = buildSearchInput(ctx, obj, query, positiveLimit(json.intField(obj, "limit"), 100), true) catch return serverError(ctx);
    input.include_deprecated = json.boolField(obj, "include_deprecated") orelse true;
    input.use_vector = json.boolField(obj, "use_vector") orelse false;
    const results = ctx.store.search(ctx.allocator, input) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };
    const summary_json = snapshotSummaryJson(ctx, input.scopes_json, query, results) catch return serverError(ctx);
    const snapshot_type = json.stringField(obj, "type") orelse "export";
    const snapshot = if (persist_snapshot)
        ctx.store.createLifecycleSnapshot(ctx.allocator, snapshot_type, summary_json) catch return serverError(ctx)
    else
        store_mod.LifecycleSnapshot{ .id = ids.make(ctx.allocator, "snap_preview_") catch return serverError(ctx), .snapshot_type = snapshot_type, .summary_json = summary_json, .created_at_ms = ids.nowMs() };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"snapshot\":{\"id\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.id) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"type\":") catch return serverError(ctx);
    json.appendString(&out, ctx.allocator, snapshot.snapshot_type) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"scopes\":") catch return serverError(ctx);
    json.appendRawJsonOr(&out, ctx.allocator, input.scopes_json, "[]") catch return serverError(ctx);
    out.print(ctx.allocator, ",\"persisted\":{s},\"created_at_ms\":{d},\"object_count\":{d},\"summary\":", .{ if (persist_snapshot) "true" else "false", snapshot.created_at_ms, results.len }) catch return serverError(ctx);
    json.appendRawJsonOr(&out, ctx.allocator, summary_json, "{}") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"objects\":") catch return serverError(ctx);
    appendSnapshotObjects(ctx, &out, results) catch return serverError(ctx);
    out.appendSlice(ctx.allocator, "}}") catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleExportJsonl(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read") or !hasCapability(ctx, "export")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const query = json.stringField(obj, "query") orelse "";
    const include_internal = json.boolField(obj, "include_internal") orelse false;
    const include_pii = json.boolField(obj, "include_pii") orelse false;
    var input = buildSearchInput(ctx, obj, query, positiveLimit(json.intField(obj, "limit"), 1000), true) catch return serverError(ctx);
    input.include_deprecated = json.boolField(obj, "include_deprecated") orelse true;
    input.use_vector = json.boolField(obj, "use_vector") orelse false;
    const results = ctx.store.search(ctx.allocator, input) catch |err| switch (err) {
        error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
        else => return serverError(ctx),
    };

    var out: std.ArrayListUnmanaged(u8) = .empty;
    var written: usize = 0;
    for (results) |result| {
        if (!include_internal and exportResultIsInternal(result)) continue;
        if (written > 0) out.append(ctx.allocator, '\n') catch return serverError(ctx);
        appendJsonlExportRecord(ctx, &out, result, include_pii) catch return serverError(ctx);
        written += 1;
    }
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn lifecycleSnapshotImport(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write") and !hasCapability(ctx, "propose")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const objects_value = snapshotObjectsValue(obj) orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing objects");
    const objects = switch (objects_value) {
        .array => |a| a,
        else => return badJson(ctx),
    };
    const default_scope = json.stringField(obj, "default_scope") orelse "workspace";
    const default_permissions = rawField(ctx.allocator, obj, "default_permissions", "[]") catch return serverError(ctx);
    const created_by = json.stringField(obj, "created_by") orelse "agent";
    const dry_run = (json.boolField(obj, "dry_run") orelse false) or
        (json.boolField(obj, "preflight") orelse false) or
        (json.boolField(obj, "preflight_only") orelse false);

    var memory_only = true;
    for (objects.items) |item| {
        if (item != .object) {
            continue;
        }
        const flat = snapshotRecordObject(item.object);
        const kind = snapshotObjectType(item.object, flat) orelse {
            memory_only = false;
            break;
        };
        if (!std.mem.eql(u8, kind, "memory_atom")) {
            memory_only = false;
            break;
        }
    }
    if (!memory_only) return lifecycleSnapshotImportStructured(ctx, objects.items, .{
        .default_scope = default_scope,
        .default_permissions_json = default_permissions,
        .created_by = created_by,
        .dry_run = dry_run,
        .preserve_ids = json.boolField(obj, "preserve_ids") orelse true,
    });

    var prepared: std.ArrayListUnmanaged(store_mod.PreparedMemoryImport) = .empty;
    errdefer prepared.deinit(ctx.allocator);
    var skipped: usize = 0;
    for (objects.items) |item| {
        if (item != .object) {
            skipped += 1;
            continue;
        }
        const source_obj = snapshotRecordObject(item.object);
        const text = json.stringField(source_obj, "text") orelse {
            skipped += 1;
            continue;
        };
        const title = json.stringField(source_obj, "title") orelse json.stringField(source_obj, "id") orelse "snapshot object";
        const result_type = json.stringField(source_obj, "type") orelse json.stringField(source_obj, "result_type") orelse "snapshot";
        const scope = json.stringField(source_obj, "scope") orelse default_scope;
        const permissions_json = rawField(ctx.allocator, source_obj, "permissions", default_permissions) catch return serverError(ctx);
        const exported_source_ids_json = rawField(ctx.allocator, source_obj, "source_ids", "[]") catch return serverError(ctx);
        var source_ids_json = rawField(ctx.allocator, source_obj, "citations", exported_source_ids_json) catch return serverError(ctx);
        const has_valid_sources = jsonArrayHasStringItems(ctx.allocator, source_ids_json) and sourceIdsCanBackRecord(ctx, source_ids_json, scope, permissions_json);
        if (!has_valid_sources) source_ids_json = "[]";
        const status = normalizedImportedMemoryStatus(json.stringField(source_obj, "status"));
        const predicate = std.fmt.allocPrint(ctx.allocator, "imported:{s}", .{result_type}) catch return serverError(ctx);
        var input = store_mod.MemoryAtomInput{
            .predicate = predicate,
            .object = title,
            .text = text,
            .scope = scope,
            .confidence = json.floatField(source_obj, "confidence") orelse 0.55,
            .status = status,
            .source_ids_json = source_ids_json,
            .created_by = created_by,
            .permissions_json = permissions_json,
            .tags_json = "[\"snapshot_import\"]",
        };
        var generated_source: ?store_mod.SourceInput = null;
        if (has_valid_sources) {
            if (!jsonArrayHasStringItems(ctx.allocator, input.evidence_ranges_json) and !jsonArrayHasObjectItems(ctx.allocator, input.evidence_ranges_json)) {
                const first_source = firstJsonStringDup(ctx.allocator, input.source_ids_json) catch return serverError(ctx);
                input.evidence_ranges_json = evidenceJson(ctx.allocator, first_source orelse "", input.text.len, "snapshot_import") catch return serverError(ctx);
            }
        } else {
            generated_source = .{
                .source_type = "snapshot_import",
                .title = title,
                .content = text,
                .author = json.nullableStringField(source_obj, "owner"),
                .permissions_json = permissions_json,
                .scope = scope,
                .metadata_json = "{\"generated_for\":\"snapshot_import\"}",
            };
        }
        if (!canCreateMemoryAtom(ctx, input)) return forbidden(ctx);
        prepared.append(ctx.allocator, .{ .atom = input, .generated_source = generated_source }) catch return serverError(ctx);
    }
    if (dry_run) {
        return snapshotHydrateResponse(ctx, 0, 0, prepared.items.len, skipped, true, true, "[]", "[]", "{}");
    }
    const atoms = ctx.store.importMemoryAtomsAtomic(ctx.allocator, prepared.items) catch return serverError(ctx);
    var imported_ids: std.ArrayListUnmanaged(u8) = .empty;
    imported_ids.append(ctx.allocator, '[') catch return serverError(ctx);
    for (atoms, 0..) |atom, i| {
        if (i > 0) imported_ids.append(ctx.allocator, ',') catch return serverError(ctx);
        json.appendString(&imported_ids, ctx.allocator, atom.id) catch return serverError(ctx);
    }
    imported_ids.append(ctx.allocator, ']') catch return serverError(ctx);
    return snapshotHydrateResponse(ctx, atoms.len, atoms.len, prepared.items.len, skipped, false, true, imported_ids.items, "[]", "{}");
}

const SnapshotImportOptions = struct {
    default_scope: []const u8,
    default_permissions_json: []const u8,
    created_by: []const u8,
    dry_run: bool,
    preserve_ids: bool = true,
};

const SnapshotHydratedObject = struct {
    object_type: []const u8,
    id: []const u8,
    created: bool = true,
};

fn lifecycleSnapshotImportStructured(ctx: *Context, items: []const std.json.Value, options: SnapshotImportOptions) HttpResponse {
    var validated: usize = 0;
    var skipped: usize = 0;
    var imported: usize = 0;
    var hydrated_count: usize = 0;
    var ids_out: std.ArrayListUnmanaged(u8) = .empty;
    ids_out.append(ctx.allocator, '[') catch return serverError(ctx);
    var first_id = true;
    var counts = SnapshotTypeCounts{};

    const phases = [_][]const u8{ "policy_scope", "space", "source", "entity", "artifact", "memory_atom", "relation", "agent_memory", "context_pack" };
    for (phases) |phase| {
        for (items) |item| {
            if (item != .object) {
                if (std.mem.eql(u8, phase, phases[0])) skipped += 1;
                continue;
            }
            const outer = item.object;
            const record = snapshotRecordObject(outer);
            const kind = snapshotObjectType(outer, record) orelse {
                if (std.mem.eql(u8, phase, phases[0])) skipped += 1;
                continue;
            };
            if (!std.mem.eql(u8, kind, phase)) continue;
            validated += 1;
            const hydrated = snapshotHydrateStructuredObject(ctx, kind, record, options) catch |err| switch (err) {
                error.Forbidden,
                error.RelatedEntityNotFound,
                error.RecordAclBroaderThanRelatedEntity,
                error.SpaceNotFound,
                error.ArtifactAclBroaderThanSpace,
                error.CanonicalArtifactNotFound,
                error.EntityAclBroaderThanCanonicalArtifact,
                error.ContextPackReferenceNotFound,
                error.ContextPackAclBroaderThanRefs,
                => return forbidden(ctx),
                error.InvalidPayload => return badJson(ctx),
                error.AgentMemoryStorageUnavailable => return agentMemoryStorageUnavailable(ctx),
                error.Skipped => {
                    skipped += 1;
                    continue;
                },
                else => return serverError(ctx),
            };
            if (!options.dry_run) {
                hydrated_count += 1;
                if (hydrated.created) imported += 1;
            }
            counts.add(kind);
            if (!first_id) ids_out.append(ctx.allocator, ',') catch return serverError(ctx);
            first_id = false;
            appendSnapshotHydratedObjectJson(ctx, &ids_out, hydrated) catch return serverError(ctx);
        }
    }
    ids_out.append(ctx.allocator, ']') catch return serverError(ctx);
    const counts_json = counts.toJson(ctx.allocator) catch return serverError(ctx);
    return snapshotHydrateResponse(ctx, imported, hydrated_count, validated, skipped, options.dry_run, false, "[]", ids_out.items, counts_json);
}

fn snapshotObjectsValue(obj: std.json.ObjectMap) ?std.json.Value {
    if (obj.get("objects")) |objects| return objects;
    if (obj.get("snapshot")) |snapshot_value| {
        if (snapshot_value == .object) return snapshot_value.object.get("objects");
    }
    return null;
}

fn snapshotHydrateResponse(ctx: *Context, imported: usize, hydrated: usize, validated: usize, skipped: usize, dry_run: bool, atomic: bool, memory_atom_ids_json: []const u8, object_ids_json: []const u8, counts_json: []const u8) HttpResponse {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.print(ctx.allocator, "{{\"imported\":{d},\"hydrated\":{d},\"validated\":{d},\"skipped\":{d},\"dry_run\":{s},\"atomic\":{s},\"memory_atom_ids\":", .{ imported, hydrated, validated, skipped, if (dry_run) "true" else "false", if (atomic) "true" else "false" }) catch return serverError(ctx);
    json.appendRawJsonOr(&out, ctx.allocator, memory_atom_ids_json, "[]") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"object_ids\":") catch return serverError(ctx);
    json.appendRawJsonOr(&out, ctx.allocator, object_ids_json, "[]") catch return serverError(ctx);
    out.appendSlice(ctx.allocator, ",\"counts\":") catch return serverError(ctx);
    json.appendRawJsonOr(&out, ctx.allocator, counts_json, "{}") catch return serverError(ctx);
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn snapshotRecordObject(outer: std.json.ObjectMap) std.json.ObjectMap {
    if (outer.get("record")) |record| {
        if (record == .object) return record.object;
    }
    if (outer.get("search_result")) |search_result| {
        if (search_result == .object) return search_result.object;
    }
    return outer;
}

fn snapshotObjectType(outer: std.json.ObjectMap, record: std.json.ObjectMap) ?[]const u8 {
    if (json.stringField(outer, "object_type")) |value| return value;
    if (json.stringField(outer, "snapshot_object_type")) |value| return value;
    if (json.stringField(record, "object_type")) |value| return value;
    if (json.stringField(record, "result_type")) |value| return value;
    const type_value = json.stringField(record, "type") orelse return null;
    if (snapshotPrimitiveSupported(type_value)) return type_value;
    return null;
}

fn snapshotPrimitiveSupported(value: []const u8) bool {
    return std.mem.eql(u8, value, "source") or
        std.mem.eql(u8, value, "artifact") or
        std.mem.eql(u8, value, "memory_atom") or
        std.mem.eql(u8, value, "entity") or
        std.mem.eql(u8, value, "relation") or
        std.mem.eql(u8, value, "space") or
        std.mem.eql(u8, value, "policy_scope") or
        std.mem.eql(u8, value, "context_pack") or
        std.mem.eql(u8, value, "agent_memory");
}

const SnapshotTypeCounts = struct {
    policy_scope: usize = 0,
    space: usize = 0,
    source: usize = 0,
    artifact: usize = 0,
    memory_atom: usize = 0,
    entity: usize = 0,
    relation: usize = 0,
    context_pack: usize = 0,
    agent_memory: usize = 0,

    fn add(self: *SnapshotTypeCounts, object_type: []const u8) void {
        if (std.mem.eql(u8, object_type, "policy_scope")) self.policy_scope += 1 else if (std.mem.eql(u8, object_type, "space")) self.space += 1 else if (std.mem.eql(u8, object_type, "source")) self.source += 1 else if (std.mem.eql(u8, object_type, "artifact")) self.artifact += 1 else if (std.mem.eql(u8, object_type, "memory_atom")) self.memory_atom += 1 else if (std.mem.eql(u8, object_type, "entity")) self.entity += 1 else if (std.mem.eql(u8, object_type, "relation")) self.relation += 1 else if (std.mem.eql(u8, object_type, "context_pack")) self.context_pack += 1 else if (std.mem.eql(u8, object_type, "agent_memory")) self.agent_memory += 1;
    }

    fn toJson(self: SnapshotTypeCounts, allocator: std.mem.Allocator) ![]const u8 {
        return std.fmt.allocPrint(allocator, "{{\"policy_scope\":{d},\"space\":{d},\"source\":{d},\"artifact\":{d},\"memory_atom\":{d},\"entity\":{d},\"relation\":{d},\"context_pack\":{d},\"agent_memory\":{d}}}", .{ self.policy_scope, self.space, self.source, self.artifact, self.memory_atom, self.entity, self.relation, self.context_pack, self.agent_memory });
    }
};

fn appendSnapshotHydratedObjectJson(ctx: *Context, out: *std.ArrayListUnmanaged(u8), hydrated: SnapshotHydratedObject) !void {
    try out.appendSlice(ctx.allocator, "{\"type\":");
    try json.appendString(out, ctx.allocator, hydrated.object_type);
    try out.appendSlice(ctx.allocator, ",\"id\":");
    try json.appendString(out, ctx.allocator, hydrated.id);
    try out.append(ctx.allocator, '}');
}

fn snapshotHydrateStructuredObject(ctx: *Context, object_type: []const u8, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    if (std.mem.eql(u8, object_type, "policy_scope")) return try snapshotHydratePolicyScope(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "space")) return try snapshotHydrateSpace(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "source")) return try snapshotHydrateSource(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "artifact")) return try snapshotHydrateArtifact(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "entity")) return try snapshotHydrateEntity(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "relation")) return try snapshotHydrateRelation(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "memory_atom")) return try snapshotHydrateMemoryAtom(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "agent_memory")) return try snapshotHydrateAgentMemory(ctx, obj, options);
    if (std.mem.eql(u8, object_type, "context_pack")) return try snapshotHydrateContextPack(ctx, obj, options);
    return error.Skipped;
}

fn snapshotHydratePolicyScope(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const scope = json.stringField(obj, "scope") orelse json.stringField(obj, "id") orelse json.stringField(obj, "title") orelse return error.Skipped;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "policy_scope", .id = scope };
    const existing = try ctx.store.getPolicyScope(ctx.allocator, scope);
    if (existing) |policy| {
        if (!recordVisibleToActor(ctx, policy.scope, policy.permissions_json)) return error.Forbidden;
    }
    const policy = try ctx.store.upsertPolicyScope(ctx.allocator, .{
        .scope = scope,
        .visibility = json.stringField(obj, "visibility") orelse "workspace",
        .permissions_json = permissions,
        .owner = json.nullableStringField(obj, "owner"),
        .ttl_ms = json.intField(obj, "ttl_ms"),
        .review_after_ms = json.intField(obj, "review_after_ms"),
        .metadata_json = try rawField(ctx.allocator, obj, "metadata", try rawField(ctx.allocator, obj, "metadata_json", "{\"snapshot_import\":true}")),
        .actor_id = ctx.actor_id,
        .suppress_feed = true,
    });
    return .{ .object_type = "policy_scope", .id = policy.scope, .created = existing == null };
}

fn snapshotHydrateSpace(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const name = json.stringField(obj, "name") orelse json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const title = json.stringField(obj, "title") orelse name;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "space", .id = json.stringField(obj, "id") orelse name };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getSpace(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                return .{ .object_type = "space", .id = existing.id, .created = false };
            }
        }
    }
    if (try ctx.store.getSpace(ctx.allocator, name)) |existing| {
        if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
        return .{ .object_type = "space", .id = existing.id, .created = false };
    }
    const space = try ctx.store.createSpace(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .name = name,
        .title = title,
        .description = json.nullableStringField(obj, "description") orelse json.nullableStringField(obj, "text"),
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try rawField(ctx.allocator, obj, "metadata", try rawField(ctx.allocator, obj, "metadata_json", "{\"snapshot_import\":true}")),
        .actor_id = ctx.actor_id,
        .suppress_feed = true,
    });
    return .{ .object_type = "space", .id = space.id };
}

fn snapshotHydrateSource(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const title = json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "source", .id = json.stringField(obj, "id") orelse title };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getSource(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                return .{ .object_type = "source", .id = existing.id, .created = false };
            }
        }
    }
    const source_type = json.stringField(obj, "source_type") orelse blk: {
        const raw_type = json.stringField(obj, "type") orelse "manual";
        break :blk if (std.mem.eql(u8, raw_type, "source")) "manual" else raw_type;
    };
    const source = try ctx.store.createSource(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .source_type = source_type,
        .title = title,
        .raw_content_uri = json.nullableStringField(obj, "raw_content_uri"),
        .content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse "",
        .author = json.nullableStringField(obj, "author"),
        .participants_json = try rawField(ctx.allocator, obj, "participants", try rawField(ctx.allocator, obj, "participants_json", "[]")),
        .permissions_json = permissions,
        .scope = scope,
        .checksum = json.nullableStringField(obj, "checksum"),
        .language = json.nullableStringField(obj, "language"),
        .related_entities_json = try rawField(ctx.allocator, obj, "related_entities", try rawField(ctx.allocator, obj, "related_entities_json", "[]")),
        .metadata_json = try rawField(ctx.allocator, obj, "metadata", try rawField(ctx.allocator, obj, "metadata_json", "{\"snapshot_import\":true}")),
        .actor_id = ctx.actor_id,
    });
    return .{ .object_type = "source", .id = source.id };
}

fn snapshotHydrateArtifact(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const title = json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    const status = json.stringField(obj, "status") orelse "draft";
    if (!canChangeGraphPrimitiveStatus(ctx, scope, permissions, status)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "artifact", .id = json.stringField(obj, "id") orelse title };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getArtifact(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                return .{ .object_type = "artifact", .id = existing.id, .created = false };
            }
        }
    }
    var source_ids = try rawField(ctx.allocator, obj, "source_ids", try rawField(ctx.allocator, obj, "citations", "[]"));
    if (!sourceIdsCanBackRecord(ctx, source_ids, scope, permissions)) source_ids = "[]";
    const space_id = json.nullableStringField(obj, "space_id");
    if (!spaceCanContainRecord(ctx, space_id, scope, permissions)) return error.Forbidden;
    const artifact_type = json.stringField(obj, "artifact_type") orelse blk: {
        const raw_type = json.stringField(obj, "type") orelse "page";
        break :blk if (std.mem.eql(u8, raw_type, "artifact")) "page" else raw_type;
    };
    const artifact = try ctx.store.createArtifact(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .artifact_type = artifact_type,
        .title = title,
        .body = json.stringField(obj, "body") orelse json.stringField(obj, "text") orelse "",
        .status = status,
        .owner = json.nullableStringField(obj, "owner"),
        .space_id = space_id,
        .scope = scope,
        .source_ids_json = source_ids,
        .related_entities_json = try rawField(ctx.allocator, obj, "related_entities", try rawField(ctx.allocator, obj, "related_entities_json", "[]")),
        .permissions_json = permissions,
        .fields_json = try rawField(ctx.allocator, obj, "fields", try rawField(ctx.allocator, obj, "fields_json", "{}")),
        .summary = json.nullableStringField(obj, "summary"),
        .agent_summary = json.nullableStringField(obj, "agent_summary"),
        .actor_id = ctx.actor_id,
    });
    return .{ .object_type = "artifact", .id = artifact.id };
}

fn snapshotHydrateEntity(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const title = json.stringField(obj, "name") orelse json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped;
    const name = snapshotEntityName(ctx.allocator, title) catch return error.OutOfMemory;
    const entity_type = json.stringField(obj, "entity_type") orelse snapshotEntityType(title);
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "entity", .id = json.stringField(obj, "id") orelse name };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getEntity(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                return .{ .object_type = "entity", .id = existing.id, .created = false };
            }
        }
    }
    const canonical_artifact_id = json.nullableStringField(obj, "canonical_artifact_id");
    if (!artifactCanBackRecord(ctx, canonical_artifact_id, scope, permissions)) return error.Forbidden;
    const entity = try ctx.store.resolveEntity(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .entity_type = entity_type,
        .name = name,
        .aliases_json = try rawField(ctx.allocator, obj, "aliases", try rawField(ctx.allocator, obj, "aliases_json", "[]")),
        .description = json.nullableStringField(obj, "description") orelse json.nullableStringField(obj, "text"),
        .canonical_artifact_id = canonical_artifact_id,
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try rawField(ctx.allocator, obj, "metadata", try rawField(ctx.allocator, obj, "metadata_json", "{}")),
        .actor_id = ctx.actor_id,
    });
    return .{ .object_type = "entity", .id = entity.id };
}

fn snapshotHydrateRelation(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const from_entity_id = json.stringField(obj, "from_entity_id") orelse return error.Skipped;
    const to_entity_id = json.stringField(obj, "to_entity_id") orelse return error.Skipped;
    const relation_type = json.stringField(obj, "relation_type") orelse json.stringField(obj, "title") orelse "related_to";
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    const status = json.stringField(obj, "status") orelse "proposed";
    if (!canChangeGraphPrimitiveStatus(ctx, scope, permissions, status)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "relation", .id = json.stringField(obj, "id") orelse relation_type };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getRelation(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                return .{ .object_type = "relation", .id = existing.id, .created = false };
            }
        }
    }
    var source_ids = try rawField(ctx.allocator, obj, "source_ids", try rawField(ctx.allocator, obj, "citations", "[]"));
    if (!sourceIdsCanBackRecord(ctx, source_ids, scope, permissions)) source_ids = "[]";
    const relation = ctx.store.createRelation(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .from_entity_id = from_entity_id,
        .relation_type = relation_type,
        .to_entity_id = to_entity_id,
        .source_ids_json = source_ids,
        .scope = scope,
        .permissions_json = permissions,
        .confidence = json.floatField(obj, "confidence") orelse 0.5,
        .status = status,
        .actor_id = ctx.actor_id,
    }) catch |err| switch (err) {
        error.EntityNotFound => return error.Skipped,
        else => return err,
    };
    return .{ .object_type = "relation", .id = relation.id };
}

fn snapshotHydrateMemoryAtom(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const text = json.stringField(obj, "text") orelse json.stringField(obj, "content") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    var source_ids = try rawField(ctx.allocator, obj, "source_ids", try rawField(ctx.allocator, obj, "citations", "[]"));
    if (!sourceIdsCanBackRecord(ctx, source_ids, scope, permissions)) source_ids = "[]";
    const input = store_mod.MemoryAtomInput{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .subject_entity_id = json.nullableStringField(obj, "subject_entity_id"),
        .predicate = json.stringField(obj, "predicate") orelse "imported:snapshot",
        .object = json.stringField(obj, "object") orelse json.stringField(obj, "title") orelse "",
        .text = text,
        .scope = scope,
        .confidence = json.floatField(obj, "confidence") orelse 0.55,
        .status = normalizedImportedMemoryStatus(json.stringField(obj, "status")),
        .source_ids_json = source_ids,
        .evidence_ranges_json = try rawField(ctx.allocator, obj, "evidence_ranges", try rawField(ctx.allocator, obj, "evidence_ranges_json", "[]")),
        .created_by = json.stringField(obj, "created_by") orelse options.created_by,
        .valid_from_ms = json.intField(obj, "valid_from_ms"),
        .valid_until_ms = json.intField(obj, "valid_until_ms"),
        .owner = json.nullableStringField(obj, "owner"),
        .permissions_json = permissions,
        .tags_json = try rawField(ctx.allocator, obj, "tags", try rawField(ctx.allocator, obj, "tags_json", "[\"snapshot_import\"]")),
        .actor_id = ctx.actor_id,
    };
    if (!canCreateMemoryAtom(ctx, input)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "memory_atom", .id = json.stringField(obj, "id") orelse text };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.getMemoryAtom(ctx.allocator, id)) |existing| {
                if (!recordVisibleToActor(ctx, existing.scope, existing.permissions_json)) return error.Forbidden;
                return .{ .object_type = "memory_atom", .id = existing.id, .created = false };
            }
        }
    }
    const atom = try ctx.store.createMemoryAtom(ctx.allocator, input);
    return .{ .object_type = "memory_atom", .id = atom.id };
}

fn snapshotHydrateAgentMemory(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const category = json.stringField(obj, "category") orelse snapshotAgentMemoryCategory(obj);
    const key = json.stringField(obj, "key") orelse try snapshotAgentMemoryKey(ctx.allocator, json.stringField(obj, "title") orelse json.stringField(obj, "id") orelse return error.Skipped, category);
    const content = json.stringField(obj, "content") orelse json.stringField(obj, "text") orelse return error.Skipped;
    const session_id = json.nullableStringField(obj, "session_id");
    if (session_id) |sid| {
        if (!agentSessionWriteAllowed(ctx, sid)) return error.Forbidden;
    }
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    const scope = json.nullableStringField(obj, "scope");
    if (scope) |requested_scope| {
        if (!canCreateMemoryAtom(ctx, .{ .text = content, .scope = requested_scope, .permissions_json = permissions, .created_by = "agent", .actor_id = ctx.actor_id })) return error.Forbidden;
    } else if (!domain.permissionsAreOpen(permissions) and !domain.permissionsWritable(permissions, ctx.actor_scopes_json)) {
        return error.Forbidden;
    }
    if (options.dry_run) return .{ .object_type = "agent_memory", .id = json.stringField(obj, "id") orelse key };
    const explicit_owner_actor_id = json.stringField(obj, "owner_id") orelse json.stringField(obj, "actor_id");
    const computed_owner_actor_id = if (explicit_owner_actor_id == null) try access.agentMemoryOwner(ctx.allocator, ctx.actor_id, scope) else null;
    defer if (computed_owner_actor_id) |owner| ctx.allocator.free(owner);
    const owner_actor_id = explicit_owner_actor_id orelse computed_owner_actor_id.?;
    const route = try storage_routes.fromObject(ctx.allocator, obj);
    if (try ctx.store.agentMemoryGetRouted(ctx.allocator, key, session_id, owner_actor_id, route)) |existing| {
        if (std.mem.eql(u8, existing.content, content) and std.mem.eql(u8, existing.category, category)) {
            return .{ .object_type = "agent_memory", .id = existing.id, .created = false };
        }
    }
    const entry = try ctx.store.agentMemoryStoreRouted(ctx.allocator, .{
        .key = key,
        .content = content,
        .category = category,
        .session_id = session_id,
        .scope = scope,
        .permissions_json = permissions,
        .metadata_json = try rawField(ctx.allocator, obj, "metadata", try rawField(ctx.allocator, obj, "metadata_json", "{\"snapshot_import\":true}")),
        .actor_id = owner_actor_id,
        .writer_actor_id = ctx.actor_id,
    }, route);
    return .{ .object_type = "agent_memory", .id = entry.id };
}

fn snapshotHydrateContextPack(ctx: *Context, obj: std.json.ObjectMap, options: SnapshotImportOptions) !SnapshotHydratedObject {
    const query = json.stringField(obj, "query") orelse json.stringField(obj, "task") orelse json.stringField(obj, "title") orelse json.stringField(obj, "text") orelse return error.Skipped;
    const scope = json.stringField(obj, "scope") orelse options.default_scope;
    const permissions = try rawField(ctx.allocator, obj, "permissions", options.default_permissions_json);
    if (!canWriteRecord(ctx, scope, permissions)) return error.Forbidden;
    if (options.dry_run) return .{ .object_type = "context_pack", .id = json.stringField(obj, "id") orelse query };
    if (options.preserve_ids) {
        if (json.stringField(obj, "id")) |id| {
            if (try ctx.store.contextPackLifecycleTarget(ctx.allocator, id, ctx.actor_id, ctx.actor_scopes_json)) |_| {
                return .{ .object_type = "context_pack", .id = id, .created = false };
            }
        }
    }
    const scopes_json = try rawField(ctx.allocator, obj, "scopes", try rawField(ctx.allocator, obj, "required_scopes", try singleStringArrayJson(ctx.allocator, scope)));
    if (json.stringField(obj, "generated_summary") != null or
        obj.get("included_sources") != null or
        obj.get("included_sources_json") != null or
        obj.get("included_artifacts") != null or
        obj.get("included_artifacts_json") != null or
        obj.get("included_memory_atoms") != null or
        obj.get("included_memory_atoms_json") != null or
        obj.get("included_result_refs") != null or
        obj.get("included_result_refs_json") != null)
    {
        const requested_actor_id = json.nullableStringField(obj, "actor_id");
        const actor_isolated = json.boolField(obj, "actor_isolated") orelse false;
        const restore_actor_id = try snapshotContextPackActorId(ctx, requested_actor_id, actor_isolated);
        const pack = try ctx.store.importContextPackSnapshot(ctx.allocator, .{
            .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
            .purpose = json.stringField(obj, "purpose") orelse "snapshot_hydrate",
            .target = json.stringField(obj, "target") orelse "agent",
            .query = query,
            .generated_summary = json.stringField(obj, "generated_summary") orelse json.stringField(obj, "summary") orelse query,
            .included_sources_json = try rawFieldAny(ctx.allocator, obj, &.{ "included_sources", "included_sources_json", "citations" }, "[]"),
            .included_artifacts_json = try rawFieldAny(ctx.allocator, obj, &.{ "included_artifacts", "included_artifacts_json" }, "[]"),
            .included_memory_atoms_json = try rawFieldAny(ctx.allocator, obj, &.{ "included_memory_atoms", "included_memory_atoms_json" }, "[]"),
            .included_result_refs_json = try rawFieldAny(ctx.allocator, obj, &.{ "included_result_refs", "included_result_refs_json" }, "[]"),
            .required_scopes_json = scopes_json,
            .actor_id = restore_actor_id,
            .actor_isolated = actor_isolated,
            .token_budget = json.intField(obj, "token_budget") orelse 12000,
            .actor_id_for_audit = ctx.actor_id,
        });
        return .{ .object_type = "context_pack", .id = pack.id };
    }
    const pack = try ctx.store.createContextPack(ctx.allocator, .{
        .id = if (options.preserve_ids) json.nullableStringField(obj, "id") else null,
        .purpose = json.stringField(obj, "purpose") orelse "snapshot_hydrate",
        .target = json.stringField(obj, "target") orelse "agent",
        .query = query,
        .token_budget = json.intField(obj, "token_budget") orelse 12000,
        .scopes_json = scopes_json,
        .persist = true,
        .include_deprecated = true,
        .use_vector = false,
        .actor_id = ctx.actor_id,
    });
    return .{ .object_type = "context_pack", .id = pack.id };
}

fn snapshotContextPackActorId(ctx: *Context, requested_actor_id: ?[]const u8, actor_isolated: bool) !?[]const u8 {
    if (requested_actor_id) |actor| {
        if (actor_isolated and !std.mem.eql(u8, actor, ctx.actor_id) and !domain.hasActorScope(ctx.actor_scopes_json, "admin")) return error.Forbidden;
        if (!actor_isolated and (std.mem.eql(u8, actor, ctx.actor_id) or access.isSharedAgentMemoryOwner(actor) or domain.hasActorScope(ctx.actor_scopes_json, "admin"))) return actor;
        if (actor_isolated) return actor;
    }
    return ctx.actor_id;
}

fn snapshotEntityType(title: []const u8) []const u8 {
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx > 0) return title[0..idx];
    }
    return "concept";
}

fn snapshotEntityName(allocator: std.mem.Allocator, title: []const u8) ![]const u8 {
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx + 1 < title.len) return allocator.dupe(u8, title[idx + 1 ..]);
    }
    return allocator.dupe(u8, title);
}

fn snapshotAgentMemoryCategory(obj: std.json.ObjectMap) []const u8 {
    const title = json.stringField(obj, "title") orelse return "core";
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx > 0 and !std.mem.eql(u8, title[0..idx], "agent_memory")) return title[0..idx];
    }
    return "core";
}

fn snapshotAgentMemoryKey(allocator: std.mem.Allocator, title: []const u8, category: []const u8) ![]const u8 {
    const prefixes = [_][]const u8{ "agent_memory:", category };
    for (prefixes) |prefix| {
        if (prefix.len == 0) continue;
        if (std.mem.startsWith(u8, title, prefix)) {
            const offset = prefix.len + if (std.mem.endsWith(u8, prefix, ":")) @as(usize, 0) else @as(usize, 1);
            if (offset < title.len and title[prefix.len] == ':') return allocator.dupe(u8, title[offset..]);
            if (std.mem.endsWith(u8, prefix, ":") and prefix.len < title.len) return allocator.dupe(u8, title[prefix.len..]);
        }
    }
    if (std.mem.indexOfScalar(u8, title, ':')) |idx| {
        if (idx + 1 < title.len) return allocator.dupe(u8, title[idx + 1 ..]);
    }
    return allocator.dupe(u8, title);
}

fn normalizedImportedMemoryStatus(status: ?[]const u8) ?[]const u8 {
    const value = status orelse return null;
    if (std.mem.eql(u8, value, "accepted")) return "verified";
    if (std.mem.eql(u8, value, "verified") or
        std.mem.eql(u8, value, "proposed") or
        std.mem.eql(u8, value, "stale") or
        std.mem.eql(u8, value, "deprecated") or
        std.mem.eql(u8, value, "rejected") or
        std.mem.eql(u8, value, "superseded"))
    {
        return value;
    }
    return null;
}

fn snapshotSummaryJson(ctx: *Context, scopes_json: []const u8, query: []const u8, results: []const domain.SearchResult) ![]const u8 {
    var out: std.ArrayListUnmanaged(u8) = .empty;
    try out.appendSlice(ctx.allocator, "{\"query\":");
    try json.appendString(&out, ctx.allocator, query);
    try out.appendSlice(ctx.allocator, ",\"scopes\":");
    try json.appendRawJsonOr(&out, ctx.allocator, scopes_json, "[]");
    try out.print(ctx.allocator, ",\"object_count\":{d},\"counts\":{{", .{results.len});
    const types = [_][]const u8{ "memory_atom", "space", "policy_scope", "source", "artifact", "entity", "relation", "context_pack", "feed_event", "session_message" };
    for (types, 0..) |kind, i| {
        if (i > 0) try out.append(ctx.allocator, ',');
        try json.appendString(&out, ctx.allocator, kind);
        try out.append(ctx.allocator, ':');
        try out.print(ctx.allocator, "{d}", .{countSearchResultsOfType(results, kind)});
    }
    try out.appendSlice(ctx.allocator, "}}");
    return out.toOwnedSlice(ctx.allocator);
}

fn countSearchResultsOfType(results: []const domain.SearchResult, result_type: []const u8) usize {
    var count: usize = 0;
    for (results) |result| {
        if (std.mem.eql(u8, result.result_type, result_type)) count += 1;
    }
    return count;
}

fn responseCachePut(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const cache_key = json.stringField(obj, "key") orelse json.stringField(obj, "cache_key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing cache key");
    const response_json = rawField(ctx.allocator, obj, "response", "{}") catch return serverError(ctx);
    ctx.store.putResponseCache(.{
        .cache_key = cache_key,
        .response_json = response_json,
        .scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx),
        .actor_id = ctx.actor_id,
        .ttl_ms = json.intField(obj, "ttl_ms") orelse 0,
    }) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"cached\":true}");
}

fn responseCacheGet(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const cache_key = json.stringField(obj, "key") orelse json.stringField(obj, "cache_key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing cache key");
    const entry = ctx.store.getResponseCacheForScopes(ctx.allocator, cache_key, ids.nowMs(), effectiveScopes(ctx, obj) catch return serverError(ctx), ctx.actor_id) catch return serverError(ctx);
    var out: std.ArrayListUnmanaged(u8) = .empty;
    out.appendSlice(ctx.allocator, "{\"hit\":") catch return serverError(ctx);
    if (entry) |hit| {
        out.appendSlice(ctx.allocator, "true,\"cache_key\":") catch return serverError(ctx);
        json.appendString(&out, ctx.allocator, hit.cache_key) catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"scopes\":") catch return serverError(ctx);
        json.appendRawJsonOr(&out, ctx.allocator, hit.scopes_json, "[]") catch return serverError(ctx);
        out.appendSlice(ctx.allocator, ",\"response\":") catch return serverError(ctx);
        json.appendRawJsonOr(&out, ctx.allocator, hit.response_json, "{}") catch return serverError(ctx);
        out.print(ctx.allocator, ",\"created_at_ms\":{d},\"expires_at_ms\":{d}", .{ hit.created_at_ms, hit.expires_at_ms }) catch return serverError(ctx);
    } else {
        out.appendSlice(ctx.allocator, "false") catch return serverError(ctx);
    }
    out.append(ctx.allocator, '}') catch return serverError(ctx);
    return .{ .status = "200 OK", .body = out.toOwnedSlice(ctx.allocator) catch return serverError(ctx) };
}

fn semanticCachePut(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "write")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
    const obj = parsed.value.object;
    const cache_key = json.stringField(obj, "key") orelse json.stringField(obj, "cache_key") orelse return json.errorResponse(ctx.allocator, 400, "bad_request", "Missing cache key");
    const query = json.stringField(obj, "query") orelse "";
    const response_json = rawField(ctx.allocator, obj, "response", "{}") catch return serverError(ctx);
    const embedding_json = if (obj.get("embedding") != null)
        rawField(ctx.allocator, obj, "embedding", "[]") catch return serverError(ctx)
    else blk: {
        const embedding = vector_mod.deterministicEmbedding(ctx.allocator, query, 64) catch return serverError(ctx);
        break :blk vector_mod.embeddingToJson(ctx.allocator, embedding) catch return serverError(ctx);
    };
    ctx.store.putSemanticCache(.{
        .cache_key = cache_key,
        .query = query,
        .response_json = response_json,
        .embedding_json = embedding_json,
        .scopes_json = effectiveScopes(ctx, obj) catch return serverError(ctx),
        .actor_id = ctx.actor_id,
        .ttl_ms = json.intField(obj, "ttl_ms") orelse 0,
    }) catch return serverError(ctx);
    return ok(ctx, "{\"ok\":true,\"cached\":true}");
}

fn semanticCacheSearch(ctx: *Context, body: []const u8) HttpResponse {
    if (!hasCapability(ctx, "read")) return forbidden(ctx);
    var parsed = parseBody(ctx, body) catch return badJson(ctx);
    defer parsed.deinit();
