    const archive_after = handleRequest(&ctx, "POST", "/v1/agent-memory/search", "{\"query\":\"Migrate Scratch Unique\",\"store\":\"archive\",\"limit\":10}", "POST /v1/agent-memory/search HTTP/1.1\r\nAuthorization: Bearer agent-route\r\n\r\n{}");
