    try std.testing.expect(std.mem.indexOf(u8, applied_memory.body, "[\\\"zig\\\"]") != null);

    const non_agent = handleRequest(&source_ctx, "POST", "/v1/memory/events", "{\"event_type\":\"memory.note\",\"operation\":\"put\",\"object_type\":\"memory_atom\",\"object_id\":\"not_agent_memory\",\"scope\":\"public\",\"payload\":{\"text\":\"not nullclaw feed\"}}", "");
    try std.testing.expectEqualStrings("200 OK", non_agent.status);

    const feed = handleRequest(&source_ctx, "GET", "/v1/agent/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", feed.status);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"schema_version\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"origin_instance_id\":\"nullclaw-a\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"origin_sequence\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"timestamp_ms\":123") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"key\":\"api.tags\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"value_kind\":\"string_set\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "\"content\":\"[\\\"zig\\\"]\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed.body, "not nullclaw feed") == null);

    const status = handleRequest(&source_ctx, "GET", "/v1/agent/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", status.status);
    try std.testing.expect(std.mem.indexOf(u8, status.body, "\"visible_events\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, status.body, "\"last_sequence\":2") != null);

    const compact = handleRequest(&source_ctx, "POST", "/v1/agent/memory/compact", "{\"through_sequence\":1}", "");
    try std.testing.expectEqualStrings("200 OK", compact.status);
    try std.testing.expect(std.mem.indexOf(u8, compact.body, "\"cursor_floor\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, compact.body, "\"projection\":\"agent_memory\"") != null);

    const expired_agent_feed = handleRequest(&source_ctx, "GET", "/v1/agent/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("410 Gone", expired_agent_feed.status);
    const observer_feed_after_compact = handleRequest(&observer_ctx, "GET", "/v1/agent/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", observer_feed_after_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, observer_feed_after_compact.body, "\"origin_instance_id\":\"nullclaw-a\"") != null);
    const native_feed_after_agent_compact = handleRequest(&source_ctx, "GET", "/v1/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", native_feed_after_agent_compact.status);
    try std.testing.expect(std.mem.indexOf(u8, native_feed_after_agent_compact.body, "not nullclaw feed") != null);

    const compacted_status = handleRequest(&source_ctx, "GET", "/v1/agent/memory/status", "", "");
    try std.testing.expectEqualStrings("200 OK", compacted_status.status);
    try std.testing.expect(std.mem.indexOf(u8, compacted_status.body, "\"cursor_floor\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, compacted_status.body, "\"visible_events\":0") != null);
    try std.testing.expect(std.mem.indexOf(u8, compacted_status.body, "\"last_sequence\":2") != null);

    const checkpoint = handleRequest(&source_ctx, "GET", "/v1/agent/memory/checkpoint?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"cursor_floor\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"origin_instance_id\":\"nullclaw-a\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"origin_sequence\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"timestamp_ms\":123") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"key\":\"api.tags\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"object_type\":\"agent_memory\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "not nullclaw feed") == null);

    const restore = handleRequest(&target_ctx, "POST", "/v1/agent/memory/checkpoint", checkpoint.body, "");
    try std.testing.expectEqualStrings("200 OK", restore.status);
    const restored = handleRequest(&target_ctx, "GET", "/v1/agent-memory/api.tags", "", "");
    try std.testing.expectEqualStrings("200 OK", restored.status);
    try std.testing.expect(std.mem.indexOf(u8, restored.body, "[\\\"zig\\\"]") != null);
    const restored_expired_feed = handleRequest(&target_ctx, "GET", "/v1/agent/memory/events?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("410 Gone", restored_expired_feed.status);
    const restored_checkpoint = handleRequest(&target_ctx, "GET", "/v1/agent/memory/checkpoint?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", restored_checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, restored_checkpoint.body, "\"origin_instance_id\":\"nullclaw-a\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, restored_checkpoint.body, "\"origin_sequence\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, restored_checkpoint.body, "\"timestamp_ms\":123") != null);
}

test "api nullclaw top-level feed apply deletes scoped and all session variants" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:nullclaw-delete",
        .actor_scopes_json = "[\"public\",\"write:public\",\"session:*\",\"write:session:*\",\"actor:agent:nullclaw-delete\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"delete\",\"export\",\"feed_apply\"]",
    };

    const put_global = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-delete\",\"origin_sequence\":10,\"operation\":\"put\",\"key\":\"top.delete\",\"category\":\"core\",\"content\":\"Top global value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", put_global.status);
    const put_session = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-delete\",\"origin_sequence\":11,\"operation\":\"put\",\"key\":\"top.delete\",\"session_id\":\"s1\",\"category\":\"core\",\"content\":\"Top session value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", put_session.status);
    const put_session_alias = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-delete\",\"origin_sequence\":111,\"operation\":\"put\",\"key\":\"top.delete.alias\",\"session\":\"s-alias\",\"category\":\"core\",\"content\":\"Top session alias value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", put_session_alias.status);
    const session_alias_get = handleRequest(&ctx, "GET", "/v1/agent-memory/top.delete.alias?session=s-alias", "", "");
    try std.testing.expectEqualStrings("200 OK", session_alias_get.status);
    try std.testing.expect(std.mem.indexOf(u8, session_alias_get.body, "Top session alias value") != null);

    const delete_scoped = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-delete\",\"origin_sequence\":12,\"operation\":\"delete_scoped\",\"key\":\"top.delete\",\"session_id\":\"s1\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", delete_scoped.status);
    const global_after_scoped_delete = handleRequest(&ctx, "GET", "/v1/agent-memory/top.delete", "", "");
    try std.testing.expectEqualStrings("200 OK", global_after_scoped_delete.status);
    try std.testing.expect(std.mem.indexOf(u8, global_after_scoped_delete.body, "Top global value") != null);
    const session_after_scoped_delete = handleRequest(&ctx, "GET", "/v1/agent-memory/top.delete?session_id=s1", "", "");
    try std.testing.expectEqualStrings("404 Not Found", session_after_scoped_delete.status);

    const put_session_again = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-delete\",\"origin_sequence\":13,\"operation\":\"put\",\"key\":\"top.delete\",\"session_id\":\"s1\",\"category\":\"core\",\"content\":\"Top session value again\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", put_session_again.status);
    const delete_all = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-delete\",\"origin_sequence\":14,\"operation\":\"delete_all\",\"key\":\"top.delete\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", delete_all.status);
    const global_after_delete_all = handleRequest(&ctx, "GET", "/v1/agent-memory/top.delete", "", "");
    try std.testing.expectEqualStrings("404 Not Found", global_after_delete_all.status);
    const session_after_delete_all = handleRequest(&ctx, "GET", "/v1/agent-memory/top.delete?session_id=s1", "", "");
    try std.testing.expectEqualStrings("404 Not Found", session_after_delete_all.status);
}

test "api nullclaw top-level feed apply accepts lifecycle reducers" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{
        .allocator = arena.allocator(),
        .store = &store,
        .actor_id = "agent:nullclaw-life",
        .actor_scopes_json = "[\"admin\"]",
    };

    const put = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-life\",\"origin_sequence\":1,\"operation\":\"put\",\"key\":\"top.lifecycle\",\"content\":\"Top lifecycle value\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", put.status);
    const stale = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-life\",\"origin_sequence\":2,\"operation\":\"mark_stale\",\"key\":\"top.lifecycle\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", stale.status);
    const stale_search = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"Top lifecycle value\",\"use_vector\":false}", "");
    try std.testing.expect(std.mem.indexOf(u8, stale_search.body, "\"status\":\"stale\"") != null);

    const verify = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-life\",\"origin_sequence\":3,\"operation\":\"verify\",\"key\":\"top.lifecycle\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", verify.status);
    const verified_search = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"Top lifecycle value\",\"use_vector\":false}", "");
    try std.testing.expect(std.mem.indexOf(u8, verified_search.body, "\"status\":\"verified\"") != null);

    const supersede = handleRequest(&ctx, "POST", "/v1/agent/memory/apply", "{\"origin_instance_id\":\"nullclaw-life\",\"origin_sequence\":4,\"operation\":\"supersede\",\"key\":\"top.lifecycle\",\"scope\":\"public\"}", "");
    try std.testing.expectEqualStrings("200 OK", supersede.status);
    const hidden = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"Top lifecycle value\",\"use_vector\":false}", "");
    try std.testing.expect(std.mem.indexOf(u8, hidden.body, "Top lifecycle value") == null);
    const checkpoint = handleRequest(&ctx, "GET", "/v1/agent/memory/checkpoint?after=0&limit=10", "", "");
    try std.testing.expectEqualStrings("200 OK", checkpoint.status);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"operation\":\"mark_stale\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"operation\":\"verify\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, checkpoint.body, "\"operation\":\"supersede\"") != null);
}

