test "api retrieval search fuses keyword and vector results" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var ctx = Context{ .allocator = alloc, .store = &store };

    const keyword_atom = try store.createMemoryAtom(alloc, .{ .text = "hybrid keyword decision", .scope = "public", .created_by = "human" });
    _ = keyword_atom;
    const vector_atom = try store.createMemoryAtom(alloc, .{ .text = "semantic only context", .scope = "public", .created_by = "human" });
    const hybrid_query = "hybrid vector context retrieval pipeline";
    const embedding = try vector_mod.deterministicEmbedding(alloc, hybrid_query, 64);
    const embedding_json = try vector_mod.embeddingToJson(alloc, embedding);
    _ = try store.upsertVectorChunk(alloc, .{
        .object_id = vector_atom.id,
        .text = "hybrid vector context",
        .scope = "public",
        .embedding_json = embedding_json,
        .dimensions = 64,
    });

    const resp_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"scopes\":[\"public\"],\"limit\":5}}", .{hybrid_query});
    const resp = handleRequest(&ctx, "POST", "/v1/retrieval/search", resp_body, "");
    try std.testing.expectEqualStrings("200 OK", resp.status);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"strategy\":\"hybrid\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"vector_ann\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"rrf\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"citation_assembly\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"llm_rerank\"") == null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "semantic only context") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, "\"groups\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, resp.body, vector_atom.id) != null);

    const adaptive_off_search = handleRequest(&ctx, "POST", "/v1/retrieval/search", "{\"query\":\"short lookup\",\"scopes\":[\"public\"],\"limit\":5,\"adaptive_retrieval\":false}", "");
    try std.testing.expectEqualStrings("200 OK", adaptive_off_search.status);
    try std.testing.expect(std.mem.indexOf(u8, adaptive_off_search.body, "\"adaptive_enabled\":false") != null);
    try std.testing.expect(std.mem.indexOf(u8, adaptive_off_search.body, "\"strategy\":\"hybrid\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, adaptive_off_search.body, "\"vector_ann\"") != null);

    const filtered_body = try std.fmt.allocPrint(alloc, "{{\"query\":\"{s}\",\"scopes\":[\"public\"],\"limit\":5,\"min_relevance\":999}}", .{hybrid_query});
    const filtered = handleRequest(&ctx, "POST", "/v1/retrieval/search", filtered_body, "");
    try std.testing.expectEqualStrings("200 OK", filtered.status);
    try std.testing.expect(std.mem.indexOf(u8, filtered.body, "\"min_relevance\":999.000000") != null);
    try std.testing.expect(std.mem.indexOf(u8, filtered.body, "\"min_relevance\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, filtered.body, "semantic only context") == null);
}

