        .{ .id = "agent_memory:scratch:agm_1", .result_type = "agent_memory", .title = "Preference", .text = "Agent memory from scratch.", .scope = "agent:agent:a", .status = "active", .score = 1, .source_ids_json = "[]", .store = "scratch" },
