    try std.testing.expect(std.mem.indexOf(u8, summary.body, "\"decisions\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, summary.body, "\"action_items\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, summary.body, "\"speaker\":\"Igor\"") != null);

    const summary_override = handleRequest(&ctx, "POST", "/v1/lifecycle/summarize", "{\"messages\":[\"x\"],\"llm_model\":\"client-model\"}", "");
    try std.testing.expectEqualStrings("400 Bad Request", summary_override.status);

    const strict_summary = handleRequest(&ctx, "POST", "/v1/lifecycle/summarize", "{\"messages\":[\"x\"],\"use_llm\":true,\"strict_llm\":true}", "");
    try std.testing.expectEqualStrings("502 Bad Gateway", strict_summary.status);

    const rollout = handleRequest(&ctx, "POST", "/v1/lifecycle/rollout", "{\"key\":\"agent:a\",\"percent\":100}", "");
    try std.testing.expectEqualStrings("200 OK", rollout.status);
    try std.testing.expect(std.mem.indexOf(u8, rollout.body, "\"enabled\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, rollout.body, "\"mode\":\"canary\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, rollout.body, "\"decision\":\"enabled\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, rollout.body, "\"policy\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, rollout.body, "\"subject\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, rollout.body, "\"salt\":\"memory\"") != null);

    const shadow_rollout = handleRequest(&ctx, "POST", "/v1/lifecycle/rollout", "{\"feature\":\"hybrid-retrieval\",\"mode\":\"shadow\",\"shadow_percent\":100,\"session_id\":\"s1\"}", "");
    try std.testing.expectEqualStrings("200 OK", shadow_rollout.status);
    try std.testing.expect(std.mem.indexOf(u8, shadow_rollout.body, "\"decision\":\"shadow\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, shadow_rollout.body, "\"shadow\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, shadow_rollout.body, "\"session_id\":\"s1\"") != null);

    var scoped_ctx = Context{ .allocator = arena.allocator(), .store = &store, .actor_id = "agent:rollout", .actor_scopes_json = "[\"project:nullpantry\"]", .actor_capabilities_json = "[\"read\"]" };
    const gated_rollout = handleRequest(&scoped_ctx, "POST", "/v1/lifecycle/rollout", "{\"feature\":\"team-memory\",\"mode\":\"on\",\"required_scopes\":[\"project:nullpantry\"],\"required_capabilities\":[\"read\"]}", "");
    try std.testing.expectEqualStrings("200 OK", gated_rollout.status);
    try std.testing.expect(std.mem.indexOf(u8, gated_rollout.body, "\"decision\":\"enabled\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, gated_rollout.body, "\"required_scopes\":[\"project:nullpantry\"]") != null);
    try std.testing.expect(std.mem.indexOf(u8, gated_rollout.body, "\"required_capabilities\":[\"read\"]") != null);
    const blocked_rollout = handleRequest(&scoped_ctx, "POST", "/v1/lifecycle/rollout", "{\"feature\":\"team-memory\",\"mode\":\"on\",\"blocked_scopes\":[\"project:nullpantry\"]}", "");
    try std.testing.expectEqualStrings("200 OK", blocked_rollout.status);
    try std.testing.expect(std.mem.indexOf(u8, blocked_rollout.body, "\"decision\":\"disabled\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, blocked_rollout.body, "\"reason\":\"blocked_scope\"") != null);

    const hygiene = handleRequest(&ctx, "POST", "/v1/lifecycle/hygiene", "{\"stale_after_ms\":1,\"archive_after_ms\":2}", "");
    try std.testing.expectEqualStrings("200 OK", hygiene.status);
    try std.testing.expect(std.mem.indexOf(u8, hygiene.body, "\"hygiene\"") != null);

    const manual_job = handleRequest(&ctx, "POST", "/v1/jobs", "{\"type\":\"hygiene\",\"scope\":\"workspace\",\"input\":{}}", "");
    try std.testing.expectEqualStrings("200 OK", manual_job.status);
    const manual_job_id = try extractJsonString(arena.allocator(), manual_job.body, "\"id\":\"");
    const manual_path = try std.fmt.allocPrint(arena.allocator(), "/v1/jobs/{s}/run", .{manual_job_id});
    const manual_run = handleRequest(&ctx, "POST", manual_path, "", "");
    try std.testing.expectEqualStrings("200 OK", manual_run.status);
    try std.testing.expect(std.mem.indexOf(u8, manual_run.body, "\"status\":\"succeeded\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, manual_run.body, "\"checked\"") != null);

    const job = handleRequest(&ctx, "POST", "/v1/jobs", "{\"type\":\"hygiene\",\"scope\":\"workspace\",\"input\":{}}", "");
    try std.testing.expectEqualStrings("200 OK", job.status);
    const worker_run = handleRequest(&ctx, "POST", "/v1/workers/run", "{\"job_limit\":5,\"outbox_limit\":5}", "");
    try std.testing.expectEqualStrings("200 OK", worker_run.status);
    try std.testing.expect(std.mem.indexOf(u8, worker_run.body, "\"jobs_succeeded\":1") != null);
}

