    const native_verify = handleRequest(&ctx, "POST", "/v1/memory/apply?storage=native", "{\"event_type\":\"agent_memory.verify\",\"object_type\":\"agent_memory\",\"payload\":{\"key\":\"native.lifecycle.pref\",\"scope\":\"public\"}}", "");
