    , "");
    try std.testing.expectEqualStrings("200 OK", qmd_ingest.status);
    try std.testing.expect(std.mem.indexOf(u8, qmd_ingest.body, "\"connector\":\"qmd\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, qmd_ingest.body, "\"count\":2") != null);
    try std.testing.expect(std.mem.indexOf(u8, qmd_ingest.body, "\"type\":\"qmd\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, qmd_ingest.body, "\"start_line\":5") != null);
    try std.testing.expect(std.mem.indexOf(u8, qmd_ingest.body, "\"atoms_extracted\":2") != null);

    const cursor = handleRequest(&ctx, "GET", "/v1/connectors/qmd/cursor?scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", cursor.status);
    try std.testing.expect(std.mem.indexOf(u8, cursor.body, "\"qmd-2\"") != null);

    const search_resp = handleRequest(&ctx, "POST", "/v1/search", "{\"query\":\"canonical pantry sources\",\"scopes\":[\"public\"],\"use_vector\":false}", "");
    try std.testing.expectEqualStrings("200 OK", search_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "QMD search results become canonical pantry sources") != null);
}

test "api qmd connector exports and prunes visible agent sessions" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var tmp = std.testing.tmpDir(.{ .iterate = true });
    defer tmp.cleanup();

    const session_id = "qmd-session";
    const root_path = try std.fmt.allocPrint(alloc, ".zig-cache/tmp/{s}/qmd-session-export", .{tmp.sub_path});
    var ctx = Context{
        .allocator = alloc,
        .store = &store,
        .actor_id = "agent:qmd",
        .actor_scopes_json = "[\"session:qmd-session\",\"write:session:qmd-session\"]",
        .actor_capabilities_json = "[\"read\",\"write\",\"export\",\"delete\"]",
    };

    const raw = "POST /v1/agent-sessions/qmd-session/messages HTTP/1.1\r\nAuthorization: Bearer local\r\n\r\n{}";
    try std.testing.expectEqualStrings("200 OK", handleRequest(&ctx, "POST", "/v1/agent-sessions/qmd-session/messages", "{\"role\":\"user\",\"content\":\"Need shared QMD context\"}", raw).status);
    try std.testing.expectEqualStrings("200 OK", handleRequest(&ctx, "POST", "/v1/agent-sessions/qmd-session/messages", "{\"role\":\"system\",\"content\":\"hidden runtime prompt\"}", raw).status);
    try std.testing.expectEqualStrings("200 OK", handleRequest(&ctx, "POST", "/v1/agent-sessions/qmd-session/messages", "{\"role\":\"assistant\",\"content\":\"Use NullPantry as the governed memory layer\"}", raw).status);

    const export_body = try std.fmt.allocPrint(alloc, "{{\"directory\":\"{s}\",\"session_ids\":[\"{s}\"]}}", .{ root_path, session_id });
    const exported = handleRequest(&ctx, "POST", "/v1/connectors/qmd/export-sessions", export_body, raw);
    try std.testing.expectEqualStrings("200 OK", exported.status);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"exported\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"written\":1") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported.body, "\"messages\":2") != null);

    const exported_path = try qmd_adapter.sessionExportPath(alloc, root_path, session_id);
    const exported_markdown = try std.Io.Dir.cwd().readFileAlloc(compat.io(), exported_path, alloc, .limited(64 * 1024));
    try std.testing.expect(std.mem.indexOf(u8, exported_markdown, "Need shared QMD context") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported_markdown, "Use NullPantry as the governed memory layer") != null);
    try std.testing.expect(std.mem.indexOf(u8, exported_markdown, "hidden runtime prompt") == null);

    const second_export = handleRequest(&ctx, "POST", "/v1/connectors/qmd/export-sessions", export_body, raw);
    try std.testing.expectEqualStrings("200 OK", second_export.status);
    try std.testing.expect(std.mem.indexOf(u8, second_export.body, "\"unchanged\":1") != null);

    var denied_ctx = ctx;
    denied_ctx.actor_scopes_json = "[\"session:other\"]";
    const denied = handleRequest(&denied_ctx, "POST", "/v1/connectors/qmd/export-sessions", export_body, raw);
    try std.testing.expectEqualStrings("403 Forbidden", denied.status);

    const prune_body = try std.fmt.allocPrint(alloc, "{{\"directory\":\"{s}\",\"retention_days\":0}}", .{root_path});
    const pruned = handleRequest(&ctx, "POST", "/v1/connectors/qmd/prune-sessions", prune_body, raw);
    try std.testing.expectEqualStrings("200 OK", pruned.status);
    try std.testing.expect(std.mem.indexOf(u8, pruned.body, "\"deleted\":1") != null);
    try std.testing.expectError(error.FileNotFound, std.Io.Dir.cwd().statFile(compat.io(), exported_path, .{}));
}

test "api connector ingest only advances cursor after all items succeed" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    var ctx = Context{ .allocator = arena.allocator(), .store = &store };

    const failed = handleRequest(&ctx, "POST", "/v1/connectors/ticket/ingest",
        \\{"scope":"public","next_cursor":"ticket-bad","items":[{"title":"ok","content":"ok"},1]}
    , "");
    try std.testing.expectEqualStrings("400 Bad Request", failed.status);

    const cursor_get = handleRequest(&ctx, "GET", "/v1/connectors/ticket/cursor?scope=public", "", "");
    try std.testing.expectEqualStrings("404 Not Found", cursor_get.status);

    const ok_ingest = handleRequest(&ctx, "POST", "/v1/connectors/ticket/ingest",
        \\{"scope":"public","next_cursor":"ticket-good","items":[{"title":"ok","content":"ok"}]}
    , "");
    try std.testing.expectEqualStrings("200 OK", ok_ingest.status);
    const ok_cursor = handleRequest(&ctx, "GET", "/v1/connectors/ticket/cursor?scope=public", "", "");
    try std.testing.expectEqualStrings("200 OK", ok_cursor.status);
    try std.testing.expect(std.mem.indexOf(u8, ok_cursor.body, "\"ticket-good\"") != null);
}

test "api spaces and policy scopes are first-class permission-filtered records" {
    var store = try Store.initSQLite(std.testing.allocator, ":memory:");
    defer store.deinit();
    var arena = std.heap.ArenaAllocator.init(std.testing.allocator);
    defer arena.deinit();
    const alloc = arena.allocator();
    var project_ctx = Context{ .allocator = alloc, .store = &store, .actor_scopes_json = "[\"project:nullpantry\",\"write:project:nullpantry\"]", .actor_capabilities_json = "[\"read\",\"write\"]" };
    var public_ctx = Context{ .allocator = alloc, .store = &store, .actor_scopes_json = "[\"public\"]", .actor_capabilities_json = "[\"read\"]" };
    var public_writer_ctx = Context{ .allocator = alloc, .store = &store, .actor_scopes_json = "[\"public\",\"write:public\"]", .actor_capabilities_json = "[\"read\",\"write\"]" };

    const create_space_resp = handleRequest(&project_ctx, "POST", "/v1/spaces", "{\"name\":\"nullpantry\",\"title\":\"NullPantry\",\"scope\":\"project:nullpantry\",\"permissions\":[\"project:nullpantry\"],\"metadata\":{\"kind\":\"shelf\"}}", "");
    try std.testing.expectEqualStrings("200 OK", create_space_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, create_space_resp.body, "\"space\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, create_space_resp.body, "\"name\":\"nullpantry\"") != null);

    const hidden_spaces = handleRequest(&public_ctx, "GET", "/v1/spaces", "", "");
    try std.testing.expectEqualStrings("200 OK", hidden_spaces.status);
    try std.testing.expect(std.mem.indexOf(u8, hidden_spaces.body, "\"spaces\":[]") != null);

    const visible_spaces = handleRequest(&project_ctx, "GET", "/v1/spaces", "", "");
    try std.testing.expectEqualStrings("200 OK", visible_spaces.status);
    try std.testing.expect(std.mem.indexOf(u8, visible_spaces.body, "\"name\":\"nullpantry\"") != null);

    const project_space = (try store.getSpace(alloc, "nullpantry")).?;
    const scoped_artifact = handleRequest(&project_ctx, "POST", "/v1/artifacts", "{\"title\":\"Project shelf page\",\"body\":\"space scoped body\",\"scope\":\"project:nullpantry\",\"permissions\":[\"project:nullpantry\"],\"space_id\":\"nullpantry\"}", "");
    try std.testing.expectEqualStrings("200 OK", scoped_artifact.status);
    var scoped_artifact_parsed = try std.json.parseFromSlice(std.json.Value, alloc, scoped_artifact.body, .{});
    defer scoped_artifact_parsed.deinit();
    const scoped_artifact_id = json.stringField(scoped_artifact_parsed.value.object.get("artifact").?.object, "id").?;
    const project_shelf_page = (try store.getArtifact(alloc, scoped_artifact_id)).?;
    try std.testing.expectEqualStrings(project_space.id, project_shelf_page.space_id.?);

    const canonical_entity_body = try std.fmt.allocPrint(alloc, "{{\"type\":\"project\",\"name\":\"NullPantry Canonical\",\"scope\":\"project:nullpantry\",\"permissions\":[\"project:nullpantry\"],\"canonical_artifact_id\":\"{s}\"}}", .{project_shelf_page.id});
    const canonical_entity = handleRequest(&project_ctx, "POST", "/v1/entities/resolve", canonical_entity_body, "");
    try std.testing.expectEqualStrings("200 OK", canonical_entity.status);
    try std.testing.expect(std.mem.indexOf(u8, canonical_entity.body, project_shelf_page.id) != null);

    const broad_entity_body = try std.fmt.allocPrint(alloc, "{{\"type\":\"project\",\"name\":\"Too Broad Canonical\",\"scope\":\"project:nullpantry\",\"permissions\":[],\"canonical_artifact_id\":\"{s}\"}}", .{project_shelf_page.id});
    const broad_entity = handleRequest(&project_ctx, "POST", "/v1/entities/resolve", broad_entity_body, "");
    try std.testing.expectEqualStrings("403 Forbidden", broad_entity.status);

    const missing_canonical_entity = handleRequest(&project_ctx, "POST", "/v1/entities/resolve", "{\"type\":\"project\",\"name\":\"Missing Canonical\",\"scope\":\"project:nullpantry\",\"permissions\":[\"project:nullpantry\"],\"canonical_artifact_id\":\"art_missing\"}", "");
    try std.testing.expectEqualStrings("403 Forbidden", missing_canonical_entity.status);

    const hidden_canonical_body = try std.fmt.allocPrint(alloc, "{{\"type\":\"project\",\"name\":\"Hidden Canonical\",\"scope\":\"public\",\"permissions\":[],\"canonical_artifact_id\":\"{s}\"}}", .{project_shelf_page.id});
    const hidden_canonical_entity = handleRequest(&public_writer_ctx, "POST", "/v1/entities/resolve", hidden_canonical_body, "");
    try std.testing.expectEqualStrings("403 Forbidden", hidden_canonical_entity.status);

    const broader_artifact = handleRequest(&project_ctx, "POST", "/v1/artifacts", "{\"title\":\"Too broad shelf page\",\"body\":\"would publish wider than shelf\",\"scope\":\"project:nullpantry\",\"permissions\":[],\"space_id\":\"nullpantry\"}", "");
    try std.testing.expectEqualStrings("403 Forbidden", broader_artifact.status);

    const missing_space_artifact = handleRequest(&project_ctx, "POST", "/v1/artifacts", "{\"title\":\"Missing shelf page\",\"body\":\"missing shelf\",\"scope\":\"project:nullpantry\",\"permissions\":[\"project:nullpantry\"],\"space_id\":\"missing-shelf\"}", "");
    try std.testing.expectEqualStrings("403 Forbidden", missing_space_artifact.status);

    const hidden_space_artifact = handleRequest(&public_writer_ctx, "POST", "/v1/artifacts", "{\"title\":\"Hidden shelf page\",\"body\":\"hidden shelf\",\"scope\":\"public\",\"permissions\":[],\"space_id\":\"nullpantry\"}", "");
    try std.testing.expectEqualStrings("403 Forbidden", hidden_space_artifact.status);

    const policy_resp = handleRequest(&project_ctx, "POST", "/v1/policy-scopes", "{\"scope\":\"project:nullpantry\",\"visibility\":\"project\",\"permissions\":[\"project:nullpantry\"],\"owner\":\"agent:nullpantry\",\"ttl_ms\":86400000,\"review_after_ms\":604800000}", "");
    try std.testing.expectEqualStrings("200 OK", policy_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, policy_resp.body, "\"policy_scope\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, policy_resp.body, "\"ttl_ms\":86400000") != null);

    const policy_update = handleRequest(&project_ctx, "POST", "/v1/policy-scopes", "{\"scope\":\"project:nullpantry\",\"visibility\":\"team\",\"permissions\":[\"project:nullpantry\"],\"owner\":\"agent:nullpantry-updated\",\"ttl_ms\":43200000,\"review_after_ms\":302400000}", "");
    try std.testing.expectEqualStrings("200 OK", policy_update.status);
    try std.testing.expect(std.mem.indexOf(u8, policy_update.body, "\"owner\":\"agent:nullpantry-updated\"") != null);
    const policy_update_retry = handleRequest(&project_ctx, "POST", "/v1/policy-scopes", "{\"scope\":\"project:nullpantry\",\"visibility\":\"team\",\"permissions\":[\"project:nullpantry\"],\"owner\":\"agent:nullpantry-updated\",\"ttl_ms\":43200000,\"review_after_ms\":302400000}", "");
    try std.testing.expectEqualStrings("200 OK", policy_update_retry.status);

    const feed_resp = handleRequest(&project_ctx, "GET", "/v1/memory/events?limit=20", "", "");
    try std.testing.expectEqualStrings("200 OK", feed_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, feed_resp.body, "\"object_type\":\"space\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed_resp.body, "\"object_type\":\"policy_scope\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, feed_resp.body, "agent:nullpantry-updated") != null);

    const hidden_policy = handleRequest(&public_ctx, "GET", "/v1/policy-scopes", "", "");
    try std.testing.expectEqualStrings("200 OK", hidden_policy.status);
    try std.testing.expect(std.mem.indexOf(u8, hidden_policy.body, "\"policy_scopes\":[]") != null);

    const search_resp = handleRequest(&project_ctx, "POST", "/v1/search", "{\"query\":\"nullpantry\",\"scopes\":[\"project:nullpantry\"],\"use_vector\":false}", "");
    try std.testing.expectEqualStrings("200 OK", search_resp.status);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"spaces\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"policy_scopes\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"type\":\"space\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, search_resp.body, "\"type\":\"policy_scope\"") != null);
}
